{
  "name": "JayTIN Private Balance Ledger",
  "description": "An ultra high-end, private banking-style financial management system for tracking outstanding balances and installments with a minimalist glassmorphism design.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type PaymentType = 'Installment' | 'Delayed';
export type PaymentMethod = 'Cash' | 'BANK' | 'E-Wallet';

export interface PurchaseItem {
  id: string;
  name: string;
  amount: number;
  date: string;
  note?: string;
}

export interface PaymentRecord {
  id: string;
  amount: number;
  method: PaymentMethod;
  date: string;
  note?: string;
}

export interface SystemNote {
  id: string;
  timestamp: string;
  content: string;
}

export interface LedgerRecord {
  id: string; // Format: JT-YYYYMM-XXXX
  userName: string;
  type: PaymentType;
  totalAmount: number;
  paidAmount: number;
  paymentCycle?: 'Weekly' | 'Monthly' | 'Custom';
  nextPaymentDate?: string;
  startDate: string;
  endDate?: string;
  tags: string[];
  items: PurchaseItem[];
  payments: PaymentRecord[];
  notes: SystemNote[];
  status: 'Active' | 'Settled' | 'Overdue';
}

export interface DashboardStats {
  totalOutstanding: number;
  activeCustomers: number;
  collectedThisMonth: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  CreditCard, 
  History, 
  User, 
  ChevronRight, 
  Calendar, 
  Tag as TagIcon, 
  FileText,
  DollarSign,
  TrendingUp,
  Clock
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import AddRecordModal from './components/AddRecordModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Initial Seed Data
  useEffect(() => {
    const mockData: LedgerRecord[] = [
      {
        id: 'JT-202401-001',
        userName: 'Alexander Vanderbilt',
        type: 'Installment',
        totalAmount: 25000,
        paidAmount: 10000,
        paymentCycle: 'Monthly',
        nextPaymentDate: '2024-11-15',
        startDate: '2024-01-10',
        tags: ['Old Customer', 'VVIP'],
        items: [
          { id: 'I-01', name: 'Diamond Chronograph XL', amount: 15000, date: '2024-01-10', note: 'Gift collection' },
          { id: 'I-02', name: 'Bespoke Cufflinks', amount: 10000, date: '2024-01-10' }
        ],
        payments: [
          { id: 'P-01', amount: 5000, method: 'BANK', date: '2024-01-10', note: 'Initial Deposit' },
          { id: 'P-02', amount: 5000, method: 'BANK', date: '2024-02-10', note: 'Feb Installment' }
        ],
        notes: [
          { id: 'N-01', timestamp: '2024-01-10 14:00', content: 'Account established with priority status.' }
        ],
        status: 'Active'
      },
      {
        id: 'JT-202405-042',
        userName: 'Elena Petrova',
        type: 'Delayed',
        totalAmount: 8400,
        paidAmount: 2000,
        startDate: '2024-05-22',
        endDate: '2024-12-30',
        tags: ['New Customer', 'Follow-up'],
        items: [
          { id: 'I-03', name: 'Silk Evening Gown', amount: 8400, date: '2024-05-22' }
        ],
        payments: [
          { id: 'P-03', amount: 2000, method: 'Cash', date: '2024-05-22' }
        ],
        notes: [],
        status: 'Active'
      }
    ];
    setRecords(mockData);
  }, []);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active').length,
      collectedThisMonth: 12500 // Mock value
    };
  }, [records]);

  const filteredRecords = records.filter(r => 
    r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
    r.id.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      {/* Header */}
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN <span className="text-xs font-normal align-top bg-[#999] text-white px-2 py-0.5 rounded-full">PVT</span></h1>
          <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Private Balance Management System</p>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Records..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64"
            />
          </div>
          <motion.button 
            whileHover={{ brightness: 1.05 }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Record</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8">
            <CustomerList 
              records={filteredRecords} 
              onSelect={setSelectedRecordId} 
              selectedId={selectedRecordId}
            />
          </div>
          <div className="lg:col-span-4">
            <AnimatePresence mode="wait">
              {selectedRecord ? (
                <CustomerDetail 
                  key={selectedRecord.id}
                  record={selectedRecord} 
                  onClose={() => setSelectedRecordId(null)}
                />
              ) : (
                <motion.div 
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -20 }}
                  className="glass-card rounded-3xl p-8 flex flex-col items-center justify-center text-center h-[600px] text-gray-400 border-dashed border-2 border-white/20"
                >
                  <Clock className="w-12 h-12 mb-4 opacity-20" />
                  <p className="text-sm font-medium">Select a client profile<br/>to view transaction timeline</p>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </main>

      <AddRecordModal 
        isOpen={isAddingRecord} 
        onClose={() => setIsAddingRecord(false)} 
        onAdd={(newRecord) => {
          setRecords([newRecord, ...records]);
          setIsAddingRecord(false);
        }}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { motion } from 'framer-motion';
import { DollarSign, UserCheck, BarChart3 } from 'lucide-react';
import { DashboardStats } from '../types';

interface DashboardProps {
  stats: DashboardStats;
}

const Dashboard: React.FC<DashboardProps> = ({ stats }) => {
  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      <StatCard 
        label="Total Outstanding" 
        value={`$${stats.totalOutstanding.toLocaleString()}`} 
        icon={<DollarSign className="w-5 h-5 text-gray-600" />}
        delay={0}
      />
      <StatCard 
        label="Active Ledgers" 
        value={stats.activeCustomers.toString()} 
        icon={<UserCheck className="w-5 h-5 text-gray-600" />}
        delay={0.1}
      />
      <StatCard 
        label="Monthly Revenue" 
        value={`$${stats.collectedThisMonth.toLocaleString()}`} 
        icon={<BarChart3 className="w-5 h-5 text-gray-600" />}
        delay={0.2}
      />
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: React.ReactNode; delay: number }> = ({ label, value, icon, delay }) => (
  <motion.div 
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ duration: 0.6, delay }}
    className="glass-card rounded-[24px] p-6 relative overflow-hidden group border border-white/40"
  >
    <div className="absolute top-0 right-0 p-4 opacity-10">
      {icon}
    </div>
    <div className="relative z-10">
      <p className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-1">{label}</p>
      <h3 className="text-3xl font-jua text-[#333] group-hover:text-black transition-colors">{value}</h3>
      <div className="mt-4 h-0.5 w-8 bg-[#B8A17D]/30 rounded-full" />
    </div>
  </motion.div>
);

export default Dashboard;

import React from 'react';
import { motion } from 'framer-motion';
import { ChevronRight, AlertCircle, CheckCircle2 } from 'lucide-react';
import { LedgerRecord } from '../types';

interface Props {
  records: LedgerRecord[];
  onSelect: (id: string) => void;
  selectedId: string | null;
}

const CustomerList: React.FC<Props> = ({ records, onSelect, selectedId }) => {
  return (
    <div className="glass-card rounded-[32px] overflow-hidden border border-white/40 min-h-[600px]">
      <div className="p-8 border-b border-white/20">
        <h2 className="text-xl font-jua text-[#333]">Client Ledgers</h2>
        <p className="text-xs text-gray-400 uppercase tracking-wider mt-1">Transaction database</p>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="border-b border-white/10">
              <th className="px-8 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-widest">Profile</th>
              <th className="px-8 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-widest">Type</th>
              <th className="px-8 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-widest text-right">Balance</th>
              <th className="px-8 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-widest">Status</th>
              <th className="px-8 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/10">
            {records.map((record, index) => (
              <motion.tr 
                key={record.id}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: index * 0.05 }}
                onClick={() => onSelect(record.id)}
                className={`group cursor-pointer hover:bg-white/20 transition-all duration-300 ${selectedId === record.id ? 'bg-white/30' : ''}`}
              >
                <td className="px-8 py-5">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-[#333] mb-0.5 group-hover:text-black">{record.userName}</span>
                    <span className="text-[10px] font-jua text-gray-400 tracking-tighter">{record.id}</span>
                  </div>
                </td>
                <td className="px-8 py-5">
                  <span className="text-[11px] font-semibold text-[#999] border border-gray-200 px-2 py-0.5 rounded-md">
                    {record.type}
                  </span>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-sm font-jua text-[#333]">
                      ${(record.totalAmount - record.paidAmount).toLocaleString()}
                    </span>
                    <span className="text-[10px] text-gray-400">Total: ${record.totalAmount.toLocaleString()}</span>
                  </div>
                </td>
                <td className="px-8 py-5">
                  <div className="flex items-center space-x-1.5">
                    {record.status === 'Active' ? (
                      <>
                        <div className="w-1.5 h-1.5 rounded-full bg-[#B8A17D]" />
                        <span className="text-[11px] font-semibold text-[#B8A17D] uppercase tracking-wider">In Progress</span>
                      </>
                    ) : (
                      <>
                        <CheckCircle2 className="w-3.5 h-3.5 text-green-500/60" />
                        <span className="text-[11px] font-semibold text-green-600/60 uppercase tracking-wider">Settled</span>
                      </>
                    )}
                  </div>
                </td>
                <td className="px-4 py-5">
                  <ChevronRight className={`w-4 h-4 text-gray-300 transition-transform duration-300 ${selectedId === record.id ? 'translate-x-1 text-[#B8A17D]' : 'group-hover:translate-x-1'}`} />
                </td>
              </motion.tr>
            ))}
          </tbody>
        </table>
      </div>

      {records.length === 0 && (
        <div className="flex flex-col items-center justify-center py-20 text-gray-400">
          <AlertCircle className="w-8 h-8 mb-2 opacity-20" />
          <p className="text-sm italic">No entries found matching your criteria</p>
        </div>
      )}
    </div>
  );
};

export default CustomerList;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2
} from 'lucide-react';
import { LedgerRecord } from '../types';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
}

const CustomerDetail: React.FC<Props> = ({ record, onClose }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');

  const progress = (record.paidAmount / record.totalAmount) * 100;

  return (
    <motion.div 
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: 20 }}
      transition={{ type: 'spring', damping: 25, stiffness: 200 }}
      className="glass-card rounded-[32px] overflow-hidden border border-white/40 flex flex-col h-[750px] relative shadow-2xl"
    >
      {/* Detail Header */}
      <div className="p-8 pb-4 relative">
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2 hover:bg-white/30 rounded-full transition-colors group"
        >
          <X className="w-5 h-5 text-gray-400 group-hover:text-black" />
        </button>

        <div className="mb-6">
          <span className="text-[10px] font-jua text-[#B8A17D] uppercase tracking-[0.2em] mb-1 block">Private Client Record</span>
          <h2 className="text-2xl font-jua text-[#333]">{record.userName}</h2>
          <p className="text-[10px] text-gray-400 tracking-wider mt-1">{record.id}</p>
        </div>

        <div className="space-y-4">
          <div className="flex justify-between items-end mb-1">
            <span className="text-[11px] font-bold text-gray-400 uppercase">Settlement Progress</span>
            <span className="text-xs font-jua text-[#333]">{progress.toFixed(0)}% Completed</span>
          </div>
          <div className="w-full h-1.5 bg-white/30 rounded-full overflow-hidden">
            <motion.div 
              initial={{ width: 0 }}
              animate={{ width: `${progress}%` }}
              transition={{ duration: 1, ease: 'easeOut' }}
              className="h-full bg-[#B8A17D] shadow-[0_0_8px_rgba(184,161,125,0.4)]"
            />
          </div>
          <div className="flex justify-between">
            <div className="text-center">
              <p className="text-[10px] text-gray-400 uppercase tracking-wider">Paid</p>
              <p className="text-sm font-jua text-gray-700">${record.paidAmount.toLocaleString()}</p>
            </div>
            <div className="text-center">
              <p className="text-[10px] text-gray-400 uppercase tracking-wider">Remaining</p>
              <p className="text-sm font-jua text-[#333]">${(record.totalAmount - record.paidAmount).toLocaleString()}</p>
            </div>
            <div className="text-center">
              <p className="text-[10px] text-gray-400 uppercase tracking-wider">Total</p>
              <p className="text-sm font-jua text-gray-700">${record.totalAmount.toLocaleString()}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex px-8 border-b border-white/10 mt-4">
        {['overview', 'items', 'history'].map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`py-4 px-4 text-[11px] font-bold uppercase tracking-widest transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}
          >
            {tab}
            {activeTab === tab && (
              <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#B8A17D]" />
            )}
          </button>
        ))}
      </div>

      {/* Scrollable Content */}
      <div className="flex-1 overflow-y-auto p-8 pt-6 space-y-6">
        {activeTab === 'overview' && (
          <>
            <div>
              <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-3 flex items-center">
                <TagIcon className="w-3 h-3 mr-2" /> Identification Tags
              </h4>
              <div className="flex flex-wrap gap-2">
                {record.tags.map(tag => (
                  <span key={tag} className="px-2.5 py-1 rounded-full bg-white/40 border border-[#B8A17D]/20 text-[10px] font-bold text-[#B8A17D] shadow-sm">
                    {tag}
                  </span>
                ))}
              </div>
            </div>

            <div>
              <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-3 flex items-center">
                <FileEdit className="w-3 h-3 mr-2" /> Account Timeline
              </h4>
              <div className="space-y-4 relative before:content-[''] before:absolute before:left-[11px] before:top-2 before:bottom-0 before:w-[1px] before:bg-white/20">
                {record.notes.map((note, idx) => (
                  <div key={note.id} className="relative pl-8">
                    <div className="absolute left-0 top-1.5 w-[23px] h-[23px] rounded-full bg-[#EBFAFF] border border-[#B8A17D]/30 flex items-center justify-center z-10">
                      <Clock className="w-2.5 h-2.5 text-[#B8A17D]" />
                    </div>
                    <p className="text-[10px] text-gray-400 mb-0.5">{note.timestamp}</p>
                    <p className="text-xs text-gray-700 leading-relaxed font-medium">{note.content}</p>
                  </div>
                ))}
                {record.notes.length === 0 && (
                  <p className="text-xs italic text-gray-400 pl-8">No formal notes recorded yet.</p>
                )}
              </div>
            </div>

            <div className="p-4 rounded-2xl bg-[#999]/5 border border-[#999]/10">
              <div className="flex justify-between items-center text-[11px] font-bold uppercase tracking-wider text-gray-500">
                <span>Next Expected Payment</span>
                <span className="text-[#333] font-jua">{record.nextPaymentDate || 'N/A'}</span>
              </div>
            </div>
          </>
        )}

        {activeTab === 'items' && (
          <div className="space-y-4">
            {record.items.map(item => (
              <div key={item.id} className="glass-card p-4 rounded-2xl border border-white/30 hover:border-[#B8A17D]/30 transition-all group">
                <div className="flex justify-between items-start mb-2">
                  <div className="flex items-center">
                    <ShoppingBag className="w-4 h-4 mr-2 text-gray-400 group-hover:text-[#B8A17D] transition-colors" />
                    <span className="text-sm font-bold text-[#333]">{item.name}</span>
                  </div>
                  <span className="text-sm font-jua text-[#333]">${item.amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center text-[10px] text-gray-400">
                  <span>{item.date}</span>
                  <span className="italic">{item.note}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'history' && (
          <div className="space-y-4">
            {record.payments.map(payment => (
              <div key={payment.id} className="flex items-start space-x-4">
                <div className="mt-1 p-2 rounded-xl bg-white/40 border border-white/40">
                  <CreditCard className="w-4 h-4 text-[#B8A17D]" />
                </div>
                <div className="flex-1 border-b border-white/10 pb-4">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-sm font-bold text-[#333]">Received via {payment.method}</span>
                    <span className="text-sm font-jua text-green-600/80">+ ${payment.amount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between items-center text-[10px] text-gray-400">
                    <span>{payment.date}</span>
                    <span className="italic">{payment.note}</span>
                  </div>
                </div>
              </div>
            ))}
            {record.payments.length === 0 && (
              <p className="text-sm text-center text-gray-400 py-10 italic">No payment history available.</p>
            )}
          </div>
        )}
      </div>

      {/* Action Footer */}
      <div className="p-6 border-t border-white/20 flex space-x-3 bg-white/20">
        <button className="flex-1 bg-[#999] text-white py-3 rounded-xl font-bold text-[11px] uppercase tracking-widest shadow-lg gold-glow border border-[#B8A17D]/20 hover:brightness-105 transition-all">
          Record Payment
        </button>
        <button className="p-3 bg-white/40 rounded-xl border border-white/40 hover:bg-white/60 transition-colors">
          <Paperclip className="w-5 h-5 text-gray-500" />
        </button>
      </div>
    </motion.div>
  );
};

export default CustomerDetail;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Info } from 'lucide-react';
import { LedgerRecord, PaymentType, PaymentMethod } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (record: LedgerRecord) => void;
}

const AddRecordModal: React.FC<Props> = ({ isOpen, onClose, onAdd }) => {
  const [step, setStep] = useState(1);
  const [userName, setUserName] = useState('');
  const [totalAmount, setTotalAmount] = useState<number>(0);
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Weekly' | 'Monthly' | 'Custom'>('Monthly');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newRecord: LedgerRecord = {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      startDate: new Date().toISOString().split('T')[0],
      tags: ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      status: 'Active'
    };
    onAdd(newRecord);
    setStep(1);
    resetForm();
  };

  const resetForm = () => {
    setUserName('');
    setTotalAmount(0);
    setType('Installment');
  };

  if (!isOpen) return null;

  return (
