                >
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed Payment</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Total Valuation</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-sm">$</span>
                  <input 
                    required
                    type="number" 
                    value={totalAmount || ''}
                    onChange={(e) => setTotalAmount(Number(e.target.value))}
                    placeholder="0.00"
                    className="w-full bg-white/40 border border-white/30 rounded-2xl pl-8 pr-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30 transition-all font-jua"
                  />
                </div>
              </div>
            </div>

            {type === 'Installment' && (
              <motion.div 
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                className="p-4 rounded-2xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-3"
              >
                <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block">Cycle Frequency</label>
                <div className="flex space-x-2">
                  {['Weekly', 'Monthly', 'Custom'].map(c => (
                    <button
                      key={c}
                      type="button"
                      onClick={() => setCycle(c as any)}
                      className={`flex-1 py-2 text-[10px] font-bold rounded-lg border transition-all ${cycle === c ? 'bg-[#B8A17D] text-white border-[#B8A17D]' : 'bg-white/40 border-white/30 text-gray-400'}`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            <div className="flex items-start space-x-3 p-4 rounded-2xl bg-gray-50/50">
              <Info className="w-4 h-4 text-gray-400 mt-0.5" />
              <p className="text-[10px] text-gray-400 leading-relaxed italic">
                By initializing this ledger, you are creating a permanent record in the JayTIN private ecosystem. Ensure all valuations are verified before preservation.
              </p>
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 active:scale-[0.98] transition-all"
          >
            Preserve Record
