            <span>{isSettled ? 'Protocol Settled' : 'Execute Capital Injection'}</span>
          </motion.button>

          <motion.button 
            whileHover={{ y: -2, backgroundColor: 'rgba(255,255,255,0.8)' }}
            whileTap={{ scale: 0.98 }}
            className="flex-1 bg-white/50 rounded-[24px] border border-white/80 hover:bg-white/80 transition-all flex items-center justify-center space-x-3 group shadow-md"
          >
            <Paperclip className="w-5 h-5 text-gray-500 group-hover:text-[#B8A17D] transition-colors" />
            <span className="text-[11px] font-bold uppercase tracking-[0.2em] text-gray-500 group-hover:text-[#B8A17D]">Attachments</span>
          </motion.button>
        </div>
      </motion.div>
    </motion.div>
  );
};

