          <div className="flex-1 space-y-2">
            <div className="flex items-center space-x-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>
              {isSettled && (
                <span className="flex items-center space-x-1 bg-[#333] text-white px-2.5 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm">
                  <ShieldCheck className="w-2.5 h-2.5 text-[#B8A17D]" />
                  <span>Certified Settled</span>
                </span>
              )}
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button 
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={onEdit}
                className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm"
                title="Refine Record"
              >
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <p className="text-[12px] text-gray-400 tracking-[0.2em] font-mono mt-2 flex items-center">
              REFERENCE ID: <span className="ml-2 font-bold text-gray-500">{record.id}</span>
            </p>
