                  <div className="flex-1">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-lg font-bold text-[#333] tracking-tight">Financial Protocol: {payment.method}</span>
                      <span className="text-2xl font-jua text-green-600/80 tracking-tighter">+ RM{payment.amount.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <div className="text-[11px] text-gray-400 font-bold uppercase tracking-widest flex items-center">
