                      )}
                    </div>
                  </div>
                </div>
              ))}
              {record.payments.length === 0 && (
                <div className="text-center py-24 opacity-20 flex flex-col items-center">
                  <History className="w-20 h-20 mb-6" />
                  <p className="text-lg font-bold uppercase tracking-[0.3em]">Zero Transaction Artifacts</p>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Action Footer */}
        <div className="p-10 px-12 border-t border-white/40 flex space-x-5 bg-white/40 shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.05)]">
          <motion.button 
            whileHover={{ brightness: 1.05, y: -2 }}
            whileTap={{ scale: 0.98 }}
            onClick={onPayment}
            disabled={isSettled}
            className={`flex-[2] py-5 rounded-[24px] font-bold text-[13px] uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 ${
              isSettled 
                ? 'bg-gray-200 text-gray-400 border-gray-300 cursor-not-allowed opacity-60' 
                : 'bg-[#999] text-white border-[#B8A17D]/40 gold-glow hover:brightness-110'
            }`}
          >
            <CreditCard className="w-5 h-5 mr-1" />
            <span>{isSettled ? 'Protocol Settled' : 'Execute Capital Injection'}</span>
          </motion.button>

          <motion.button 
            whileHover={{ y: -2, backgroundColor: 'rgba(255,255,255,0.8)' }}
            whileTap={{ scale: 0.98 }}
            className="flex-1 bg-white/50 rounded-[24px] border border-white/80 hover:bg-white/80 transition-all flex items-center justify-center space-x-3 group shadow-md"
          >
            <Paperclip className="w-5 h-5 text-gray-500 group-hover:text-[#B8A17D] transition-colors" />
            <span className="text-[11px] font-bold uppercase tracking-[0.2em] text-gray-500 group-hover:text-[#B8A17D]">Attachments</span>
          </motion.button>
