import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Info, Calculator } from 'lucide-react';
import { LedgerRecord, PaymentType } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: LedgerRecord) => void;
  initialData?: LedgerRecord;
}

const RecordFormModal: React.FC<Props> = ({ isOpen, onClose, onSave, initialData }) => {
  const [userName, setUserName] = useState('');
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Weekly' | 'Monthly' | 'Custom'>('Monthly');
  const [tagsInput, setTagsInput] = useState('');

  useEffect(() => {
    if (initialData) {
      setUserName(initialData.userName);
      setType(initialData.type);
      setCycle(initialData.paymentCycle || 'Monthly');
      setTagsInput(initialData.tags.join(', '));
    } else {
      setUserName('');
      setType('Installment');
      setCycle('Monthly');
      setTagsInput('');
    }
  }, [initialData, isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tags = tagsInput.split(',').map(t => t.trim()).filter(t => t !== '');

    // Total Amount is calculated from existing items if editing, or 0 if new.
    const record: LedgerRecord = initialData ? {
      ...initialData,
      userName,
      type,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      tags,
      notes: [{ 
        id: `N-E-${Date.now()}`, 
        timestamp: new Date().toLocaleString(), 
        content: `Protocol profile refined via system interface.` 
      }, ...initialData.notes]
    } : {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount: 0, // Must add items in detail view to increase total
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      startDate: new Date().toISOString().split('T')[0],
      tags: tags.length > 0 ? tags : ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };

    onSave(record);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        transition={{ duration: 0.5, ease: 'circOut' }}
        className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden border border-white/50 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Protocol' : 'Initialize Ledger'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] mt-1">Financial Data Preservation</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/30 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-8 max-h-[70vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-6">
            <div className="group">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Client Profile Name</label>
              <input 
                required
                type="text" 
                value={userName}
                onChange={(e) => setUserName(e.target.value)}
                placeholder="Full Name / Legal Entity"
                className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30 transition-all placeholder:text-gray-300"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Type</label>
                <select 
                  value={type}
                  onChange={(e) => setType(e.target.value as PaymentType)}
                  className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none appearance-none cursor-pointer"
                >
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed</option>
                </select>
              </div>
              <div className="flex flex-col justify-end">
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Protocol Sum</label>
                <div className="bg-white/40 border border-white/30 rounded-2xl px-5 py-4 flex items-center space-x-2">
                  <Calculator className="w-3.5 h-3.5 text-[#B8A17D]" />
                  <span className="text-sm font-jua text-[#333]">RM{(initialData?.totalAmount || 0).toLocaleString()}</span>
                </div>
              </div>
            </div>

            <div className="group">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Initial Tags (comma separated)</label>
              <input 
                type="text" 
                value={tagsInput}
                onChange={(e) => setTagsInput(e.target.value)}
                placeholder="VIP, Follow-up, Special"
                className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30 transition-all placeholder:text-gray-300"
              />
            </div>

            {type === 'Installment' && (
              <motion.div 
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                className="p-4 rounded-2xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-3"
              >
                <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block">Cycle Frequency</label>
                <div className="flex space-x-2">
                  {['Weekly', 'Monthly', 'Custom'].map(c => (
                    <button
                      key={c}
                      type="button"
                      onClick={() => setCycle(c as any)}
                      className={`flex-1 py-2 text-[10px] font-bold rounded-lg border transition-all ${cycle === c ? 'bg-[#B8A17D] text-white border-[#B8A17D]' : 'bg-white/40 border-white/30 text-gray-400'}`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            <div className="flex items-start space-x-3 p-4 rounded-2xl bg-gray-50/50">
              <Info className="w-4 h-4 text-gray-400 mt-0.5" />
              <p className="text-[10px] text-gray-400 leading-relaxed italic">
                {initialData 
                  ? 'Modifying protocol properties. Valuation is auto-aggregated based on registered assets.' 
                  : 'Total Valuation will be calculated automatically as you add items in the protocol view.'}
              </p>
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 active:scale-[0.98] transition-all"
          >
            {initialData ? 'Commit Profile Refinement' : 'Preserve Protocol'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

