import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { X, CreditCard } from 'lucide-react';
import { PaymentMethod } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (payment: any) => void;
  maxAmount: number;
}

const PaymentModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, maxAmount }) => {
  const [amount, setAmount] = useState<number>(0);
  const [method, setMethod] = useState<PaymentMethod>('BANK');
  const [note, setNote] = useState('');

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) return;
    onSubmit({
      amount,
      method,
      date: new Date().toISOString().split('T')[0],
      note
    });
    setAmount(0);
    setNote('');
  };

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-md rounded-[32px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">Settle Balance</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Transaction Entry</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Payment Amount</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-sm">RM</span>
              <input 
                required
                type="number" 
                max={maxAmount}
                value={amount || ''}
                onChange={(e) => setAmount(Number(e.target.value))}
                placeholder={`Max: RM${maxAmount.toLocaleString()}`}
                className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30 transition-all font-jua"
              />
            </div>
            <p className="text-[9px] text-gray-400 mt-2 px-1">Current outstanding: RM{maxAmount.toLocaleString()}</p>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Execution Method</label>
            <div className="grid grid-cols-3 gap-2">
              {['Cash', 'BANK', 'E-Wallet'].map((m) => (
                <button
                  key={m}
                  type="button"
                  onClick={() => setMethod(m as PaymentMethod)}
                  className={`py-3 text-[10px] font-bold rounded-xl border transition-all ${method === m ? 'bg-[#999] text-white border-[#999]' : 'bg-white/40 border-white/30 text-gray-400'}`}
                >
                  {m}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Transaction Reference</label>
            <input 
              type="text" 
              value={note}
              onChange={(e) => setNote(e.target.value)}
              placeholder="Ref number or memo"
              className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30 transition-all placeholder:text-gray-300"
            />
          </div>

          <button 
            type="submit"
            className="w-full bg-[#B8A17D] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.4em] shadow-lg border border-[#B8A17D] hover:brightness-105 transition-all"
          >
            Confirm Transaction
          </button>
        </form>
      </motion.div>
    </div>
  );
};

