          </button>

          <div className="flex-1 space-y-2">
            <div className="flex items-center space-x-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>
              {isSettled && (
                <span className="flex items-center space-x-1 bg-[#333] text-white px-2.5 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm">
