import React, { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import { X, CreditCard, ImageIcon, CheckCircle2, AlertCircle, Calendar } from 'lucide-react';
import { PaymentMethod, Attachment } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (payment: any) => void;
  maxAmount: number;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const PaymentModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, maxAmount }) => {
  const [amount, setAmount] = useState<number>(0);
  const [method, setMethod] = useState<PaymentMethod>('BANK');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [proofImage, setProofImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("Proof photo exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setProofImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) return;

    const payment: any = {
      amount,
      method,
      date,
      note
    };

    if (proofImage) {
      payment.attachment = {
        id: `A-P-${Date.now()}`,
        name: `Payment Proof: ${amount}`,
        data: proofImage,
        type: 'image',
      };
    }

    onSubmit(payment);
    resetForm();
  };

  const resetForm = () => {
    setAmount(0);
    setMethod('BANK');
    setDate(new Date().toISOString().split('T')[0]);
    setNote('');
    setProofImage(null);
    setError(null);
  };

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-md rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">Execute Injection</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Capital Transfer Protocol</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Amount</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-bold">RM</span>
                <input required type="number" max={maxAmount} value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua" placeholder="0.00" />
              </div>
            </div>
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Date</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-3.5 h-3.5" />
                <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-10 pr-4 py-4 text-sm focus:outline-none" />
              </div>
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Method</label>
            <div className="grid grid-cols-3 gap-2">
              {['Cash', 'BANK', 'E-Wallet'].map((m) => (
                <button key={m} type="button" onClick={() => setMethod(m as PaymentMethod)} className={`py-3 text-[10px] font-bold rounded-xl border transition-all ${method === m ? 'bg-[#999] text-white border-[#999]' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                  {m}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Protocol Memo</label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Transaction reference or memo..." className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-xs focus:outline-none min-h-[80px]" />
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Proof Artifact</label>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full h-24 border-2 border-dashed border-[#B8A17D]/30 rounded-2xl flex flex-col items-center justify-center text-gray-400 hover:bg-[#B8A17D]/5 transition-all overflow-hidden relative group">
              {proofImage ? (
                <img src={proofImage} className="w-full h-full object-cover" />
              ) : (
                <>
                  <ImageIcon className="w-6 h-6 mb-1 group-hover:text-[#B8A17D]" />
                  <span className="text-[9px] uppercase font-bold">Attach Proof (Max 5MB)</span>
                </>
              )}
            </button>
            {error && <p className="text-[10px] text-red-400 mt-2 flex items-center"><AlertCircle className="w-3 h-3 mr-1"/> {error}</p>}
          </div>

          <button type="submit" className="w-full bg-[#B8A17D] text-white py-5 rounded-[20px] font-bold text-xs uppercase tracking-[0.4em] shadow-lg border border-[#B8A17D] hover:brightness-105 transition-all">Archive Injection</button>
        </form>
      </motion.div>
    </div>
  );
};

