import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  // Initial Seed Data
  useEffect(() => {
    const mockData: LedgerRecord[] = [
      {
        id: 'JT-202401-001',
        userName: 'Alexander Vanderbilt',
        type: 'Installment',
        totalAmount: 25000,
        paidAmount: 10000,
        paymentCycle: 'Monthly',
        nextPaymentDate: '2024-11-15',
        startDate: '2024-01-10',
        tags: ['Old Customer', 'VVIP'],
        items: [
          { id: 'I-01', name: 'Diamond Chronograph XL', amount: 15000, date: '2024-01-10', note: 'Gift collection' },
          { id: 'I-02', name: 'Bespoke Cufflinks', amount: 10000, date: '2024-01-10' }
        ],
        payments: [
          { id: 'P-01', amount: 5000, method: 'BANK', date: '2024-01-10', note: 'Initial Deposit' },
          { id: 'P-02', amount: 5000, method: 'BANK', date: '2024-02-10', note: 'Feb Installment' }
        ],
        notes: [
          { id: 'N-01', timestamp: '2024-01-10 14:00', content: 'Account established with priority status.' }
        ],
        attachments: [],
        status: 'Active'
      }
    ];
    setRecords(mockData);
  }, []);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        // Auto-settle only if paid >= total
        const newStatus = newPaid >= r.totalAmount ? 'Settled' : r.status;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Injection of RM${payment.amount.toLocaleString()} archived via ${payment.method}.`
        };
        const newPayments = [...r.payments, { ...payment, id: `P-${Date.now()}` }];

        return {
          ...r,
          paidAmount: newPaid,
          status: newStatus,
          payments: newPayments,
          notes: [newNote, ...r.notes]
        };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return {
          ...r,
          items: newItems,
          totalAmount: newTotal,
          status: r.paidAmount >= newTotal ? 'Settled' : 'Active'
        };
      }
      return r;
    }));
  };

  const handleAddTag = (recordId: string, tag: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId && !r.tags.includes(tag)) {
        return { ...r, tags: [...r.tags, tag] };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, type };
      }
      return r;
    }));
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      {/* Header */}
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN <span className="text-xs font-normal align-top bg-[#999] text-white px-2 py-0.5 rounded-full">PVT</span></h1>
          <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Private Balance Management System</p>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Records..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64"
            />
          </div>
          <motion.button 
            whileHover={{ brightness: 1.05 }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Record</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
          <div className="flex items-center space-x-6">
            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
              <div className="flex space-x-1.5">
                {['All', 'Active', 'Settled'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setStatusFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      statusFilter === filter 
                        ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Type:</span>
              <div className="flex space-x-1.5">
                {['All', 'Installment', 'Delayed'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setTypeFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      typeFilter === filter 
                        ? 'bg-[#333] text-white border-[#333]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Showing {filteredRecords.length} records
          </div>
        </div>

        <div className="w-full">
          <CustomerList 
            records={filteredRecords} 
            onSelect={setSelectedRecordId} 
            selectedId={selectedRecordId}
          />
        </div>
      </main>

      {/* Full Page Detail Overlay */}
      <AnimatePresence>
        {selectedRecordId && selectedRecord && (
          <CustomerDetail 
            record={selectedRecord} 
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(selectedRecord.id, item)}
            onAddTag={(tag) => handleAddTag(selectedRecord.id, tag)}
            onAddAttachment={(att) => handleAddAttachment(selectedRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(selectedRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(selectedRecord.id, type)}
          />
        )}
      </AnimatePresence>

      {/* Modals */}
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={selectedRecord} />
      {selectedRecord && (
        <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(selectedRecord.id, p)} maxAmount={selectedRecord.totalAmount - selectedRecord.paidAmount} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Tag as TagIcon,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddTag: (tag: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddTag, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [tagInput, setTagInput] = useState('');

  // Item Form State
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [newItemName, setNewItemName] = useState('');
  const [newItemAmount, setNewItemAmount] = useState(0);
  const [newItemDate, setNewItemDate] = useState(new Date().toISOString().split('T')[0]);
  const [newItemNote, setNewItemNote] = useState('');
  const [newItemImage, setNewItemImage] = useState<string | null>(null);

  // Evidence Form State
  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const evidenceInputRef = useRef<HTMLInputElement>(null);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("File size exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setter(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddTagSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (tagInput.trim()) {
      onAddTag(tagInput.trim());
      setTagInput('');
      setIsAddingTag(false);
    }
  };

  const handleAddItemSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newItemName.trim() && newItemAmount > 0) {
      const item: PurchaseItem = {
        id: `I-${Date.now()}`,
        name: newItemName.trim(),
        amount: newItemAmount,
        date: newItemDate,
        note: newItemNote,
      };
      if (newItemImage) {
        item.attachment = {
          id: `A-I-${Date.now()}`,
          name: `Item Photo: ${newItemName}`,
          data: newItemImage,
          type: 'image',
        };
      }
      onAddItem(item);
      resetItemForm();
    }
  };

  const resetItemForm = () => {
    setNewItemName('');
    setNewItemAmount(0);
    setNewItemDate(new Date().toISOString().split('T')[0]);
    setNewItemNote('');
    setNewItemImage(null);
    setIsAddingItem(false);
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({
        id: `A-E-${Date.now()}`,
        name: `General Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      });
      setEvidenceNote('');
      setEvidenceImage(null);
      setIsAddingEvidence(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button 
            onClick={onClose}
            className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90"
          >
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>

              {/* Type Badge (Clickable to toggle) */}
              <button 
                onClick={() => onUpdateType(record.type === 'Installment' ? 'Delayed' : 'Installment')}
                className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center"
              >
                {record.type}
                <ChevronDown className="w-2 h-2 ml-1 opacity-40" />
              </button>

              {/* Status Badge (Clickable to change) */}
              <select 
                value={record.status}
                onChange={(e) => onUpdateStatus(e.target.value as any)}
                className={`appearance-none bg-[#333] text-white px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm cursor-pointer hover:bg-black transition-all outline-none text-center`}
              >
                <option value="Active">Active</option>
                <option value="Settled">Settled</option>
                <option value="Overdue">Overdue</option>
              </select>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button 
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={onEdit}
                className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm"
              >
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <p className="text-[12px] text-gray-400 tracking-[0.2em] font-mono">ID: {record.id}</p>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Paid</p>
