            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>
              <button onClick={() => onUpdateType(record.type === 'Installment' ? 'Delayed' : 'Installment')} className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center">
                {record.type} <ChevronDown className="w-2 h-2 ml-1 opacity-40" />
              </button>
              <select value={record.status} onChange={(e) => onUpdateStatus(e.target.value as any)} className="appearance-none bg-[#333] text-white px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm cursor-pointer hover:bg-black outline-none text-center">
                <option value="Active">Active</option>
                <option value="Settled">Settled</option>
                <option value="Overdue">Overdue</option>
              </select>
