              <div className="space-y-4">
                <p className="text-3xl font-jua text-green-600/80">RM{selectedPayment.amount.toLocaleString()}</p>
                <p className="text-sm font-bold text-gray-700">{selectedPayment.method} Protocol Executed {selectedPayment.date}</p>
                <p className="text-sm italic text-gray-500">{selectedPayment.note || 'Reference memo absent.'}</p>
