import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  // Initial Seed Data
  useEffect(() => {
    const mockData: LedgerRecord[] = [
      {
        id: 'JT-202401-001',
        userName: 'Alexander Vanderbilt',
        type: 'Installment',
        totalAmount: 2400,
        paidAmount: 600,
        paymentCycle: 'Weekly',
        startDate: '2024-01-01',
        endDate: '2024-01-31', // 4 weeks
        tags: ['Old Customer', 'VVIP'],
        items: [
          { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
        ],
        payments: [
          { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Week 1 Installment' }
        ],
        notes: [
          { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
        ],
        attachments: [],
        status: 'Active'
      }
    ];
    setRecords(mockData);
  }, []);

  // Automatic Status Monitor
  useEffect(() => {
    const now = new Date();
    setRecords(prev => prev.map(r => {
      let newStatus = r.status;

      // Auto Settle
      if (r.paidAmount >= r.totalAmount && r.totalAmount > 0) {
        newStatus = 'Settled';
      } else if (r.endDate) {
        // Auto Overdue check if past end date and not paid off
        const end = new Date(r.endDate);
        if (now > end && r.paidAmount < r.totalAmount) {
          newStatus = 'Overdue';
        } else if (now <= end && r.paidAmount < r.totalAmount && r.status === 'Overdue') {
          // Revert to active if date is extended or payments made (logic fallback)
          newStatus = 'Active';
        }
      }

      return newStatus !== r.status ? { ...r, status: newStatus } : r;
    }));
  }, [records.map(r => r.paidAmount + r.totalAmount + r.endDate).join(',')]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Capital Injection of RM${payment.amount.toLocaleString()} archived via ${payment.method}. Balance remaining: RM${(r.totalAmount - newPaid).toLocaleString()}.`
        };
        const newPayments = [...r.payments, { ...payment, id: `P-${Date.now()}` }];

        return {
          ...r,
          paidAmount: newPaid,
          payments: newPayments,
          notes: [newNote, ...r.notes]
        };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return {
          ...r,
          items: newItems,
          totalAmount: newTotal
        };
      }
      return r;
    }));
  };

  const handleAddTag = (recordId: string, tag: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId && !r.tags.includes(tag)) {
        return { ...r, tags: [...r.tags, tag] };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, type };
      }
      return r;
    }));
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      {/* Header */}
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN <span className="text-xs font-normal align-top bg-[#999] text-white px-2 py-0.5 rounded-full">PVT</span></h1>
          <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Private Balance Management System</p>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Records..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ brightness: 1.05 }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Record</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
          <div className="flex items-center space-x-6">
            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
              <div className="flex space-x-1.5">
                {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setStatusFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      statusFilter === filter 
                        ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Type:</span>
              <div className="flex space-x-1.5">
                {['All', 'Installment', 'Delayed'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setTypeFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      typeFilter === filter 
                        ? 'bg-[#333] text-white border-[#333]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Showing {filteredRecords.length} records
          </div>
        </div>

        <div className="w-full">
          <CustomerList 
            records={filteredRecords} 
            onSelect={setSelectedRecordId} 
            selectedId={selectedRecordId}
          />
        </div>
      </main>

      {/* Full Page Detail Overlay */}
      <AnimatePresence>
        {selectedRecordId && selectedRecord && (
          <CustomerDetail 
            record={selectedRecord} 
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(selectedRecord.id, item)}
            onAddTag={(tag) => handleAddTag(selectedRecord.id, tag)}
            onAddAttachment={(att) => handleAddAttachment(selectedRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(selectedRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(selectedRecord.id, type)}
          />
        )}
      </AnimatePresence>

      {/* Modals */}
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={selectedRecord} />
      {selectedRecord && (
        <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(selectedRecord.id, p)} maxAmount={selectedRecord.totalAmount - selectedRecord.paidAmount} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Tag as TagIcon,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddTag: (tag: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddTag, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);

  const evidenceInputRef = useRef<HTMLInputElement>(null);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Advanced Installment Calculation & Pinned Reminders
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate || !record.endDate) return [];

    const now = new Date();
    const start = new Date(record.startDate);
    const end = new Date(record.endDate);

    // Calculate total periods
    let totalPeriods = 0;
    if (record.paymentCycle === 'Weekly') {
      totalPeriods = Math.ceil((end.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000)) || 1;
    } else if (record.paymentCycle === 'Monthly') {
      totalPeriods = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) || 1;
    } else {
       totalPeriods = 1; // Custom fallback
    }

    const installmentAmount = record.totalAmount / totalPeriods;

    // Determine current period
    let currentPeriod = 0;
    if (record.paymentCycle === 'Weekly') {
      currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    } else if (record.paymentCycle === 'Monthly') {
      currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    }

    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    // Calculate next due date for the reminder
    let nextDate = new Date(start);
    if (record.paymentCycle === 'Weekly') {
      nextDate.setDate(start.getDate() + (currentPeriod * 7));
    } else if (record.paymentCycle === 'Monthly') {
      nextDate.setMonth(start.getMonth() + currentPeriod);
    }

    // Only pin if there's a balance left
    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `Calculated Protocol Installment [${currentPeriod} / ${totalPeriods}]: RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due for current cycle. Total outstanding balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => {
    return [...pinnedReminders, ...record.notes];
  }, [pinnedReminders, record.notes]);

  const displayedTimeline = useMemo(() => {
    if (isTimelineExpanded) return timelineNotes;
    return timelineNotes.slice(0, 10);
  }, [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("File size exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({
        id: `A-E-${Date.now()}`,
        name: `General Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>
              <button onClick={() => onUpdateType(record.type === 'Installment' ? 'Delayed' : 'Installment')} className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center shadow-sm">
                {record.type} <ChevronDown className="w-2 h-2 ml-1 opacity-40" />
              </button>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white' : 
                record.status === 'Settled' ? 'bg-[#333] text-white' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> End: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999] shadow-[0_0_8px_rgba(184,161,125,0.4)]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Paid</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Balance</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline-overlay" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><TagIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Tags</h4>
                  <div className="flex flex-wrap gap-3">
                    {record.tags.map(tag => <span key={tag} className="px-5 py-2 rounded-xl bg-white/40 border border-[#B8A17D]/30 text-[10px] font-bold text-[#B8A17D] tracking-widest uppercase">{tag}</span>)}
                    {!isAddingTag ? (
                      <button 
                        onClick={() => setIsAddingTag(true)}
                        className="px-5 py-2 rounded-xl border border-dashed border-gray-300 text-[10px] font-bold text-gray-400 hover:border-[#B8A17D]/40 hover:text-[#B8A17D] transition-all"
                      >
                        + Add Tag
                      </button>
                    ) : (
                      <form onSubmit={(e) => {
                        e.preventDefault();
                        if (tagInput.trim()) {
                          onAddTag(tagInput.trim());
                          setTagInput('');
                          setIsAddingTag(false);
                        }
                      }} className="flex items-center space-x-2">
                        <input autoFocus type="text" value={tagInput} onChange={(e) => setTagInput(e.target.value)} className="bg-white/40 border border-white/60 rounded-lg px-3 py-1 text-[10px] focus:outline-none" placeholder="Tag..." />
                        <button type="submit" className="p-1 text-[#B8A17D]"><Plus className="w-3.5 h-3.5"/></button>
                      </form>
                    )}
                  </div>
                </div>
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    <button onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>
                  </h4>
                  {isAddingEvidence && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4 shadow-sm">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, setEvidenceImage)} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black transition-colors">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {record.attachments.map(att => (
                      <div key={att.id} onClick={() => setSelectedAttachment(att)} className="bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                      </div>
                    ))}
                    {record.attachments.length === 0 && !isAddingEvidence && <div className="col-span-2 text-center py-8 opacity-20 border border-dashed border-gray-300 rounded-2xl"><p className="text-[9px] uppercase tracking-widest font-bold">No evidence archived</p></div>}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>
                        {note.isPinned ? 'System Calculation Reminder' : note.timestamp}
                      </p>
                      <p className={`text-[14px] leading-relaxed font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>
                        {note.content}
                      </p>
                    </div>
                  ))}
                </div>
                {timelineNotes.length > 10 && (
                  <button 
                    onClick={() => setIsTimelineExpanded(!isTimelineExpanded)}
                    className="flex items-center justify-center space-x-2 w-full py-4 mt-4 bg-white/30 border border-white/40 rounded-2xl text-[10px] font-bold uppercase tracking-[0.2em] text-[#B8A17D] hover:bg-white/50 transition-all shadow-sm"
                  >
                    <span>{isTimelineExpanded ? 'Show Less Protocol Data' : `Expand Full Protocol History (${timelineNotes.length - 10} more)`}</span>
                    {isTimelineExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                  </button>
                )}
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              {/* Premium Add Item Button */}
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={() => setIsAddingItemModalOpen(true)}
                className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow"
              >
                <ShoppingBag className="w-5 h-5" />
                <span>Declare New Asset Entry</span>
              </motion.button>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {record.items.map(item => (
                  <div key={item.id} onClick={() => setSelectedItem(item)} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 shadow-sm group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
                {record.items.length === 0 && (
                  <div className="col-span-2 text-center py-20 opacity-20 flex flex-col items-center">
                    <ShoppingBag className="w-16 h-16 mb-4" />
                    <p className="text-sm font-bold uppercase tracking-widest">No assets archived for this profile.</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-3xl mx-auto space-y-8">
              {/* Execute Injection Button in History Tab */}
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={onPayment} disabled={record.status === 'Settled'}
                className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow'}`}
              >
                <CreditCard className="w-5 h-5" />
                <span>{record.status === 'Settled' ? 'Full Settlement Achieved' : 'Execute Capital Injection'}</span>
              </motion.button>

              <div className="space-y-6">
                {record.payments.map(payment => (
                  <div key={payment.id} onClick={() => setSelectedPayment(payment)} className="flex items-start space-x-8 p-8 rounded-[36px] bg-white/30 border border-white/40 hover:bg-white/40 cursor-pointer group shadow-sm transition-all">
                    <div className="p-5 rounded-2xl bg-[#333] shadow-lg group-hover:bg-black transition-colors"><CreditCard className="w-7 h-7 text-[#B8A17D]" /></div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-lg font-bold text-[#333] tracking-tight">{payment.method} Protocol</span>
                        <span className="text-2xl font-jua text-green-600/80 tracking-tighter">+ RM{payment.amount.toLocaleString()}</span>
                      </div>
                      <div className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{payment.date}</div>
                    </div>
                  </div>
                ))}
                {record.payments.length === 0 && <div className="text-center py-20 opacity-20 flex flex-col items-center"><History className="w-16 h-16 mb-4" /><p className="text-sm font-bold uppercase tracking-widest">No Protocol History</p></div>}
              </div>
            </div>
          )}
        </div>

        {/* Action Footer refined */}
        <div className="p-8 px-12 border-t border-white/40 flex justify-center bg-white/20">
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.3em] opacity-60">Authorized Private Ledger System Access</p>
        </div>
      </motion.div>

      {/* Add Item Modal */}
      <AnimatePresence>
        {isAddingItemModalOpen && (
          <AddItemModal 
            isOpen={isAddingItemModalOpen} 
            onClose={() => setIsAddingItemModalOpen(false)} 
            onSubmit={(item) => {
              onAddItem(item);
              setIsAddingItemModalOpen(false);
            }} 
          />
        )}
      </AnimatePresence>

      {/* Overlays for detailed view */}
      <AnimatePresence>
        {selectedItem && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedItem(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Asset Insight</h3><button onClick={() => setSelectedItem(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedItem.attachment?.data && <img src={selectedItem.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-lg font-bold">{selectedItem.name}</p>
                <p className="text-2xl font-jua text-[#B8A17D]">RM{selectedItem.amount.toLocaleString()}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedItem.note || 'No memo available.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedPayment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedPayment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Audit Confirmation</h3><button onClick={() => setSelectedPayment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedPayment.attachment?.data && <img src={selectedPayment.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-3xl font-jua text-green-600/80">RM{selectedPayment.amount.toLocaleString()}</p>
                <p className="text-sm font-bold text-gray-700">{selectedPayment.method} Protocol Executed {selectedPayment.date}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedPayment.note || 'Reference memo absent.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedAttachment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedAttachment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-2xl w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center"><h3 className="text-2xl font-jua text-[#333]">Secure Artifact</h3><button onClick={() => setSelectedAttachment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedAttachment.data && <img src={selectedAttachment.data} className="w-full max-h-[60vh] object-contain rounded-2xl shadow-inner bg-black/5" />}
              {selectedAttachment.description && <div className="bg-white/30 p-6 rounded-3xl border border-white/40"><p className="text-[10px] text-gray-400 uppercase font-bold mb-2">Evidence Annotation</p><p className="text-sm text-gray-700 italic leading-relaxed">{selectedAttachment.description}</p></div>}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default CustomerDetail;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Tag as TagIcon,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddTag: (tag: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddTag, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);

  const evidenceInputRef = useRef<HTMLInputElement>(null);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Advanced Installment Calculation & Pinned Reminders
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate || !record.endDate) return [];

    const now = new Date();
    const start = new Date(record.startDate);
    const end = new Date(record.endDate);

    // Calculate total periods (weeks or months)
    let totalPeriods = 0;
    const diffMs = end.getTime() - start.getTime();

    if (record.paymentCycle === 'Weekly') {
      totalPeriods = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000)) || 1;
    } else if (record.paymentCycle === 'Monthly') {
      totalPeriods = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
      if (end.getDate() > start.getDate()) totalPeriods += 1;
      totalPeriods = Math.max(1, totalPeriods);
    } else {
       totalPeriods = 1;
    }

    const installmentAmount = record.totalAmount / totalPeriods;

    // Find current period relative to today
    let currentPeriod = 1;
    if (record.paymentCycle === 'Weekly') {
      const elapsedMs = now.getTime() - start.getTime();
      currentPeriod = Math.ceil(elapsedMs / (7 * 24 * 60 * 60 * 1000));
    } else if (record.paymentCycle === 'Monthly') {
      currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    }

    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    // Next payment target date
    let nextDate = new Date(start);
    if (record.paymentCycle === 'Weekly') {
      nextDate.setDate(start.getDate() + (currentPeriod * 7));
    } else if (record.paymentCycle === 'Monthly') {
      nextDate.setMonth(start.getMonth() + currentPeriod);
    }

    // Only pin if there's balance left
    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `Auto Protocol Reminder [Cycle ${currentPeriod}/${totalPeriods}]: Weekly installment calculated at RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})}. Current outstanding: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => {
    return [...pinnedReminders, ...record.notes];
  }, [pinnedReminders, record.notes]);

  const displayedTimeline = useMemo(() => {
    if (isTimelineExpanded) return timelineNotes;
    return timelineNotes.slice(0, 10);
  }, [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("File size exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({
        id: `A-E-${Date.now()}`,
        name: `General Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">Private Ledger Protocol</span>
              <button onClick={() => onUpdateType(record.type === 'Installment' ? 'Delayed' : 'Installment')} className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center shadow-sm">
                {record.type} <ChevronDown className="w-2 h-2 ml-1 opacity-40" />
              </button>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white' : 
                record.status === 'Settled' ? 'bg-[#333] text-white' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> End: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999] shadow-[0_0_8px_rgba(184,161,125,0.4)]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Paid</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Balance</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline-overlay" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><TagIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Tags</h4>
                  <div className="flex flex-wrap gap-3">
                    {record.tags.map(tag => <span key={tag} className="px-5 py-2 rounded-xl bg-white/40 border border-[#B8A17D]/30 text-[10px] font-bold text-[#B8A17D] tracking-widest uppercase">{tag}</span>)}
                    {!isAddingTag ? (
                      <button 
                        onClick={() => setIsAddingTag(true)}
                        className="px-5 py-2 rounded-xl border border-dashed border-gray-300 text-[10px] font-bold text-gray-400 hover:border-[#B8A17D]/40 hover:text-[#B8A17D] transition-all"
                      >
                        + Add Tag
                      </button>
                    ) : (
                      <form onSubmit={(e) => {
                        e.preventDefault();
                        if (tagInput.trim()) {
                          onAddTag(tagInput.trim());
                          setTagInput('');
                          setIsAddingTag(false);
                        }
                      }} className="flex items-center space-x-2">
                        <input autoFocus type="text" value={tagInput} onChange={(e) => setTagInput(e.target.value)} className="bg-white/40 border border-white/60 rounded-lg px-3 py-1 text-[10px] focus:outline-none" placeholder="Tag..." />
                        <button type="submit" className="p-1 text-[#B8A17D]"><Plus className="w-3.5 h-3.5"/></button>
                      </form>
                    )}
                  </div>
                </div>
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    <button onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>
                  </h4>
                  {isAddingEvidence && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4 shadow-sm">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, setEvidenceImage)} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black transition-colors">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {record.attachments.map(att => (
                      <div key={att.id} onClick={() => setSelectedAttachment(att)} className="bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                      </div>
                    ))}
                    {record.attachments.length === 0 && !isAddingEvidence && <div className="col-span-2 text-center py-8 opacity-20 border border-dashed border-gray-300 rounded-2xl"><p className="text-[9px] uppercase tracking-widest font-bold">No evidence archived</p></div>}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>
                        {note.isPinned ? 'Protocol Reminders' : note.timestamp}
                      </p>
                      <p className={`text-[14px] leading-relaxed font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>
                        {note.content}
                      </p>
                    </div>
                  ))}
                </div>
                {timelineNotes.length > 10 && (
                  <button 
                    onClick={() => setIsTimelineExpanded(!isTimelineExpanded)}
                    className="flex items-center justify-center space-x-2 w-full py-4 mt-4 bg-white/30 border border-white/40 rounded-2xl text-[10px] font-bold uppercase tracking-[0.2em] text-[#B8A17D] hover:bg-white/50 transition-all shadow-sm"
                  >
                    <span>{isTimelineExpanded ? 'Show Less Protocol Data' : `Expand Full Protocol History (${timelineNotes.length - 10} more)`}</span>
                    {isTimelineExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                  </button>
                )}
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={() => setIsAddingItemModalOpen(true)}
                className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow"
              >
                <ShoppingBag className="w-5 h-5" />
                <span>Declare New Asset Entry</span>
              </motion.button>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {record.items.map(item => (
                  <div key={item.id} onClick={() => setSelectedItem(item)} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 shadow-sm group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
                {record.items.length === 0 && (
                  <div className="col-span-2 text-center py-20 opacity-20 flex flex-col items-center">
                    <ShoppingBag className="w-16 h-16 mb-4" />
                    <p className="text-sm font-bold uppercase tracking-widest">No assets archived for this profile.</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-3xl mx-auto space-y-8">
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={onPayment} disabled={record.status === 'Settled'}
                className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow'}`}
              >
                <CreditCard className="w-5 h-5" />
                <span>{record.status === 'Settled' ? 'Full Settlement Achieved' : 'Execute Capital Injection'}</span>
              </motion.button>

              <div className="space-y-6">
                {record.payments.map(payment => (
                  <div key={payment.id} onClick={() => setSelectedPayment(payment)} className="flex items-start space-x-8 p-8 rounded-[36px] bg-white/30 border border-white/40 hover:bg-white/40 cursor-pointer group shadow-sm transition-all">
                    <div className="p-5 rounded-2xl bg-[#333] shadow-lg group-hover:bg-black transition-colors"><CreditCard className="w-7 h-7 text-[#B8A17D]" /></div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-lg font-bold text-[#333] tracking-tight">{payment.method} Protocol</span>
                        <span className="text-2xl font-jua text-green-600/80 tracking-tighter">+ RM{payment.amount.toLocaleString()}</span>
                      </div>
                      <div className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{payment.date}</div>
                    </div>
                  </div>
                ))}
                {record.payments.length === 0 && <div className="text-center py-20 opacity-20 flex flex-col items-center"><History className="w-16 h-16 mb-4" /><p className="text-sm font-bold uppercase tracking-widest">No Protocol History</p></div>}
              </div>
            </div>
          )}
        </div>

        {/* Action Footer refined */}
        <div className="p-8 px-12 border-t border-white/40 flex justify-center bg-white/20">
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.3em] opacity-60">Authorized Private Ledger System Access</p>
        </div>
      </motion.div>

      {/* Add Item Modal */}
      <AnimatePresence>
        {isAddingItemModalOpen && (
          <AddItemModal 
            isOpen={isAddingItemModalOpen} 
            onClose={() => setIsAddingItemModalOpen(false)} 
            onSubmit={(item) => {
              onAddItem(item);
              setIsAddingItemModalOpen(false);
            }} 
          />
        )}
      </AnimatePresence>

      {/* Overlays for detailed view */}
      <AnimatePresence>
        {selectedItem && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedItem(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Asset Insight</h3><button onClick={() => setSelectedItem(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedItem.attachment?.data && <img src={selectedItem.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-lg font-bold">{selectedItem.name}</p>
                <p className="text-2xl font-jua text-[#B8A17D]">RM{selectedItem.amount.toLocaleString()}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedItem.note || 'No memo available.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedPayment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedPayment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Audit Confirmation</h3><button onClick={() => setSelectedPayment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedPayment.attachment?.data && <img src={selectedPayment.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-3xl font-jua text-green-600/80">RM{selectedPayment.amount.toLocaleString()}</p>
                <p className="text-sm font-bold text-gray-700">{selectedPayment.method} Protocol Executed {selectedPayment.date}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedPayment.note || 'Reference memo absent.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedAttachment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedAttachment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-2xl w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center"><h3 className="text-2xl font-jua text-[#333]">Secure Artifact</h3><button onClick={() => setSelectedAttachment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedAttachment.data && <img src={selectedAttachment.data} className="w-full max-h-[60vh] object-contain rounded-2xl shadow-inner bg-black/5" />}
              {selectedAttachment.description && <div className="bg-white/30 p-6 rounded-3xl border border-white/40"><p className="text-[10px] text-gray-400 uppercase font-bold mb-2">Evidence Annotation</p><p className="text-sm text-gray-700 italic leading-relaxed">{selectedAttachment.description}</p></div>}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default CustomerDetail;

