export type PaymentType = 'Installment' | 'Delayed';
export type PaymentMethod = 'Cash' | 'BANK' | 'E-Wallet';

export interface PurchaseItem {
  id: string;
  name: string;
  amount: number;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface PaymentRecord {
  id: string;
  amount: number;
  method: PaymentMethod;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface SystemNote {
  id: string;
  timestamp: string;
  content: string;
  isPinned?: boolean;
}

export interface Attachment {
  id: string;
  name: string;
  data: string; // Base64 or URL
  type: 'image' | 'document';
  description?: string;
  fileSize?: number;
}

export interface LedgerRecord {
  id: string; // Format: JT-YYYYMM-XXXX
  userName: string;
  type: PaymentType;
  totalAmount: number; // Derived from sum of items
  paidAmount: number;
  paymentCycle?: 'Day' | 'Weekly' | 'Monthly' | 'Custom';
  cycleCount?: number; // Number of periods (e.g., 4 weeks, 10 days)
  startDate: string;
  endDate?: string;
  nextPaymentDate?: string;
  tags: string[];
  items: PurchaseItem[];
  payments: PaymentRecord[];
  notes: SystemNote[];
  attachments: Attachment[]; // General evidence collection
  status: 'Active' | 'Settled' | 'Overdue';
}

export interface DashboardStats {
  totalOutstanding: number;
  activeCustomers: number;
  collectedThisMonth: number;
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Info, Calculator, Calendar, Hash } from 'lucide-react';
import { LedgerRecord, PaymentType } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: LedgerRecord) => void;
  initialData?: LedgerRecord;
}

const RecordFormModal: React.FC<Props> = ({ isOpen, onClose, onSave, initialData }) => {
  const [userName, setUserName] = useState('');
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Day' | 'Weekly' | 'Monthly' | 'Custom'>('Monthly');
  const [cycleCount, setCycleCount] = useState<number>(1);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState('');
  const [tagsInput, setTagsInput] = useState('');

  useEffect(() => {
    if (initialData) {
      setUserName(initialData.userName);
      setType(initialData.type);
      setCycle(initialData.paymentCycle || 'Monthly');
      setCycleCount(initialData.cycleCount || 1);
      setStartDate(initialData.startDate);
      setEndDate(initialData.endDate || '');
      setTagsInput(initialData.tags.join(', '));
    } else {
      setUserName('');
      setType('Installment');
      setCycle('Monthly');
      setCycleCount(1);
      setStartDate(new Date().toISOString().split('T')[0]);
      setEndDate('');
      setTagsInput('');
    }
  }, [initialData, isOpen]);

  // Auto-calculate end date when cycle or count changes
  useEffect(() => {
    if (type === 'Installment' && startDate && cycleCount > 0) {
      const start = new Date(startDate);
      const calculatedEnd = new Date(start);

      if (cycle === 'Day') {
        calculatedEnd.setDate(start.getDate() + cycleCount);
      } else if (cycle === 'Weekly') {
        calculatedEnd.setDate(start.getDate() + (cycleCount * 7));
      } else if (cycle === 'Monthly') {
        calculatedEnd.setMonth(start.getMonth() + cycleCount);
      } else {
        return; // Custom doesn't auto-calculate
      }

      setEndDate(calculatedEnd.toISOString().split('T')[0]);
    }
  }, [cycle, cycleCount, startDate, type]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tags = tagsInput.split(',').map(t => t.trim()).filter(t => t !== '');

    const record: LedgerRecord = initialData ? {
      ...initialData,
      userName,
      type,
      startDate,
      endDate: endDate || undefined,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      tags,
      notes: [{ 
        id: `N-E-${Date.now()}`, 
        timestamp: new Date().toLocaleString(), 
        content: `Protocol profile refined via system interface.` 
      }, ...initialData.notes]
    } : {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount: 0,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      startDate,
      endDate: endDate || undefined,
      tags: tags.length > 0 ? tags : ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };

    onSave(record);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        transition={{ duration: 0.5, ease: 'circOut' }}
        className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden border border-white/50 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Protocol' : 'Initialize Ledger'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] mt-1">Financial Data Preservation</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/30 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-5">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Client Profile Name</label>
              <input required type="text" value={userName} onChange={(e) => setUserName(e.target.value)} placeholder="Full Name" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Start Protocol Date</label>
                <input required type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Maturity Date (End)</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Type</label>
                <select value={type} onChange={(e) => setType(e.target.value as PaymentType)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none appearance-none cursor-pointer">
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Initial Tags</label>
                <input type="text" value={tagsInput} onChange={(e) => setTagsInput(e.target.value)} placeholder="VIP, New" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            {type === 'Installment' && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="p-6 rounded-3xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-6">
                <div>
                  <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block mb-3">Cycle Frequency Reminder</label>
                  <div className="flex space-x-2">
                    {['Day', 'Weekly', 'Monthly', 'Custom'].map(c => (
                      <button key={c} type="button" onClick={() => setCycle(c as any)} className={`flex-1 py-2.5 text-[10px] font-bold rounded-xl border transition-all ${cycle === c ? 'bg-[#333] text-white border-[#333] shadow-md' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                        {c}
                      </button>
                    ))}
                  </div>
                </div>

                {cycle !== 'Custom' && (
                  <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-2">
                    <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">
                      {cycle === 'Day' ? 'Duration (Days)' : cycle === 'Weekly' ? 'Duration (Weeks)' : 'Duration (Months)'}
                    </label>
                    <div className="relative">
                      <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-300" />
                      <input 
                        type="number" 
                        min="1" 
                        value={cycleCount} 
                        onChange={(e) => setCycleCount(Math.max(1, Number(e.target.value)))} 
                        className="w-full bg-white/60 border border-white/30 rounded-2xl pl-10 pr-5 py-3 text-sm focus:outline-none font-jua" 
                      />
                    </div>
                    <p className="text-[9px] text-gray-400 italic px-1">Sets the maturity date and installments automatically.</p>
                  </motion.div>
                )}
              </motion.div>
            )}
          </div>

          <button type="submit" className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 transition-all">
            {initialData ? 'Update Protocol' : 'Preserve Protocol'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default RecordFormModal;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Tag as TagIcon,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddTag: (tag: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddTag, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);

  const evidenceInputRef = useRef<HTMLInputElement>(null);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Advanced Installment Calculation & Pinned Reminders
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];

    const now = new Date();
    const start = new Date(record.startDate);

    // Total periods - prioritize the explicitly saved cycleCount
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';

    // Fallback if no cycleCount but has endDate
    if (!record.cycleCount && record.endDate) {
      const end = new Date(record.endDate);
      const diffMs = end.getTime() - start.getTime();
      if (record.paymentCycle === 'Day') totalPeriods = Math.ceil(diffMs / (24 * 60 * 60 * 1000)) || 1;
      else if (record.paymentCycle === 'Weekly') totalPeriods = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000)) || 1;
      else if (record.paymentCycle === 'Monthly') {
        totalPeriods = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) totalPeriods += 1;
        totalPeriods = Math.max(1, totalPeriods);
      }
    }

    const installmentAmount = record.totalAmount / totalPeriods;

    // Find current period relative to today
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') {
      const elapsedMs = now.getTime() - start.getTime();
      currentPeriod = Math.ceil(elapsedMs / (24 * 60 * 60 * 1000));
    } else if (record.paymentCycle === 'Weekly') {
      const elapsedMs = now.getTime() - start.getTime();
      currentPeriod = Math.ceil(elapsedMs / (7 * 24 * 60 * 60 * 1000));
    } else if (record.paymentCycle === 'Monthly') {
      currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    }

    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    // Next payment target date
    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    // Only pin if there's balance left
    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due per cycle. Outstanding Balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => {
    return [...pinnedReminders, ...record.notes];
  }, [pinnedReminders, record.notes]);

  const displayedTimeline = useMemo(() => {
    if (isTimelineExpanded) return timelineNotes;
    return timelineNotes.slice(0, 10);
  }, [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("File size exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({
        id: `A-E-${Date.now()}`,
        name: `General Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>
              <button onClick={() => onUpdateType(record.type === 'Installment' ? 'Delayed' : 'Installment')} className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center shadow-sm">
                {record.type} <ChevronDown className="w-2 h-2 ml-1 opacity-40" />
              </button>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white' : 
                record.status === 'Settled' ? 'bg-[#333] text-white' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> End: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999] shadow-[0_0_8px_rgba(184,161,125,0.4)]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Paid</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Balance</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline-overlay" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
