                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black transition-colors">Archive Evidence</button>
                    </motion.div>
