import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Info, Calculator, Calendar, Hash } from 'lucide-react';
import { LedgerRecord, PaymentType } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: LedgerRecord) => void;
  initialData?: LedgerRecord;
}

const RecordFormModal: React.FC<Props> = ({ isOpen, onClose, onSave, initialData }) => {
  const [userName, setUserName] = useState('');
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Day' | 'Weekly' | 'Monthly'>('Monthly');
  const [cycleCount, setCycleCount] = useState<number>(1);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState('');
  const [tagsInput, setTagsInput] = useState('');

  useEffect(() => {
    if (initialData) {
      setUserName(initialData.userName);
      setType(initialData.type);
      setCycle((initialData.paymentCycle as any) || 'Monthly');
      setCycleCount(initialData.cycleCount || 1);
      setStartDate(initialData.startDate);
      setEndDate(initialData.endDate || '');
      setTagsInput(initialData.tags.join(', '));
    } else {
      setUserName('');
      setType('Installment');
      setCycle('Monthly');
      setCycleCount(1);
      setStartDate(new Date().toISOString().split('T')[0]);
      setEndDate('');
      setTagsInput('');
    }
  }, [initialData, isOpen]);

  // Auto-calculate end date when cycle or count changes
  useEffect(() => {
    if (type === 'Installment' && startDate && cycleCount > 0) {
      const start = new Date(startDate);
      const calculatedEnd = new Date(start);

      if (cycle === 'Day') {
        calculatedEnd.setDate(start.getDate() + cycleCount);
      } else if (cycle === 'Weekly') {
        calculatedEnd.setDate(start.getDate() + (cycleCount * 7));
      } else if (cycle === 'Monthly') {
        calculatedEnd.setMonth(start.getMonth() + cycleCount);
      }

      setEndDate(calculatedEnd.toISOString().split('T')[0]);
    }
  }, [cycle, cycleCount, startDate, type]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tags = tagsInput.split(',').map(t => t.trim()).filter(t => t !== '');

    const record: LedgerRecord = initialData ? {
      ...initialData,
      userName,
      type,
      startDate,
      endDate: endDate || undefined,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      tags,
      notes: [{ 
        id: `N-E-${Date.now()}`, 
        timestamp: new Date().toLocaleString(), 
        content: `Protocol profile refined via system interface.` 
      }, ...initialData.notes]
    } : {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount: 0,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      startDate,
      endDate: endDate || undefined,
      tags: tags.length > 0 ? tags : ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };

    onSave(record);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        transition={{ duration: 0.5, ease: 'circOut' }}
        className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden border border-white/50 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Protocol' : 'Initialize Ledger'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] mt-1">Financial Data Preservation</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/30 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-5">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Client Profile Name</label>
              <input required type="text" value={userName} onChange={(e) => setUserName(e.target.value)} placeholder="Full Name" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Start Protocol Date</label>
                <input required type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Maturity Date (End)</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Type</label>
                <select value={type} onChange={(e) => setType(e.target.value as PaymentType)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none appearance-none cursor-pointer">
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Initial Tags</label>
                <input type="text" value={tagsInput} onChange={(e) => setTagsInput(e.target.value)} placeholder="VIP, New" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            {type === 'Installment' && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="p-6 rounded-3xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-6">
                <div>
                  <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block mb-3">Cycle Frequency Reminder</label>
                  <div className="flex space-x-2">
                    {['Day', 'Weekly', 'Monthly'].map(c => (
                      <button key={c} type="button" onClick={() => setCycle(c as any)} className={`flex-1 py-2.5 text-[10px] font-bold rounded-xl border transition-all ${cycle === c ? 'bg-[#333] text-white border-[#333] shadow-md' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                        {c}
                      </button>
                    ))}
                  </div>
                </div>

                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">
                    {cycle === 'Day' ? 'Duration (Days)' : cycle === 'Weekly' ? 'Duration (Weeks)' : 'Duration (Months)'}
                  </label>
                  <div className="relative">
                    <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-300" />
                    <input 
                      type="number" 
                      min="1" 
                      value={cycleCount} 
                      onChange={(e) => setCycleCount(Math.max(1, Number(e.target.value)))} 
                      className="w-full bg-white/60 border border-white/30 rounded-2xl pl-10 pr-5 py-3 text-sm focus:outline-none font-jua" 
                    />
                  </div>
                  <p className="text-[9px] text-gray-400 italic px-1">Sets the maturity date and installments automatically.</p>
                </motion.div>
              </motion.div>
            )}
          </div>

          <button type="submit" className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 transition-all">
            {initialData ? 'Update Protocol' : 'Preserve Protocol'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default RecordFormModal;

