import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Info, Calculator, Calendar, Hash } from 'lucide-react';
import { LedgerRecord, PaymentType } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: LedgerRecord) => void;
  initialData?: LedgerRecord;
}

const RecordFormModal: React.FC<Props> = ({ isOpen, onClose, onSave, initialData }) => {
  const [userName, setUserName] = useState('');
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Day' | 'Weekly' | 'Monthly'>('Monthly');
  const [cycleCount, setCycleCount] = useState<number>(1);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState('');
  const [tagsInput, setTagsInput] = useState('');

  // Refs to prevent recursive calculation loops
  const isUpdatingFromDate = useRef(false);
  const isUpdatingFromCount = useRef(false);

  useEffect(() => {
    if (initialData) {
      setUserName(initialData.userName);
      setType(initialData.type);
      setCycle((initialData.paymentCycle as any) || 'Monthly');
      setCycleCount(initialData.cycleCount || 1);
      setStartDate(initialData.startDate);
      setEndDate(initialData.endDate || '');
      setTagsInput(initialData.tags.join(', '));
    } else {
      setUserName('');
      setType('Installment');
      setCycle('Monthly');
      setCycleCount(1);
      setStartDate(new Date().toISOString().split('T')[0]);
      setEndDate('');
      setTagsInput('');
    }
  }, [initialData, isOpen]);

  // Logic: Sync End Date when Cycle Count or Cycle Type changes
  useEffect(() => {
    if (isUpdatingFromDate.current) return;
    // Only auto-calculate End Date if the user is interacting with cycle/count controls
    // and there isn't already a manually typed end date that is currently driving the count.
    if (type === 'Installment' && startDate && cycleCount > 0 && !endDate) {
      isUpdatingFromCount.current = true;
      const start = new Date(startDate);
      const calculatedEnd = new Date(start);

      if (cycle === 'Day') {
        calculatedEnd.setDate(start.getDate() + cycleCount);
      } else if (cycle === 'Weekly') {
        calculatedEnd.setDate(start.getDate() + (cycleCount * 7));
      } else if (cycle === 'Monthly') {
        calculatedEnd.setMonth(start.getMonth() + cycleCount);
      }

      setEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isUpdatingFromCount.current = false; }, 50);
    }
  }, [cycle, cycleCount, startDate, type]);

  // Logic: Sync Cycle Count when End Date is manually changed
  const handleEndDateChange = (newEndDate: string) => {
    setEndDate(newEndDate);
    if (isUpdatingFromCount.current) return;
    if (type === 'Installment' && startDate && newEndDate) {
      isUpdatingFromDate.current = true;
      const start = new Date(startDate);
      const end = new Date(newEndDate);
      const diffMs = end.getTime() - start.getTime();

      if (diffMs > 0) {
        let newCount = 1;
        if (cycle === 'Day') {
          newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
        } else if (cycle === 'Weekly') {
          newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
        } else if (cycle === 'Monthly') {
          newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
          if (end.getDate() > start.getDate()) newCount += 1;
        }
        setCycleCount(Math.max(1, newCount));
      }
      setTimeout(() => { isUpdatingFromDate.current = false; }, 50);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tags = tagsInput.split(',').map(t => t.trim()).filter(t => t !== '');

    const record: LedgerRecord = initialData ? {
      ...initialData,
      userName,
      type,
      startDate,
      endDate: endDate || undefined,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      tags,
      notes: [{ 
        id: `N-E-${Date.now()}`, 
        timestamp: new Date().toLocaleString(), 
        content: `Protocol profile refined via system interface.` 
      }, ...initialData.notes]
    } : {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount: 0,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      startDate,
      endDate: endDate || undefined,
      tags: tags.length > 0 ? tags : ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };

    onSave(record);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        transition={{ duration: 0.5, ease: 'circOut' }}
        className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden border border-white/50 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Protocol' : 'Initialize Ledger'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] mt-1">Financial Data Preservation</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/30 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-5">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Client Profile Name</label>
              <input required type="text" value={userName} onChange={(e) => setUserName(e.target.value)} placeholder="Full Name" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Start Protocol Date</label>
                <input required type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Maturity Date (End)</label>
                <input type="date" value={endDate} onChange={(e) => handleEndDateChange(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Type</label>
                <select value={type} onChange={(e) => setType(e.target.value as PaymentType)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none appearance-none cursor-pointer">
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Initial Tags</label>
                <input type="text" value={tagsInput} onChange={(e) => setTagsInput(e.target.value)} placeholder="VIP, New" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            {type === 'Installment' && (
              <AnimatePresence>
                {/* Automatically hide Cycle Frequency Reminder if End Date is filled */}
                {!endDate && (
                  <motion.div 
                    initial={{ opacity: 0, height: 0 }} 
                    animate={{ opacity: 1, height: 'auto' }} 
                    exit={{ opacity: 0, height: 0 }}
                    className="p-6 rounded-3xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-6 overflow-hidden"
                  >
                    <div>
                      <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block mb-3">Cycle Frequency Reminder</label>
                      <div className="flex space-x-2">
                        {['Day', 'Weekly', 'Monthly'].map(c => (
                          <button key={c} type="button" onClick={() => setCycle(c as any)} className={`flex-1 py-2.5 text-[10px] font-bold rounded-xl border transition-all ${cycle === c ? 'bg-[#333] text-white border-[#333] shadow-md' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                            {c}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">
                        {cycle === 'Day' ? 'Duration (Days)' : cycle === 'Weekly' ? 'Duration (Weeks)' : 'Duration (Months)'}
                      </label>
                      <div className="relative">
                        <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-300" />
                        <input 
                          type="number" 
                          min="1" 
                          value={cycleCount} 
                          onChange={(e) => setCycleCount(Math.max(1, Number(e.target.value)))} 
                          className="w-full bg-white/60 border border-white/30 rounded-2xl pl-10 pr-5 py-3 text-sm focus:outline-none font-jua" 
                        />
                      </div>
                      <p className="text-[9px] text-gray-400 italic px-1">Determines Maturity Date automatically based on count.</p>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            )}

            {/* Show a summary if frequency is derived from End Date */}
            {type === 'Installment' && endDate && (
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="px-6 py-4 rounded-3xl bg-white/30 border border-white/30 flex justify-between items-center">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Calculated Cycle</span>
                <span className="text-[11px] font-jua text-[#B8A17D] uppercase">{cycleCount} {cycle}{cycleCount > 1 ? 's' : ''} <span className="text-[9px] font-normal opacity-50 ml-1">(Derived from dates)</span></span>
              </motion.div>
            )}
          </div>

          <button type="submit" className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 transition-all">
            {initialData ? 'Update Protocol' : 'Preserve Protocol'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default RecordFormModal;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Tag as TagIcon,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp,
  AlertTriangle,
  RefreshCw,
  Hash
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddTag: (tag: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
  onUpdateCycle?: (cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddTag, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType,
  onUpdateCycle
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);

  // Confirmation/Edit states
  const [showTypeConfirm, setShowTypeConfirm] = useState(false);
  const [showCycleEdit, setShowCycleEdit] = useState(false);

  // Temporary states for Cycle editing
  const [tempCycle, setTempCycle] = useState<'Day' | 'Weekly' | 'Monthly'>(record.paymentCycle || 'Monthly');
  const [tempCount, setTempCount] = useState(record.cycleCount || 1);
  const [tempEndDate, setTempEndDate] = useState(record.endDate || '');

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const isSyncing = useRef(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Detail View: Sync tempEndDate and tempCount
  useEffect(() => {
    if (!showCycleEdit || isSyncing.current) return;

    // Only auto-calculate tempEndDate if it's currently empty (manual mode)
    if (!tempEndDate) {
      isSyncing.current = true;
      const start = new Date(record.startDate);
      const calculatedEnd = new Date(start);

      if (tempCycle === 'Day') calculatedEnd.setDate(start.getDate() + tempCount);
      else if (tempCycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (tempCount * 7));
      else if (tempCycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + tempCount);

      setTempEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isSyncing.current = false; }, 50);
    }
  }, [tempCycle, tempCount, showCycleEdit, record.startDate, tempEndDate]);

  const handleTempEndDateChange = (val: string) => {
    setTempEndDate(val);
    if (isSyncing.current) return;

    isSyncing.current = true;
    const start = new Date(record.startDate);
    const end = new Date(val);
    const diffMs = end.getTime() - start.getTime();

    if (diffMs > 0) {
      let newCount = 1;
      if (tempCycle === 'Day') newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
      else if (tempCycle === 'Weekly') newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
      else if (tempCycle === 'Monthly') {
        newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) newCount += 1;
      }
      setTempCount(Math.max(1, newCount));
    }
    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  // Advanced Installment Calculation & Pinned Reminders
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];

    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';

    if (!record.cycleCount && record.endDate) {
      const end = new Date(record.endDate);
      const diffMs = end.getTime() - start.getTime();
      if (record.paymentCycle === 'Day') totalPeriods = Math.ceil(diffMs / (24 * 60 * 60 * 1000)) || 1;
      else if (record.paymentCycle === 'Weekly') totalPeriods = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000)) || 1;
      else if (record.paymentCycle === 'Monthly') {
        totalPeriods = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) totalPeriods += 1;
        totalPeriods = Math.max(1, totalPeriods);
      }
    }

    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;

    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due per cycle. Outstanding Balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => {
    return [...pinnedReminders, ...record.notes];
  }, [pinnedReminders, record.notes]);

  const displayedTimeline = useMemo(() => {
    if (isTimelineExpanded) return timelineNotes;
    return timelineNotes.slice(0, 10);
  }, [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("File size exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({
        id: `A-E-${Date.now()}`,
        name: `General Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const confirmTypeChange = () => {
    const nextType = record.type === 'Installment' ? 'Delayed' : 'Installment';
    onUpdateType(nextType);
    setShowTypeConfirm(false);
  };

  const saveCycleEdit = () => {
    onUpdateCycle?.(tempCycle, tempCount);
    setShowCycleEdit(false);
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>

              <div className="flex items-center space-x-2">
                <button 
                  onClick={() => setShowTypeConfirm(true)} 
                  className="bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:bg-white/60 transition-all flex items-center shadow-sm"
                >
                  {record.type} <RefreshCw className="w-2 h-2 ml-1.5 opacity-40" />
                </button>

                {record.type === 'Installment' && (
                  <button 
                    onClick={() => setShowCycleEdit(true)}
                    className="bg-[#333] text-[#B8A17D] px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest hover:bg-black transition-all flex items-center shadow-sm"
                  >
                    Cycle: {record.paymentCycle} ({record.cycleCount}) <Edit2 className="w-2 h-2 ml-1.5 opacity-60" />
                  </button>
                )}
              </div>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white' : 
                record.status === 'Settled' ? 'bg-[#333] text-white' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                <Edit2 className="w-4.5 h-4.5" />
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> End: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999] shadow-[0_0_8px_rgba(184,161,125,0.4)]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Paid</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Balance</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline-overlay" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><TagIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Tags</h4>
                  <div className="flex flex-wrap gap-3">
                    {record.tags.map(tag => <span key={tag} className="px-5 py-2 rounded-xl bg-white/40 border border-[#B8A17D]/30 text-[10px] font-bold text-[#B8A17D] tracking-widest uppercase">{tag}</span>)}
                    {!isAddingTag ? (
                      <button 
                        onClick={() => setIsAddingTag(true)}
                        className="px-5 py-2 rounded-xl border border-dashed border-gray-300 text-[10px] font-bold text-gray-400 hover:border-[#B8A17D]/40 hover:text-[#B8A17D] transition-all"
                      >
                        + Add Tag
                      </button>
                    ) : (
                      <form onSubmit={(e) => {
                        e.preventDefault();
                        if (tagInput.trim()) {
                          onAddTag(tagInput.trim());
                          setTagInput('');
                          setIsAddingTag(false);
                        }
                      }} className="flex items-center space-x-2">
                        <input autoFocus type="text" value={tagInput} onChange={(e) => setTagInput(e.target.value)} className="bg-white/40 border border-white/60 rounded-lg px-3 py-1 text-[10px] focus:outline-none" placeholder="Tag..." />
                        <button type="submit" className="p-1 text-[#B8A17D]"><Plus className="w-3.5 h-3.5"/></button>
                      </form>
                    )}
                  </div>
                </div>
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    <button onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>
                  </h4>
                  {isAddingEvidence && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4 shadow-sm">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, setEvidenceImage)} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black transition-colors">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {record.attachments.map(att => (
                      <div key={att.id} onClick={() => setSelectedAttachment(att)} className="bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                      </div>
                    ))}
                    {record.attachments.length === 0 && !isAddingEvidence && <div className="col-span-2 text-center py-8 opacity-20 border border-dashed border-gray-300 rounded-2xl"><p className="text-[9px] uppercase tracking-widest font-bold">No evidence archived</p></div>}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>
                        {note.isPinned ? 'Protocol Reminders' : note.timestamp}
                      </p>
                      <p className={`text-[14px] leading-relaxed font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>
                        {note.content}
                      </p>
                    </div>
                  ))}
                </div>
                {timelineNotes.length > 10 && (
                  <button 
                    onClick={() => setIsTimelineExpanded(!isTimelineExpanded)}
                    className="flex items-center justify-center space-x-2 w-full py-4 mt-4 bg-white/30 border border-white/40 rounded-2xl text-[10px] font-bold uppercase tracking-[0.2em] text-[#B8A17D] hover:bg-white/50 transition-all shadow-sm"
                  >
                    <span>{isTimelineExpanded ? 'Show Less Protocol Data' : `Expand Full Protocol History (${timelineNotes.length - 10} more)`}</span>
                    {isTimelineExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                  </button>
                )}
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={() => setIsAddingItemModalOpen(true)}
                className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow"
              >
                <ShoppingBag className="w-5 h-5" />
                <span>Declare New Asset Entry</span>
              </motion.button>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {record.items.map(item => (
                  <div key={item.id} onClick={() => setSelectedItem(item)} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 shadow-sm group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
                {record.items.length === 0 && (
                  <div className="col-span-2 text-center py-20 opacity-20 flex flex-col items-center">
                    <ShoppingBag className="w-16 h-16 mb-4" />
                    <p className="text-sm font-bold uppercase tracking-widest">No assets archived for this profile.</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-3xl mx-auto space-y-8">
              <motion.button 
                whileHover={{ brightness: 1.05 }} whileTap={{ scale: 0.98 }}
                onClick={onPayment} disabled={record.status === 'Settled'}
                className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] shadow-[0_10px_30px_-5px_rgba(0,0,0,0.2)] gold-glow'}`}
              >
                <CreditCard className="w-5 h-5" />
                <span>{record.status === 'Settled' ? 'Full Settlement Achieved' : 'Execute Capital Injection'}</span>
              </motion.button>

              <div className="space-y-6">
                {record.payments.map(payment => (
                  <div key={payment.id} onClick={() => setSelectedPayment(payment)} className="flex items-start space-x-8 p-8 rounded-[36px] bg-white/30 border border-white/40 hover:bg-white/40 cursor-pointer group shadow-sm transition-all">
                    <div className="p-5 rounded-2xl bg-[#333] shadow-lg group-hover:bg-black transition-colors"><CreditCard className="w-7 h-7 text-[#B8A17D]" /></div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-lg font-bold text-[#333] tracking-tight">{payment.method} Protocol</span>
                        <span className="text-2xl font-jua text-green-600/80 tracking-tighter">+ RM{payment.amount.toLocaleString()}</span>
                      </div>
                      <div className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{payment.date}</div>
                    </div>
                  </div>
                ))}
                {record.payments.length === 0 && <div className="text-center py-20 opacity-20 flex flex-col items-center"><History className="w-16 h-16 mb-4" /><p className="text-sm font-bold uppercase tracking-widest">No Protocol History</p></div>}
              </div>
            </div>
          )}
        </div>

        {/* Confirmation Overlays */}
        <AnimatePresence>
          {showTypeConfirm && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 z-[140] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
              <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="glass-card max-w-sm w-full p-10 rounded-[40px] shadow-2xl space-y-6 bg-white/90">
                <div className="flex flex-col items-center text-center space-y-4">
                  <div className="p-4 bg-orange-100 rounded-full text-orange-600"><AlertTriangle className="w-10 h-10" /></div>
                  <h3 className="text-2xl font-jua text-[#333]">Protocol Shift</h3>
                  <p className="text-sm text-gray-500 leading-relaxed">You are about to switch this account to <b>{record.type === 'Installment' ? 'Delayed' : 'Installment'}</b>. This may alter automatic calculation schedules. Confirm shifting protocol?</p>
                </div>
                <div className="flex flex-col gap-3">
                  <button onClick={confirmTypeChange} className="w-full bg-[#333] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-widest hover:bg-black">Confirm Shift</button>
                  <button onClick={() => setShowTypeConfirm(false)} className="w-full py-4 text-xs font-bold text-gray-400 uppercase tracking-widest">Cancel</button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {showCycleEdit && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 z-[140] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
              <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="glass-card max-w-sm w-full p-10 rounded-[40px] shadow-2xl space-y-6 bg-white/90">
                <div className="flex flex-col space-y-4">
                  <h3 className="text-2xl font-jua text-[#333] text-center">Protocol Cycle Refinement</h3>
                  <div className="space-y-4">
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Maturity Date (End)</label>
                      <input type="date" value={tempEndDate} onChange={(e) => handleTempEndDateChange(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-xl px-4 py-3 text-sm focus:outline-none" />
                    </div>

                    <AnimatePresence>
                      {!tempEndDate && (
                        <motion.div 
                          initial={{ opacity: 0, height: 0 }} 
                          animate={{ opacity: 1, height: 'auto' }} 
                          exit={{ opacity: 0, height: 0 }}
                          className="space-y-4 overflow-hidden"
                        >
                          <div>
                            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2">Cycle Frequency</label>
                            <div className="flex space-x-1.5">
                              {['Day', 'Weekly', 'Monthly'].map(c => (
                                <button key={c} onClick={() => setTempCycle(c as any)} className={`flex-1 py-2 text-[10px] font-bold rounded-xl border transition-all ${tempCycle === c ? 'bg-[#333] text-white' : 'bg-white/50 text-gray-400'}`}>{c}</button>
                              ))}
                            </div>
                          </div>
                          <div>
                            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2">Duration (Count)</label>
                            <div className="relative">
                              <Hash className="absolute left-3.5 top-1/2 -translate-y-1/2 w-3 h-3 text-gray-300" />
                              <input type="number" min="1" value={tempCount} onChange={(e) => setTempCount(Math.max(1, Number(e.target.value)))} className="w-full bg-white/50 border border-white/60 rounded-xl pl-8 pr-4 py-3 text-sm focus:outline-none font-jua" />
                            </div>
                          </div>
                        </motion.div>
                      )}
                    </AnimatePresence>

                    {tempEndDate && (
                      <div className="px-4 py-3 rounded-2xl bg-white/30 border border-white/40 flex justify-between items-center">
                        <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Calculated Count</span>
                        <span className="text-[10px] font-jua text-[#B8A17D]">{tempCount} {tempCycle}s</span>
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex flex-col gap-3">
                  <button onClick={saveCycleEdit} className="w-full bg-[#B8A17D] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-widest">Update Schedule</button>
                  <button onClick={() => setShowCycleEdit(false)} className="w-full py-4 text-xs font-bold text-gray-400 uppercase tracking-widest">Cancel</button>
                </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Action Footer refined */}
        <div className="p-8 px-12 border-t border-white/40 flex justify-center bg-white/20">
        </div>
      </motion.div>

      {/* Add Item Modal */}
      <AnimatePresence>
        {isAddingItemModalOpen && (
          <AddItemModal 
            isOpen={isAddingItemModalOpen} 
            onClose={() => setIsAddingItemModalOpen(false)} 
            onSubmit={(item) => {
              onAddItem(item);
              setIsAddingItemModalOpen(false);
            }} 
          />
        )}
      </AnimatePresence>

      {/* Overlays for detailed view */}
      <AnimatePresence>
        {selectedItem && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedItem(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Asset Insight</h3><button onClick={() => setSelectedItem(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedItem.attachment?.data && <img src={selectedItem.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-lg font-bold">{selectedItem.name}</p>
                <p className="text-2xl font-jua text-[#B8A17D]">RM{selectedItem.amount.toLocaleString()}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedItem.note || 'No memo available.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedPayment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedPayment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-md w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center pb-4 border-b border-[#B8A17D]/20"><h3 className="text-2xl font-jua text-[#333]">Audit Confirmation</h3><button onClick={() => setSelectedPayment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedPayment.attachment?.data && <img src={selectedPayment.attachment.data} className="w-full h-48 object-cover rounded-2xl" />}
              <div className="space-y-4">
                <p className="text-3xl font-jua text-green-600/80">RM{selectedPayment.amount.toLocaleString()}</p>
                <p className="text-sm font-bold text-gray-700">{selectedPayment.method} Protocol Executed {selectedPayment.date}</p>
                <p className="text-sm italic text-gray-500 leading-relaxed bg-white/20 p-4 rounded-2xl">{selectedPayment.note || 'Reference memo absent.'}</p>
              </div>
            </motion.div>
          </motion.div>
        )}
        {selectedAttachment && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[130] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" onClick={() => setSelectedAttachment(null)}>
            <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-2xl w-full p-10 rounded-[40px] shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center"><h3 className="text-2xl font-jua text-[#333]">Secure Artifact</h3><button onClick={() => setSelectedAttachment(null)}><X className="w-5 h-5 text-gray-400"/></button></div>
              {selectedAttachment.data && <img src={selectedAttachment.data} className="w-full max-h-[60vh] object-contain rounded-2xl shadow-inner bg-black/5" />}
              {selectedAttachment.description && <div className="bg-white/30 p-6 rounded-3xl border border-white/40"><p className="text-[10px] text-gray-400 uppercase font-bold mb-2">Evidence Annotation</p><p className="text-sm text-gray-700 italic leading-relaxed">{selectedAttachment.description}</p></div>}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default CustomerDetail;

export type PaymentType = 'Installment' | 'Delayed';
export type PaymentMethod = 'Cash' | 'BANK' | 'E-Wallet';

export interface PurchaseItem {
  id: string;
  name: string;
  amount: number;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface PaymentRecord {
  id: string;
  amount: number;
  method: PaymentMethod;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface SystemNote {
  id: string;
  timestamp: string;
  content: string;
  isPinned?: boolean;
}

export interface Attachment {
  id: string;
  name: string;
  data: string; // Base64 or URL
  type: 'image' | 'document';
  description?: string;
  fileSize?: number;
}

export interface LedgerRecord {
  id: string; // Format: JayTINxxxxxx (6 random alphanumeric characters)
  userName: string;
  type: PaymentType;
  totalAmount: number; // Derived from sum of items
  paidAmount: number;
  paymentCycle?: 'Day' | 'Weekly' | 'Monthly';
  cycleCount?: number; // Number of periods (e.g., 4 weeks, 10 days)
  startDate: string;
  endDate?: string;
  nextPaymentDate?: string;
  tags: string[];
  items: PurchaseItem[];
  payments: PaymentRecord[];
  notes: SystemNote[];
  attachments: Attachment[]; // General evidence collection
  status: 'Active' | 'Settled' | 'Overdue';
}

export interface DashboardStats {
  totalOutstanding: number;
  activeCustomers: number;
  collectedThisMonth: number;
}

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  // Initial Seed Data
  useEffect(() => {
    const mockData: LedgerRecord[] = [
      {
        id: 'JayTINd4Za2C',
        userName: 'Alexander Vanderbilt',
        type: 'Installment',
        totalAmount: 2400,
        paidAmount: 600,
        paymentCycle: 'Weekly',
        cycleCount: 4,
        startDate: '2024-01-01',
        endDate: '2024-01-31', 
        tags: ['Old Customer', 'VVIP'],
        items: [
          { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
        ],
        payments: [
          { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Week 1 Installment' }
        ],
        notes: [
          { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
        ],
        attachments: [],
        status: 'Active'
      }
    ];
    setRecords(mockData);
  }, []);

  // Automatic Status Monitor
  useEffect(() => {
    const now = new Date();
    setRecords(prev => prev.map(r => {
      let newStatus = r.status;

      // Auto Settle
      if (r.paidAmount >= r.totalAmount && r.totalAmount > 0) {
        newStatus = 'Settled';
      } else if (r.endDate) {
        // Auto Overdue check if past end date and not paid off
        const end = new Date(r.endDate);
        if (now > end && r.paidAmount < r.totalAmount) {
          newStatus = 'Overdue';
        } else if (now <= end && r.paidAmount < r.totalAmount && r.status === 'Overdue') {
          // Revert to active if date is extended or payments made (logic fallback)
          newStatus = 'Active';
        }
      }

      return newStatus !== r.status ? { ...r, status: newStatus } : r;
    }));
  }, [records.map(r => r.paidAmount + r.totalAmount + r.endDate).join(',')]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Capital Injection of RM${payment.amount.toLocaleString()} archived via ${payment.method}. Balance remaining: RM${(r.totalAmount - newPaid).toLocaleString()}.`
        };
        const newPayments = [...r.payments, { ...payment, id: `P-${Date.now()}` }];

        return {
          ...r,
          paidAmount: newPaid,
          payments: newPayments,
          notes: [newNote, ...r.notes]
        };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return {
          ...r,
          items: newItems,
          totalAmount: newTotal
        };
      }
      return r;
    }));
  };

  const handleAddTag = (recordId: string, tag: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId && !r.tags.includes(tag)) {
        return { ...r, tags: [...r.tags, tag] };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-T-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol type shifted to: ${type}.`
        };
        return { ...r, type, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const start = new Date(r.startDate);
        const calculatedEnd = new Date(start);
        if (cycle === 'Day') calculatedEnd.setDate(start.getDate() + count);
        else if (cycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (count * 7));
        else if (cycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + count);

        const newNote = {
          id: `N-C-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol cycle refined: ${cycle} (${count} periods). Maturity reset to ${calculatedEnd.toLocaleDateString()}.`
        };

        return { 
          ...r, 
          paymentCycle: cycle, 
          cycleCount: count, 
          endDate: calculatedEnd.toISOString().split('T')[0],
          notes: [newNote, ...r.notes] 
        };
      }
      return r;
    }));
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      {/* Header */}
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN <span className="text-xs font-normal align-top bg-[#999] text-white px-2 py-0.5 rounded-full">PVT</span></h1>
          <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Private Balance Management System</p>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Records..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ brightness: 1.05 }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Record</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
          <div className="flex items-center space-x-6">
            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
              <div className="flex space-x-1.5">
                {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setStatusFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      statusFilter === filter 
                        ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Type:</span>
              <div className="flex space-x-1.5">
                {['All', 'Installment', 'Delayed'].map((filter) => (
                  <button
                    key={filter}
                    onClick={() => setTypeFilter(filter as any)}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                      typeFilter === filter 
                        ? 'bg-[#333] text-white border-[#333]' 
                        : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                    }`}
                  >
                    {filter}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Showing {filteredRecords.length} records
          </div>
        </div>

        <div className="w-full">
          <CustomerList 
            records={filteredRecords} 
            onSelect={setSelectedRecordId} 
            selectedId={selectedRecordId}
          />
        </div>
      </main>

      {/* Full Page Detail Overlay */}
      <AnimatePresence>
        {selectedRecordId && selectedRecord && (
          <CustomerDetail 
            record={selectedRecord} 
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(selectedRecord.id, item)}
            onAddTag={(tag) => handleAddTag(selectedRecord.id, tag)}
            onAddAttachment={(att) => handleAddAttachment(selectedRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(selectedRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(selectedRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(selectedRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      {/* Modals */}
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={selectedRecord} />
      {selectedRecord && (
        <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(selectedRecord.id, p)} maxAmount={selectedRecord.totalAmount - selectedRecord.paidAmount} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Info, Calculator, Calendar, Hash } from 'lucide-react';
import { LedgerRecord, PaymentType } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: LedgerRecord) => void;
  initialData?: LedgerRecord;
}

const generateJayTINId = () => {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let result = 'JayTIN';
  for (let i = 0; i < 6; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
};

const RecordFormModal: React.FC<Props> = ({ isOpen, onClose, onSave, initialData }) => {
  const [userName, setUserName] = useState('');
  const [type, setType] = useState<PaymentType>('Installment');
  const [cycle, setCycle] = useState<'Day' | 'Weekly' | 'Monthly'>('Monthly');
  const [cycleCount, setCycleCount] = useState<number>(1);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState('');
  const [tagsInput, setTagsInput] = useState('');

  // Refs to prevent recursive calculation loops
  const isUpdatingFromDate = useRef(false);
  const isUpdatingFromCount = useRef(false);

  useEffect(() => {
    if (initialData) {
      setUserName(initialData.userName);
      setType(initialData.type);
      setCycle((initialData.paymentCycle as any) || 'Monthly');
      setCycleCount(initialData.cycleCount || 1);
      setStartDate(initialData.startDate);
      setEndDate(initialData.endDate || '');
      setTagsInput(initialData.tags.join(', '));
    } else {
      setUserName('');
      setType('Installment');
      setCycle('Monthly');
      setCycleCount(1);
      setStartDate(new Date().toISOString().split('T')[0]);
      setEndDate('');
      setTagsInput('');
    }
  }, [initialData, isOpen]);

  // Logic: Sync End Date when Cycle Count or Cycle Type changes
  useEffect(() => {
    if (isUpdatingFromDate.current) return;
    // Only auto-calculate End Date if the user is interacting with cycle/count controls
    // and there isn't already a manually typed end date that is currently driving the count.
    if (type === 'Installment' && startDate && cycleCount > 0 && !endDate) {
      isUpdatingFromCount.current = true;
      const start = new Date(startDate);
      const calculatedEnd = new Date(start);

      if (cycle === 'Day') {
        calculatedEnd.setDate(start.getDate() + cycleCount);
      } else if (cycle === 'Weekly') {
        calculatedEnd.setDate(start.getDate() + (cycleCount * 7));
      } else if (cycle === 'Monthly') {
        calculatedEnd.setMonth(start.getMonth() + cycleCount);
      }

      setEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isUpdatingFromCount.current = false; }, 50);
    }
  }, [cycle, cycleCount, startDate, type]);

  // Logic: Sync Cycle Count when End Date is manually changed
  const handleEndDateChange = (newEndDate: string) => {
    setEndDate(newEndDate);
    if (isUpdatingFromCount.current) return;
    if (type === 'Installment' && startDate && newEndDate) {
      isUpdatingFromDate.current = true;
      const start = new Date(startDate);
      const end = new Date(newEndDate);
      const diffMs = end.getTime() - start.getTime();

      if (diffMs > 0) {
        let newCount = 1;
        if (cycle === 'Day') {
          newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
        } else if (cycle === 'Weekly') {
          newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
        } else if (cycle === 'Monthly') {
          newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
          if (end.getDate() > start.getDate()) newCount += 1;
        }
        setCycleCount(Math.max(1, newCount));
      }
      setTimeout(() => { isUpdatingFromDate.current = false; }, 50);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const tags = tagsInput.split(',').map(t => t.trim()).filter(t => t !== '');

    const record: LedgerRecord = initialData ? {
      ...initialData,
      userName,
      type,
      startDate,
      endDate: endDate || undefined,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      tags,
      notes: [{ 
        id: `N-E-${Date.now()}`, 
        timestamp: new Date().toLocaleString(), 
        content: `Protocol profile refined via system interface.` 
      }, ...initialData.notes]
    } : {
      id: generateJayTINId(),
      userName,
      type,
      totalAmount: 0,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      cycleCount: type === 'Installment' ? cycleCount : undefined,
      startDate,
      endDate: endDate || undefined,
      tags: tags.length > 0 ? tags : ['New Entry'],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };

    onSave(record);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        transition={{ duration: 0.5, ease: 'circOut' }}
        className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden border border-white/50 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Protocol' : 'Initialize Ledger'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] mt-1">Financial Data Preservation</p>
          </div>
          <button onClose={onClose} className="p-2 hover:bg-white/30 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-5">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Client Profile Name</label>
              <input required type="text" value={userName} onChange={(e) => setUserName(e.target.value)} placeholder="Full Name" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Start Protocol Date</label>
                <input required type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Maturity Date (End)</label>
                <input type="date" value={endDate} onChange={(e) => handleEndDateChange(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Type</label>
                <select value={type} onChange={(e) => setType(e.target.value as PaymentType)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none appearance-none cursor-pointer">
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Initial Tags</label>
                <input type="text" value={tagsInput} onChange={(e) => setTagsInput(e.target.value)} placeholder="VIP, New" className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
              </div>
            </div>

            {type === 'Installment' && (
              <AnimatePresence>
                {/* Automatically hide Cycle Frequency Reminder if End Date is filled */}
                {!endDate && (
                  <motion.div 
                    initial={{ opacity: 0, height: 0 }} 
                    animate={{ opacity: 1, height: 'auto' }} 
                    exit={{ opacity: 0, height: 0 }}
                    className="p-6 rounded-3xl bg-[#B8A17D]/5 border border-[#B8A17D]/10 space-y-6 overflow-hidden"
                  >
                    <div>
                      <label className="text-[10px] font-bold text-[#B8A17D] uppercase tracking-wider block mb-3">Cycle Frequency Reminder</label>
                      <div className="flex space-x-2">
                        {['Day', 'Weekly', 'Monthly'].map(c => (
                          <button key={c} type="button" onClick={() => setCycle(c as any)} className={`flex-1 py-2.5 text-[10px] font-bold rounded-xl border transition-all ${cycle === c ? 'bg-[#333] text-white border-[#333] shadow-md' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                            {c}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">
                        {cycle === 'Day' ? 'Duration (Days)' : cycle === 'Weekly' ? 'Duration (Weeks)' : 'Duration (Months)'}
                      </label>
                      <div className="relative">
                        <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-300" />
                        <input 
                          type="number" 
                          min="1" 
                          value={cycleCount} 
                          onChange={(e) => setCycleCount(Math.max(1, Number(e.target.value)))} 
                          className="w-full bg-white/60 border border-white/30 rounded-2xl pl-10 pr-5 py-3 text-sm focus:outline-none font-jua" 
                        />
                      </div>
                      <p className="text-[9px] text-gray-400 italic px-1">Determines Maturity Date automatically based on count.</p>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            )}

            {/* Show a summary if frequency is derived from End Date */}
            {type === 'Installment' && endDate && (
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="px-6 py-4 rounded-3xl bg-white/30 border border-white/30 flex justify-between items-center">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Calculated Cycle</span>
                <span className="text-[11px] font-jua text-[#B8A17D] uppercase">{cycleCount} {cycle}{cycleCount > 1 ? 's' : ''} <span className="text-[9px] font-normal opacity-50 ml-1">(Derived from dates)</span></span>
              </motion.div>
            )}
          </div>

          <button type="submit" className="w-full bg-[#999] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.3em] shadow-xl gold-glow border border-[#B8A17D]/30 hover:brightness-105 transition-all">
            {initialData ? 'Update Protocol' : 'Preserve Protocol'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default RecordFormModal;

export type PaymentType = 'Installment' | 'Delayed';
export type PaymentMethod = 'Cash' | 'BANK' | 'E-Wallet';

export interface PurchaseItem {
  id: string;
  name: string;
  amount: number;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface PaymentRecord {
  id: string;
  amount: number;
  method: PaymentMethod;
  date: string;
  note?: string;
  attachment?: Attachment;
}

export interface SystemNote {
  id: string;
  timestamp: string;
  content: string;
  isPinned?: boolean;
}

export interface Attachment {
  id: string;
  name: string;
  data: string; // Base64 or URL
  type: 'image' | 'document';
  description?: string;
  fileSize?: number;
}

export interface LedgerRecord {
  id: string; // Format: JayTINxxxxxx (6 random alphanumeric characters)
  userName: string;
  type: PaymentType;
  totalAmount: number; // Derived from sum of items
  paidAmount: number;
  paymentCycle?: 'Day' | 'Weekly' | 'Monthly';
  cycleCount?: number; // Number of periods (e.g., 4 weeks, 10 days)
  startDate: string;
  endDate?: string;
  nextPaymentDate?: string;
  items: PurchaseItem[];
  payments: PaymentRecord[];
  notes: SystemNote[];
  attachments: Attachment[]; // General evidence collection
  status: 'Active' | 'Settled' | 'Overdue';
}

export interface DashboardStats {
  totalOutstanding: number;
  activeCustomers: number;
  collectedThisMonth: number;
}

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal,
  LogOut,
  ShieldAlert
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  // Routing state for Guest View
  const [viewModeId, setViewModeId] = useState<string | null>(null);

  // Initial Seed Data / Load from LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const mockData: LedgerRecord[] = [
        {
          id: 'JayTINd4Za2C',
          userName: 'Alexander Vanderbilt',
          type: 'Installment',
          totalAmount: 2400,
          paidAmount: 600,
          paymentCycle: 'Weekly',
          cycleCount: 4,
          startDate: '2024-01-01',
          endDate: '2024-01-31', 
          items: [
            { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
          ],
          payments: [
            { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Week 1 Installment' }
          ],
          notes: [
            { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
          ],
          attachments: [],
          status: 'Active'
        }
      ];
      setRecords(mockData);
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  // Handle Hash Routing for #/view/ID
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };

    window.addEventListener('hashchange', handleHash);
    handleHash(); // Initial check
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Automatic Status Monitor
  useEffect(() => {
    const now = new Date();
    setRecords(prev => prev.map(r => {
      let newStatus = r.status;
      if (r.paidAmount >= r.totalAmount && r.totalAmount > 0) {
        newStatus = 'Settled';
      } else if (r.endDate) {
        const end = new Date(r.endDate);
        if (now > end && r.paidAmount < r.totalAmount) {
          newStatus = 'Overdue';
        } else if (now <= end && r.paidAmount < r.totalAmount && r.status === 'Overdue') {
          newStatus = 'Active';
        }
      }
      return newStatus !== r.status ? { ...r, status: newStatus } : r;
    }));
  }, [records.length]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Capital Injection of RM${payment.amount.toLocaleString()} archived via ${payment.method}. Balance remaining: RM${(r.totalAmount - newPaid).toLocaleString()}.`
        };
        const newPayments = [...r.payments, { ...payment, id: `P-${Date.now()}` }];
        return { ...r, paidAmount: newPaid, payments: newPayments, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-T-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol type shifted to: ${type}.`
        };
        return { ...r, type, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const start = new Date(r.startDate);
        const calculatedEnd = new Date(start);
        if (cycle === 'Day') calculatedEnd.setDate(start.getDate() + count);
        else if (cycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (count * 7));
        else if (cycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + count);
        const newNote = {
          id: `N-C-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol cycle refined: ${cycle} (${count} periods). Maturity reset to ${calculatedEnd.toLocaleDateString()}.`
        };
        return { ...r, paymentCycle: cycle, cycleCount: count, endDate: calculatedEnd.toISOString().split('T')[0], notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  // Exit View Only Mode
  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      {/* Header - Hidden in Guest Mode if user wants total isolation, but kept for "Bank Identity" */}
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN <span className="text-xs font-normal align-top bg-[#999] text-white px-2 py-0.5 rounded-full">PVT</span></h1>
          <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">{viewModeId ? 'Secure Guest Protocol View' : 'Private Balance Management System'}</p>
        </div>

        {!viewModeId && (
          <div className="flex items-center space-x-4">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
              <input 
                type="text" 
                placeholder="Search Records..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
              />
            </div>
            <motion.button 
              whileHover={{ brightness: 1.05 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setIsAddingRecord(true)}
              className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
            >
              <Plus className="w-4 h-4" />
              <span>New Record</span>
            </motion.button>
          </div>
        )}

        {viewModeId && (
          <motion.button 
            whileHover={{ x: -5 }}
            onClick={exitViewMode}
            className="flex items-center space-x-2 text-gray-400 hover:text-[#333] text-xs font-bold uppercase tracking-widest transition-all"
          >
            <LogOut className="w-4 h-4" />
            <span>Terminal Exit</span>
          </motion.button>
        )}
      </header>

      {/* Main Admin UI - Hidden in View Mode */}
      {!viewModeId && (
        <main className="w-full max-w-7xl space-y-8">
          <Dashboard stats={stats} />

          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
            <div className="flex items-center space-x-6">
              <div className="flex items-center space-x-2">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
                <div className="flex space-x-1.5">
                  {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
                    <button
                      key={filter}
                      onClick={() => setStatusFilter(filter as any)}
                      className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                        statusFilter === filter 
                          ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                          : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                      }`}
                    >
                      {filter}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex items-center space-x-2">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Type:</span>
                <div className="flex space-x-1.5">
                  {['All', 'Installment', 'Delayed'].map((filter) => (
                    <button
                      key={filter}
                      onClick={() => setTypeFilter(filter as any)}
                      className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                        typeFilter === filter 
                          ? 'bg-[#333] text-white border-[#333]' 
                          : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                      }`}
                    >
                      {filter}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
              Showing {filteredRecords.length} records
            </div>
          </div>

          <div className="w-full">
            <CustomerList 
              records={filteredRecords} 
              onSelect={setSelectedRecordId} 
              selectedId={selectedRecordId}
            />
          </div>
        </main>
      )}

      {/* View Only Mode Greeting */}
      {viewModeId && !activeRecord && (
        <div className="flex flex-col items-center justify-center py-40 space-y-4">
          <ShieldAlert className="w-16 h-16 text-gray-200" />
          <h2 className="text-xl font-jua text-gray-400">Protocol Link Invalid or Expired</h2>
          <button onClick={exitViewMode} className="text-xs font-bold text-[#B8A17D] uppercase tracking-widest underline underline-offset-4">Return to Master Terminal</button>
        </div>
      )}

      {/* Detail Overlay */}
      <AnimatePresence>
        {(selectedRecordId || viewModeId) && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={!!viewModeId}
            onClose={() => viewModeId ? exitViewMode() : setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(activeRecord.id, item)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      {/* Modals */}
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

