            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(activeRecord.id, item)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      {/* Modals */}
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

