import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Paperclip,
  CheckCircle2,
  Edit2,
  Image as ImageIcon,
  Plus,
  History,
  ShieldCheck,
  ChevronRight,
  Calculator,
  Calendar,
  AlertCircle,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp,
  AlertTriangle,
  RefreshCw,
  Hash,
  Share2,
  Check
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
  onUpdateCycle?: (cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType,
  onUpdateCycle
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);
  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedPayment, setSelectedPayment] = useState<PaymentRecord | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  // Confirmation/Edit states
  const [showTypeConfirm, setShowTypeConfirm] = useState(false);
  const [showCycleEdit, setShowCycleEdit] = useState(false);

  // Temporary states for Cycle editing
  const [tempCycle, setTempCycle] = useState<'Day' | 'Weekly' | 'Monthly'>(record.paymentCycle || 'Monthly');
  const [tempCount, setTempCount] = useState(record.cycleCount || 1);
  const [tempEndDate, setTempEndDate] = useState(record.endDate || '');

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const isSyncing = useRef(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  useEffect(() => {
    if (!showCycleEdit || isSyncing.current) return;
    if (!tempEndDate) {
      isSyncing.current = true;
      const start = new Date(record.startDate);
      const calculatedEnd = new Date(start);
      if (tempCycle === 'Day') calculatedEnd.setDate(start.getDate() + tempCount);
      else if (tempCycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (tempCount * 7));
      else if (tempCycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + tempCount);
      setTempEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isSyncing.current = false; }, 50);
    }
  }, [tempCycle, tempCount, showCycleEdit, record.startDate, tempEndDate]);

  const handleTempEndDateChange = (val: string) => {
    setTempEndDate(val);
    if (isSyncing.current) return;
    isSyncing.current = true;
    const start = new Date(record.startDate);
    const end = new Date(val);
    const diffMs = end.getTime() - start.getTime();
    if (diffMs > 0) {
      let newCount = 1;
      if (tempCycle === 'Day') newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
      else if (tempCycle === 'Weekly') newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
      else if (tempCycle === 'Monthly') {
        newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) newCount += 1;
      }
      setTempCount(Math.max(1, newCount));
    }
    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));
    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due per cycle. Outstanding Balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...record.notes], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => isTimelineExpanded ? timelineNotes : timelineNotes.slice(0, 10), [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file && file.size <= MAX_FILE_SIZE) {
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    } else if (file) setError("File size exceeds 5MB limit.");
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({ id: `A-E-${Date.now()}`, name: `General Evidence Artifact`, data: evidenceImage || '', type: 'image', description: evidenceNote });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareUrl = `${window.location.origin}${window.location.pathname}#/view/${record.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Fix: Added missing confirmTypeChange function
  const confirmTypeChange = () => {
    const nextType: PaymentType = record.type === 'Installment' ? 'Delayed' : 'Installment';
    onUpdateType(nextType);
    setShowTypeConfirm(false);
  };

  // Fix: Added missing saveCycleEdit function
  const saveCycleEdit = () => {
    if (onUpdateCycle) {
      onUpdateCycle(tempCycle, tempCount);
    }
    setShowCycleEdit(false);
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
