import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Info } from 'lucide-react';
import { LedgerRecord, PaymentType, PaymentMethod } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (record: LedgerRecord) => void;
}

const AddRecordModal: React.FC<Props> = ({ isOpen, onClose, onAdd }) => {
  const [step, setStep] = useState(1);
  const [userName, setUserName] = useState('');
  const [totalAmount, setTotalAmount] = useState<number>(0);
  const [type, setType] = useState<PaymentType>('Installment');
  /* Fix: changed 'Weekly' | 'Monthly' | 'Custom' to 'Day' | 'Weekly' | 'Monthly' to match LedgerRecord */
  const [cycle, setCycle] = useState<'Day' | 'Weekly' | 'Monthly'>('Monthly');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Fix: Added missing attachments property to satisfy LedgerRecord interface
    const newRecord: LedgerRecord = {
      id: `JT-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}-${Math.floor(1000 + Math.random() * 9000)}`,
      userName,
      type,
      totalAmount,
      paidAmount: 0,
      paymentCycle: type === 'Installment' ? cycle : undefined,
      startDate: new Date().toISOString().split('T')[0],
      items: [],
      payments: [],
      notes: [
        { 
          id: `N-${Date.now()}`, 
          timestamp: new Date().toLocaleString(), 
          content: 'Record initialized.' 
        }
      ],
      attachments: [],
      status: 'Active'
    };
    onAdd(newRecord);
    setStep(1);
    resetForm();
  };

  const resetForm = () => {
    setUserName('');
    setTotalAmount(0);
    setType('Installment');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-sm"
      />

      <motion.div 
