                >
                  <option value="Installment">Installment</option>
                  <option value="Delayed">Delayed Payment</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Total Valuation</label>
