import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal,
  LogOut,
  ShieldAlert
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  const [viewModeId, setViewModeId] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const mockData: LedgerRecord[] = [
        {
          id: 'JayTINd4Za2C',
          userName: 'Alexander Vanderbilt',
          type: 'Installment',
          totalAmount: 2400,
          paidAmount: 600,
          paymentCycle: 'Weekly',
          cycleCount: 4,
          startDate: '2024-01-01',
          endDate: '2024-01-31', 
          items: [
            { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
          ],
          payments: [
            { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Initial Protocol Injection' }
          ],
          notes: [
            { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
          ],
          attachments: [],
          status: 'Active'
        }
      ];
      setRecords(mockData);
    }
  }, []);

  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // 核心状态协议逻辑：确保状态在还款后精准切换
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        // 未结清状态下的逻辑
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            // 如果没过期且没付完，必须是 Active
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Capital Injection of RM${payment.amount.toLocaleString()} archived. Balance remaining: RM${(r.totalAmount - newPaid).toLocaleString()}.`
        };
        const newPayment = {
          ...payment,
          id: `P-${Date.now()}`
        };
        return { 
          ...r, 
          paidAmount: newPaid, 
          payments: [newPayment, ...r.payments], // 最新的还款放在最前面
          notes: [newNote, ...r.notes] 
        };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-T-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol type shifted to: ${type}.`
        };
        return { ...r, type, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const start = new Date(r.startDate);
        const calculatedEnd = new Date(start);
        if (cycle === 'Day') calculatedEnd.setDate(start.getDate() + count);
        else if (cycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (count * 7));
        else if (cycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + count);
        const newNote = {
          id: `N-C-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol cycle refined: ${cycle} (${count} periods). Maturity reset to ${calculatedEnd.toLocaleDateString()}.`
        };
        return { ...r, paymentCycle: cycle, cycleCount: count, endDate: calculatedEnd.toISOString().split('T')[0], notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          {viewModeId && (
            <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Secure Guest Protocol View</p>
          )}
        </div>

        {!viewModeId && (
          <div className="flex items-center space-x-4">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
              <input 
                type="text" 
                placeholder="Search Records..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
              />
            </div>
            <motion.button 
              whileHover={{ filter: 'brightness(1.05)' }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setIsAddingRecord(true)}
              className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
            >
              <Plus className="w-4 h-4" />
              <span>New Record</span>
            </motion.button>
          </div>
        )}

        {viewModeId && (
          <motion.button 
            whileHover={{ x: -5 }}
            onClick={exitViewMode}
            className="flex items-center space-x-2 text-gray-400 hover:text-[#333] text-xs font-bold uppercase tracking-widest transition-all"
          >
            <LogOut className="w-4 h-4" />
            <span>Terminal Exit</span>
          </motion.button>
        )}
      </header>

      {!viewModeId && (
        <main className="w-full max-w-7xl space-y-8">
          <Dashboard stats={stats} />

          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
            <div className="flex items-center space-x-6">
              <div className="flex items-center space-x-2">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
                <div className="flex space-x-1.5">
                  {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
                    <button
                      key={filter}
                      onClick={() => setStatusFilter(filter as any)}
                      className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                        statusFilter === filter 
                          ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                          : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                      }`}
                    >
                      {filter}
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
              Showing {filteredRecords.length} records
            </div>
          </div>

          <div className="w-full">
            <CustomerList 
              records={filteredRecords} 
              onSelect={setSelectedRecordId} 
              selectedId={selectedRecordId}
            />
          </div>
        </main>
      )}

      <AnimatePresence>
        {(selectedRecordId || viewModeId) && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={!!viewModeId}
            onClose={() => viewModeId ? exitViewMode() : setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(activeRecord.id, item)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

