  }, [records]);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // 核心状态协议：处理还款后的自动恢复与逾期判定
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            // 只要没到期且未付完，无论之前是什么状态（哪怕是逾期手动恢复），都应是 Active
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddPayment = (recordId: string, payment: any) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPaid = r.paidAmount + payment.amount;
        const newNote = {
          id: `N-P-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Capital Injection of RM${payment.amount.toLocaleString()} achieved. Balance remaining: RM${(r.totalAmount - newPaid).toLocaleString()}. Status recalibrated.`
        };
        const newPaymentRecord = {
          ...payment,
          id: `P-${Date.now()}`
        };
        return { 
          ...r, 
          paidAmount: newPaid, 
          payments: [newPaymentRecord, ...r.payments], // 倒序排列，最新还款在最上
          notes: [newNote, ...r.notes] 
        };
      }
      return r;
    }));
    setIsRecordingPayment(false);
  };

  const handleAddItem = (recordId: string, item: PurchaseItem) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = [...r.items, item];
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-T-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol type shifted to: ${type}.`
        };
        return { ...r, type, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const start = new Date(r.startDate);
        const calculatedEnd = new Date(start);
        if (cycle === 'Day') calculatedEnd.setDate(start.getDate() + count);
        else if (cycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (count * 7));
        else if (cycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + count);
        const newNote = {
          id: `N-C-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol cycle refined: ${cycle} (${count} periods). Maturity reset to ${calculatedEnd.toLocaleDateString()}.`
        };
        return { ...r, paymentCycle: cycle, cycleCount: count, endDate: calculatedEnd.toISOString().split('T')[0], notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          {viewModeId && (
            <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Secure Guest Protocol View</p>
          )}
        </div>

        {!viewModeId && (
          <div className="flex items-center space-x-4">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
              <input 
                type="text" 
                placeholder="Search Records..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
              />
            </div>
            <motion.button 
              whileHover={{ filter: 'brightness(1.05)' }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setIsAddingRecord(true)}
              className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
            >
              <Plus className="w-4 h-4" />
              <span>New Record</span>
            </motion.button>
          </div>
        )}

        {viewModeId && (
          <motion.button 
            whileHover={{ x: -5 }}
            onClick={exitViewMode}
            className="flex items-center space-x-2 text-gray-400 hover:text-[#333] text-xs font-bold uppercase tracking-widest transition-all"
          >
            <LogOut className="w-4 h-4" />
            <span>Terminal Exit</span>
          </motion.button>
        )}
      </header>

      {!viewModeId && (
        <main className="w-full max-w-7xl space-y-8">
          <Dashboard stats={stats} />

          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 py-2">
            <div className="flex items-center space-x-6">
              <div className="flex items-center space-x-2">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status:</span>
                <div className="flex space-x-1.5">
                  {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
                    <button
                      key={filter}
                      onClick={() => setStatusFilter(filter as any)}
                      className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all border ${
                        statusFilter === filter 
                          ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                          : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                      }`}
                    >
                      {filter}
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
              Showing {filteredRecords.length} records
            </div>
          </div>

          <div className="w-full">
            <CustomerList 
              records={filteredRecords} 
              onSelect={setSelectedRecordId} 
              selectedId={selectedRecordId}
            />
          </div>
        </main>
      )}

      <AnimatePresence>
        {(selectedRecordId || viewModeId) && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={!!viewModeId}
            onClose={() => viewModeId ? exitViewMode() : setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onAddItem={(item) => handleAddItem(activeRecord.id, item)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp,
  AlertTriangle,
  RefreshCw,
  Hash,
  Share2,
  Check,
  ExternalLink,
  Eye
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
  onUpdateCycle?: (cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType,
  onUpdateCycle
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);
  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const [showTypeConfirm, setShowTypeConfirm] = useState(false);
  const [showCycleEdit, setShowCycleEdit] = useState(false);

  const [tempCycle, setTempCycle] = useState<'Day' | 'Weekly' | 'Monthly'>(record.paymentCycle || 'Monthly');
  const [tempCount, setTempCount] = useState(record.cycleCount || 1);
  const [tempEndDate, setTempEndDate] = useState(record.endDate || '');

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const isSyncing = useRef(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  useEffect(() => {
    if (!showCycleEdit || isSyncing.current) return;
    if (!tempEndDate) {
      isSyncing.current = true;
      const start = new Date(record.startDate);
      const calculatedEnd = new Date(start);
      if (tempCycle === 'Day') calculatedEnd.setDate(start.getDate() + tempCount);
      else if (tempCycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (tempCount * 7));
      else if (tempCycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + tempCount);
      setTempEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isSyncing.current = false; }, 50);
    }
  }, [tempCycle, tempCount, showCycleEdit, record.startDate, tempEndDate]);

  const handleTempEndDateChange = (val: string) => {
    setTempEndDate(val);
    if (isSyncing.current) return;
    isSyncing.current = true;
    const start = new Date(record.startDate);
    const end = new Date(val);
    const diffMs = end.getTime() - start.getTime();
    if (diffMs > 0) {
      let newCount = 1;
      if (tempCycle === 'Day') newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
      else if (tempCycle === 'Weekly') newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
      else if (tempCycle === 'Monthly') {
        newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) newCount += 1;
      }
      setTempCount(Math.max(1, newCount));
    }
    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due per cycle. Outstanding Balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...record.notes], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => isTimelineExpanded ? timelineNotes : timelineNotes.slice(0, 10), [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file && file.size <= MAX_FILE_SIZE) {
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({ id: `A-E-${Date.now()}`, name: `General Evidence Artifact`, data: evidenceImage || '', type: 'image', description: evidenceNote });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareUrl = `${window.location.origin}${window.location.pathname}#/view/${record.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const confirmTypeChange = () => {
    const nextType: PaymentType = record.type === 'Installment' ? 'Delayed' : 'Installment';
    onUpdateType(nextType);
    setShowTypeConfirm(false);
  };

  const saveCycleEdit = () => {
    if (onUpdateCycle) {
      onUpdateCycle(tempCycle, tempCount);
    }
    setShowCycleEdit(false);
  };

  const openArtifactPreview = (attachment: Attachment) => {
    setSelectedAttachment(attachment);
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>

              <div className="flex items-center space-x-2">
                <button 
                  disabled={isViewOnly}
                  onClick={() => setShowTypeConfirm(true)} 
                  className={`bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 flex items-center shadow-sm ${!isViewOnly ? 'hover:bg-white/60 cursor-pointer' : 'cursor-default'}`}
                >
                  {record.type} {!isViewOnly && <RefreshCw className="w-2 h-2 ml-1.5 opacity-40" />}
                </button>

                {record.type === 'Installment' && (
                  <button 
                    disabled={isViewOnly}
                    onClick={() => setShowCycleEdit(true)}
                    className={`bg-[#333] text-[#B8A17D] px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest flex items-center shadow-sm ${!isViewOnly ? 'hover:bg-black cursor-pointer' : 'cursor-default'}`}
                  >
                    Cycle: {record.paymentCycle} ({record.cycleCount}) {!isViewOnly && <Edit2 className="w-2 h-2 ml-1.5 opacity-60" />}
                  </button>
                )}
              </div>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white border-red-400' : 
                record.status === 'Settled' ? 'bg-[#333] text-white border-gray-700' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              {!isViewOnly && (
                <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                  <Edit2 className="w-4.5 h-4.5" />
                </motion.button>
              )}
              <motion.button 
                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                onClick={handleShare}
                className={`p-2.5 bg-white/40 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 ${copied ? 'text-green-600' : 'text-[#B8A17D] hover:bg-white/60'}`}
              >
                {copied ? <Check className="w-4.5 h-4.5" /> : <Share2 className="w-4.5 h-4.5" />}
                <span className="text-[10px] font-bold uppercase tracking-widest pr-1">{copied ? 'Linked' : 'Share'}</span>
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">Protocol ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Maturity: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Fulfillment Scope</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Preserved</p>
