export default CustomerDetail;

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal,
  LogOut,
  ShieldCheck,
  AlertTriangle
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment, PaymentRecord } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  const [viewModeId, setViewModeId] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const mockData: LedgerRecord[] = [
        {
          id: 'JayTINd4Za2C',
          userName: 'Alexander Vanderbilt',
          type: 'Installment',
          totalAmount: 2400,
          paidAmount: 600,
          paymentCycle: 'Weekly',
          cycleCount: 4,
          startDate: '2024-01-01',
          endDate: '2024-01-31', 
          items: [
            { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
          ],
          payments: [
            { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Initial Protocol Injection' }
          ],
          notes: [
            { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
          ],
          attachments: [],
          status: 'Active'
        }
      ];
      setRecords(mockData);
    }
  }, []);

  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // 核心状态协议
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddOrEditPayment = (recordId: string, payment: any, paymentId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newPayments = [...r.payments];
        if (paymentId) {
          // Editing
          newPayments = newPayments.map(p => p.id === paymentId ? { ...p, ...payment } : p);
        } else {
          // New
          newPayments = [{ ...payment, id: `P-${Date.now()}` }, ...newPayments];
        }
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        return { ...r, paidAmount: newPaid, payments: newPayments };
      }
      return r;
    }));
  };

  const handleDeletePayment = (recordId: string, paymentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPayments = r.payments.filter(p => p.id !== paymentId);
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        const newNote = { id: `N-DEL-P-${Date.now()}`, timestamp: new Date().toLocaleString(), content: `Payment record destroyed. Recovery sync initiated.` };
        return { ...r, paidAmount: newPaid, payments: newPayments, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleAddOrEditItem = (recordId: string, item: PurchaseItem, itemId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newItems = [...r.items];
        if (itemId) {
          newItems = newItems.map(i => i.id === itemId ? item : i);
        } else {
          newItems = [...newItems, item];
        }
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleDeleteItem = (recordId: string, itemId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = r.items.filter(i => i.id !== itemId);
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        const newNote = { id: `N-DEL-I-${Date.now()}`, timestamp: new Date().toLocaleString(), content: `Asset record entry purged. Valuation recalibrated.` };
        return { ...r, items: newItems, totalAmount: newTotal, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleDeleteAttachment = (recordId: string, attachmentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: r.attachments.filter(a => a.id !== attachmentId) };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newNote = {
          id: `N-S-${Date.now()}`,
          timestamp: new Date().toLocaleString(),
          content: `Protocol status manually adjusted to: ${status}.`
        };
        return { ...r, status, notes: [newNote, ...r.notes] };
      }
      return r;
    }));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, type };
      }
      return r;
    }));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const start = new Date(r.startDate);
        const calculatedEnd = new Date(start);
        if (cycle === 'Day') calculatedEnd.setDate(start.getDate() + count);
        else if (cycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (count * 7));
        else if (cycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + count);
        return { ...r, paymentCycle: cycle, cycleCount: count, endDate: calculatedEnd.toISOString().split('T')[0] };
      }
      return r;
    }));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          {viewModeId && <p className="text-sm text-gray-500 mt-1 uppercase tracking-widest">Secure Guest Protocol View</p>}
        </div>

        {!viewModeId && (
          <div className="flex items-center space-x-4">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
              <input 
                type="text" 
                placeholder="Search Records..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none focus:ring-1 focus:ring-gray-300 transition-all w-64 shadow-sm"
              />
            </div>
            <motion.button 
              whileHover={{ filter: 'brightness(1.05)' }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setIsAddingRecord(true)}
              className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
            >
              <Plus className="w-4 h-4" />
              <span>New Record</span>
            </motion.button>
          </div>
        )}

        {viewModeId && (
          <motion.button 
            whileHover={{ x: -5 }}
            onClick={exitViewMode}
            className="flex items-center space-x-2 text-gray-400 hover:text-[#333] text-xs font-bold uppercase tracking-widest transition-all"
          >
            <LogOut className="w-4 h-4" />
            <span>Terminal Exit</span>
          </motion.button>
        )}
      </header>

      {!viewModeId && (
        <main className="w-full max-w-7xl space-y-8">
          <Dashboard stats={stats} />
          <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
        </main>
      )}

      <AnimatePresence>
        {(selectedRecordId || viewModeId) && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={!!viewModeId}
            onClose={() => viewModeId ? exitViewMode() : setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onEditPayment={(p) => handleAddOrEditPayment(activeRecord.id, p, p.id)}
            onDeletePayment={(pid) => handleDeletePayment(activeRecord.id, pid)}
            onAddItem={(item) => handleAddOrEditItem(activeRecord.id, item)}
            onEditItem={(item) => handleAddOrEditItem(activeRecord.id, item, item.id)}
            onDeleteItem={(iid) => handleDeleteItem(activeRecord.id, iid)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onDeleteAttachment={(aid) => handleDeleteAttachment(activeRecord.id, aid)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddOrEditPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp,
  AlertTriangle,
  RefreshCw,
  Hash,
  Share2,
  Check,
  ExternalLink,
  Eye,
  Trash2,
  AlertCircle
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onEditPayment: (payment: PaymentRecord) => void;
  onDeletePayment: (id: string) => void;
  onAddItem: (item: PurchaseItem) => void;
  onEditItem: (item: PurchaseItem) => void;
  onDeleteItem: (id: string) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onDeleteAttachment: (id: string) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
  onUpdateCycle?: (cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => void;
}

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onEdit, 
  onPayment, 
  onEditPayment,
  onDeletePayment,
  onAddItem, 
  onEditItem,
  onDeleteItem,
  onAddAttachment,
  onDeleteAttachment,
  onUpdateStatus,
  onUpdateType,
  onUpdateCycle
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [editingItem, setEditingItem] = useState<PurchaseItem | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | null>(null);
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);
  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment', id: string } | null>(null);

  const [showTypeConfirm, setShowTypeConfirm] = useState(false);
  const [showCycleEdit, setShowCycleEdit] = useState(false);

  const [tempCycle, setTempCycle] = useState<'Day' | 'Weekly' | 'Monthly'>(record.paymentCycle || 'Monthly');
  const [tempCount, setTempCount] = useState(record.cycleCount || 1);
  const [tempEndDate, setTempEndDate] = useState(record.endDate || '');

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file && file.size <= 5 * 1024 * 1024) {
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({ id: `A-E-${Date.now()}`, name: `General Evidence Artifact`, data: evidenceImage || '', type: 'image', description: evidenceNote });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareUrl = `${window.location.origin}${window.location.pathname}#/view/${record.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') onDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') onDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      onDeleteAttachment(confirmDelete.id);
      setSelectedAttachment(null);
    }
    setConfirmDelete(null);
  };

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} due per cycle. Outstanding: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Maturity: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...record.notes], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => isTimelineExpanded ? timelineNotes : timelineNotes.slice(0, 10), [timelineNotes, isTimelineExpanded]);

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8">
      <motion.div initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }} className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-2xl">
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all hover:rotate-90 z-10"><X className="w-7 h-7 text-gray-400" /></button>
          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em]">JAYTIN TEAM</span>
              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 ${record.status === 'Overdue' ? 'bg-red-500 text-white' : 'bg-white/60 text-gray-800'}`}>{record.status}</div>
            </div>
            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              <motion.button whileHover={{ scale: 1.05 }} onClick={handleShare} className={`p-2.5 bg-white/40 border border-white/60 rounded-xl flex items-center space-x-2 ${copied ? 'text-green-600' : 'text-[#B8A17D]'}`}>{copied ? <Check className="w-4.5 h-4.5" /> : <Share2 className="w-4.5 h-4.5" />}</motion.button>
            </div>
          </div>
          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1"><span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Fulfillment Scope</span><span className="text-base font-jua">{progress.toFixed(1)}%</span></div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden"><motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" /></div>
            <div className="grid grid-cols-2 gap-4">
              <div><p className="text-[10px] text-gray-400 uppercase font-bold">Preserved</p><p className="text-xl font-jua">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[10px] text-gray-400 uppercase font-bold">Outstanding</p><p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                  <span><ImageIcon className="w-4 h-4 inline mr-2" /> Evidence Artifacts</span>
                  {!isViewOnly && <button onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D]">+ Archive</button>}
                </h4>
                {isAddingEvidence && (
                  <div className="p-6 bg-white/20 border border-[#B8A17D]/30 rounded-3xl space-y-4">
                    <input type="file" ref={evidenceInputRef} className="hidden" onChange={(e) => handleFileChange(e, setEvidenceImage)} />
                    <button onClick={() => evidenceInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-gray-200 rounded-2xl overflow-hidden">{evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 mx-auto opacity-20" />}</button>
                    <textarea placeholder="Memo" value={evidenceNote} onChange={e => setEvidenceNote(e.target.value)} className="w-full bg-white/40 border border-white/20 p-4 rounded-xl text-xs" />
                    <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-3 rounded-xl text-[10px] font-bold uppercase">Archive</button>
                  </div>
                )}
                <div className="grid grid-cols-2 gap-4">
                  {record.attachments.map(att => (
                    <div key={att.id} onClick={() => setSelectedAttachment(att)} className="relative group bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer">
                      <div className="h-24">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 m-auto" />}</div>
                      <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                      {!isViewOnly && <button onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'attachment', id: att.id }); }} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-3 h-3" /></button>}
                    </div>
                  ))}
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em]"><FileEdit className="w-4 h-4 inline mr-2" /> Ledger Timeline</h4>
                <div className="space-y-6 relative border-l-2 border-white/40 pl-8 ml-4">
                  {displayedTimeline.map(note => (
                    <div key={note.id} className="relative">
                      <div className="absolute -left-[45px] top-1.5 w-[32px] h-[32px] rounded-full bg-white border border-[#B8A17D] flex items-center justify-center shadow-sm text-[#B8A17D]">{note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}</div>
                      <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">{note.timestamp}</p>
                      <p className={`text-[13px] p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333] text-white border-[#B8A17D]' : 'bg-white/20 border-white/30 text-gray-700'}`}>{note.content}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              {!isViewOnly && (
                <button onClick={() => setIsAddingItemModalOpen(true)} className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] bg-[#333] text-white border border-[#B8A17D] shadow-xl">+ New Asset Entry</button>
              )}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {record.items.map(item => (
                  <div key={item.id} className="relative group glass-card p-8 rounded-[32px] border border-white/50 shadow-sm">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5"><ShoppingBag className="w-6 h-6 text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold block">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua">RM{item.amount.toLocaleString()}</span>
                    </div>
                    {!isViewOnly && (
                      <div className="absolute bottom-6 right-8 flex space-x-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingItem(item)} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                        <button onClick={() => setConfirmDelete({ type: 'item', id: item.id })} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-4xl mx-auto space-y-8">
              {!isViewOnly && <button onClick={onPayment} disabled={record.status === 'Settled'} className="w-full py-6 rounded-[32px] font-bold text-sm uppercase bg-[#333] text-white border border-[#B8A17D] shadow-xl tracking-[0.4em]">Execute Injection</button>}
              <div className="space-y-8 relative border-l border-[#B8A17D]/20 ml-24 pl-8">
                {record.payments.map(payment => (
                  <div key={payment.id} className="relative group">
