                    <div className="bg-white/40 border border-white/60 p-6 rounded-[28px] hover:bg-white/60 shadow-sm relative">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className="text-[9px] font-bold text-[#B8A17D] uppercase block">{payment.method} Protocol</span>
                          <span className="text-xl font-jua text-green-600/90">Injection: RM{payment.amount.toLocaleString()}</span>
                        </div>
                        <div className="flex space-x-2">
                          {payment.attachment && <button onClick={() => setSelectedAttachment(payment.attachment!)} className="p-2 text-[#B8A17D]"><Eye className="w-4 h-4" /></button>}
                          {!isViewOnly && (
                            <div className="flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => setEditingPayment(payment)} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                              <button onClick={() => setConfirmDelete({ type: 'payment', id: payment.id })} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                            </div>
                          )}
                        </div>
                      </div>
                      {payment.note && <div className="p-3 bg-white/50 rounded-xl mb-4 italic text-[13px] text-gray-600 border border-white/20">{payment.note}</div>}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Global Overlays */}
        <AnimatePresence>
          {confirmDelete && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[200] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
              <motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="glass-card max-w-sm w-full p-10 rounded-[40px] shadow-2xl space-y-6 bg-white/95">
                <div className="flex flex-col items-center text-center space-y-4">
                  <div className="p-4 bg-red-100 rounded-full text-red-600"><AlertTriangle className="w-10 h-10" /></div>
                  <h3 className="text-2xl font-jua text-[#333]">Destroy Record?</h3>
                  <p className="text-sm text-gray-500">This action will purge the artifact from the JayTIN terminal forever. Are you sure?</p>
                </div>
                <div className="flex flex-col gap-3">
                  <button onClick={executeDelete} className="w-full bg-red-500 text-white py-4 rounded-2xl font-bold text-xs uppercase hover:bg-red-600">Execute Destruction</button>
                  <button onClick={() => setConfirmDelete(null)} className="w-full py-4 text-xs font-bold text-gray-400 uppercase">Abort</button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {selectedAttachment && (
