  if (viewModeId && activeRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail 
          record={activeRecord} 
          isViewOnly={true}
          onClose={exitViewMode}
          onEdit={() => {}}
          onPayment={() => {}}
          onEditPayment={() => {}}
          onDeletePayment={() => {}}
          onAddItem={() => {}}
          onEditItem={() => {}}
          onDeleteItem={() => {}}
          onAddAttachment={() => {}}
          onDeleteAttachment={() => {}}
          onUpdateStatus={() => {}}
          onUpdateType={() => {}}
        />
      </div>
    );
