  // Condition 2: Admin Authentication required
  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  // Condition 3: Full Admin Dashboard
  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
