        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />
             <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em]">Master Protocol Active</p>
          </div>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Archives..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ filter: 'brightness(1.05)' }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <motion.button 
            whileHover={{ filter: 'brightness(0.9)', x: 3 }}
            onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
            title="Security Exit"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter}
                onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList 
          records={filteredRecords} 
          onSelect={setSelectedRecordId} 
          selectedId={selectedRecordId}
        />
      </main>

      <AnimatePresence>
        {selectedRecordId && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={false}
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onEditPayment={(p) => handleAddOrEditPayment(activeRecord.id, p, p.id)}
            onDeletePayment={(pid) => handleDeletePayment(activeRecord.id, pid)}
            onAddItem={(item) => handleAddOrEditItem(activeRecord.id, item)}
            onEditItem={(item) => handleAddOrEditItem(activeRecord.id, item, item.id)}
            onDeleteItem={(iid) => handleDeleteItem(activeRecord.id, iid)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onDeleteAttachment={(aid) => handleDeleteAttachment(activeRecord.id, aid)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddOrEditPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

