      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
