import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ShoppingBag, ImageIcon, CheckCircle2, AlertCircle, Calendar } from 'lucide-react';
import { PurchaseItem, Attachment } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (item: PurchaseItem) => void;
  // Added initialData prop to support editing
  initialData?: PurchaseItem;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const AddItemModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData }) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [itemImage, setItemImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Synchronize state with initialData when editing or opening modal
  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setAmount(initialData.amount);
      setDate(initialData.date);
      setNote(initialData.note || '');
      setItemImage(initialData.attachment?.data || null);
    } else {
      resetForm();
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("Asset photo exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setItemImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || amount <= 0) return;

    const item: PurchaseItem = {
      // Preserve ID if editing, otherwise generate a new one
      id: initialData?.id || `I-${Date.now()}`,
      name: name.trim(),
      amount,
      date,
      note
    };

    if (itemImage) {
      item.attachment = {
        // Preserve attachment ID if editing
        id: initialData?.attachment?.id || `A-I-${Date.now()}`,
        name: `Asset Photo: ${name}`,
        data: itemImage,
        type: 'image',
      };
    }

    onSubmit(item);
    resetForm();
  };

  const resetForm = () => {
    setName('');
    setAmount(0);
    setDate(new Date().toISOString().split('T')[0]);
    setNote('');
    setItemImage(null);
    setError(null);
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-lg rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Asset' : 'Declare Asset'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">{initialData ? 'Modification Protocol' : 'New Entry Protocol'}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Asset Nomenclature</label>
            <input required type="text" placeholder="e.g. Rare Watch, Jewelry Set" value={name} onChange={(e) => setName(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none shadow-inner" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Valuation (RM)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-bold">RM</span>
                <input required type="number" value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua shadow-inner" placeholder="0.00" />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Archive Date</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-3.5 h-3.5" />
                <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-10 pr-4 py-4 text-sm focus:outline-none shadow-inner" />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Registry Annotation</label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Describe the asset quality or details..." className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-xs focus:outline-none min-h-[100px] shadow-inner" />
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Visual Evidence</label>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-[#B8A17D]/30 rounded-2xl flex flex-col items-center justify-center text-gray-400 hover:bg-[#B8A17D]/5 transition-all overflow-hidden relative group shadow-inner">
              {itemImage ? (
                <img src={itemImage} className="w-full h-full object-cover" />
              ) : (
                <>
                  <ShoppingBag className="w-6 h-6 mb-1 group-hover:text-[#B8A17D]" />
                  <span className="text-[9px] uppercase font-bold tracking-widest">Attach Asset Photo (Max 5MB)</span>
                </>
              )}
            </button>
            {error && <p className="text-[10px] text-red-400 mt-2 flex items-center"><AlertCircle className="w-3 h-3 mr-1"/> {error}</p>}
          </div>

          <button type="submit" className="w-full bg-[#333] text-white py-5 rounded-[24px] font-bold text-xs uppercase tracking-[0.4em] shadow-xl border border-[#B8A17D] hover:brightness-105 transition-all gold-glow">{initialData ? 'Update Archive' : 'Archive Protocol Asset'}</button>
        </form>
      </motion.div>
    </div>
  );
};

