      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-md rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Injection' : 'Execute Injection'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Capital Transfer Protocol</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Amount</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-bold">RM</span>
                <input required type="number" max={maxAmount} value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua" placeholder="0.00" />
              </div>
            </div>
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Date</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-3.5 h-3.5" />
                <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-10 pr-4 py-4 text-sm focus:outline-none" />
              </div>
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Method</label>
            <div className="grid grid-cols-3 gap-2">
              {['Cash', 'BANK', 'E-Wallet'].map((m) => (
                <button key={m} type="button" onClick={() => setMethod(m as PaymentMethod)} className={`py-3 text-[10px] font-bold rounded-xl border transition-all ${method === m ? 'bg-[#999] text-white border-[#999]' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                  {m}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Protocol Memo</label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Transaction reference or memo..." className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-xs focus:outline-none min-h-[80px]" />
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Proof Artifact</label>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full h-24 border-2 border-dashed border-[#B8A17D]/30 rounded-2xl flex flex-col items-center justify-center text-gray-400 hover:bg-[#B8A17D]/5 transition-all overflow-hidden relative group">
              {proofImage ? (
                <img src={proofImage} className="w-full h-full object-cover" />
              ) : (
                <>
                  <ImageIcon className="w-6 h-6 mb-1 group-hover:text-[#B8A17D]" />
                  <span className="text-[9px] uppercase font-bold">Attach Proof (Max 5MB)</span>
                </>
              )}
            </button>
            {error && <p className="text-[10px] text-red-400 mt-2 flex items-center"><AlertCircle className="w-3 h-3 mr-1"/> {error}</p>}
          </div>

          <button type="submit" className="w-full bg-[#B8A17D] text-white py-5 rounded-[20px] font-bold text-xs uppercase tracking-[0.4em] shadow-lg border border-[#B8A17D] hover:brightness-105 transition-all">{initialData ? 'Update Archive' : 'Archive Injection'}</button>
        </form>
      </motion.div>
    </div>
  );
};

export default PaymentModal;

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal,
  LogOut,
  ShieldCheck,
  AlertTriangle,
  Lock
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment, PaymentRecord } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';
import Login from './components/Login';

const ADMIN_USER = "admin";
const ADMIN_PASS = "jaytin_secure";

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  const [viewModeId, setViewModeId] = useState<string | null>(null);

  // Load records
  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const mockData: LedgerRecord[] = [
        {
          id: 'JayTINd4Za2C',
          userName: 'Alexander Vanderbilt',
          type: 'Installment',
          totalAmount: 2400,
          paidAmount: 600,
          paymentCycle: 'Weekly',
          cycleCount: 4,
          startDate: '2024-01-01',
          endDate: '2024-01-31', 
          items: [
            { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
          ],
          payments: [
            { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Initial Protocol Injection' }
          ],
          notes: [
            { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
          ],
          attachments: [],
          status: 'Active'
        }
      ];
      setRecords(mockData);
    }
  }, []);

  // Save records
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  // Public View detection (Bypass Login)
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Auth Handler
  const handleLogin = (user: string, pass: string) => {
    if (user === ADMIN_USER && pass === ADMIN_PASS) {
      setIsAuthenticated(true);
      localStorage.setItem('jaytin_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
  };

  // Status Protocol logic
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  // Handlers
  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddOrEditPayment = (recordId: string, payment: any, paymentId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newPayments = [...r.payments];
        if (paymentId) {
          newPayments = newPayments.map(p => p.id === paymentId ? { ...p, ...payment } : p);
        } else {
          newPayments = [{ ...payment, id: `P-${Date.now()}` }, ...newPayments];
        }
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        return { ...r, paidAmount: newPaid, payments: newPayments };
      }
      return r;
    }));
  };

  const handleDeletePayment = (recordId: string, paymentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPayments = r.payments.filter(p => p.id !== paymentId);
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        return { ...r, paidAmount: newPaid, payments: newPayments };
      }
      return r;
    }));
  };

  const handleAddOrEditItem = (recordId: string, item: PurchaseItem, itemId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newItems = [...r.items];
        if (itemId) {
          newItems = newItems.map(i => i.id === itemId ? item : i);
        } else {
          newItems = [...newItems, item];
        }
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleDeleteItem = (recordId: string, itemId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = r.items.filter(i => i.id !== itemId);
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleDeleteAttachment = (recordId: string, attachmentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: r.attachments.filter(a => a.id !== attachmentId) };
      }
      return r;
    }));
  };

  // Fixed missing handlers for protocol updates
  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, status } : r));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, type } : r));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, paymentCycle: cycle, cycleCount: count } : r));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  // Condition 1: Shared Public View (Priority)
  if (viewModeId && activeRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail 
          record={activeRecord} 
          isViewOnly={true}
          onClose={exitViewMode}
          onEdit={() => {}}
          onPayment={() => {}}
          onEditPayment={() => {}}
          onDeletePayment={() => {}}
          onAddItem={() => {}}
          onEditItem={() => {}}
          onDeleteItem={() => {}}
          onAddAttachment={() => {}}
          onDeleteAttachment={() => {}}
          onUpdateStatus={() => {}}
          onUpdateType={() => {}}
        />
      </div>
    );
  }

  // Condition 2: Admin Authentication required
  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  // Condition 3: Full Admin Dashboard
  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />
             <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em]">Master Protocol Active</p>
          </div>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Archives..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ filter: 'brightness(1.05)' }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <motion.button 
            whileHover={{ filter: 'brightness(0.9)', x: 3 }}
            onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
            title="Security Exit"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter}
                onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList 
          records={filteredRecords} 
          onSelect={setSelectedRecordId} 
          selectedId={selectedRecordId}
        />
      </main>

      <AnimatePresence>
        {selectedRecordId && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={false}
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onEditPayment={(p) => handleAddOrEditPayment(activeRecord.id, p, p.id)}
            onDeletePayment={(pid) => handleDeletePayment(activeRecord.id, pid)}
            onAddItem={(item) => handleAddOrEditItem(activeRecord.id, item)}
            onEditItem={(item) => handleAddOrEditItem(activeRecord.id, item, item.id)}
            onDeleteItem={(iid) => handleDeleteItem(activeRecord.id, iid)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onDeleteAttachment={(aid) => handleDeleteAttachment(activeRecord.id, aid)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal isOpen={isRecordingPayment} onClose={() => setIsRecordingPayment(false)} onSubmit={(p) => handleAddOrEditPayment(activeRecord.id, p)} maxAmount={activeRecord.totalAmount - activeRecord.paidAmount} />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ShoppingBag, ImageIcon, CheckCircle2, AlertCircle, Calendar } from 'lucide-react';
import { PurchaseItem, Attachment } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (item: PurchaseItem) => void;
  // Added initialData prop to support editing
  initialData?: PurchaseItem;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const AddItemModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData }) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [itemImage, setItemImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  function resetForm() {
    setName('');
    setAmount(0);
    setDate(new Date().toISOString().split('T')[0]);
    setNote('');
    setItemImage(null);
    setError(null);
  }

  // Synchronize state with initialData when editing or opening modal
  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setAmount(initialData.amount);
      setDate(initialData.date);
      setNote(initialData.note || '');
      setItemImage(initialData.attachment?.data || null);
    } else {
      resetForm();
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("Asset photo exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setItemImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || amount <= 0) return;

    const item: PurchaseItem = {
      // Preserve ID if editing, otherwise generate a new one
      id: initialData?.id || `I-${Date.now()}`,
      name: name.trim(),
      amount,
      date,
      note
    };

    if (itemImage) {
      item.attachment = {
        // Preserve attachment ID if editing
        id: initialData?.attachment?.id || `A-I-${Date.now()}`,
        name: `Asset Photo: ${name}`,
        data: itemImage,
        type: 'image',
      };
    }

    onSubmit(item);
    resetForm();
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-lg rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Asset' : 'Declare Asset'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">{initialData ? 'Modification Protocol' : 'New Entry Protocol'}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Asset Nomenclature</label>
            <input required type="text" placeholder="e.g. Rare Watch, Jewelry Set" value={name} onChange={(e) => setName(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none shadow-inner" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Valuation (RM)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-bold">RM</span>
                <input required type="number" value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua shadow-inner" placeholder="0.00" />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Archive Date</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-3.5 h-3.5" />
