export default AddItemModal;

import React, { useState, useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { X, CreditCard, ImageIcon, CheckCircle2, AlertCircle, Calendar } from 'lucide-react';
import { PaymentMethod, Attachment, PaymentRecord } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (payment: any) => void;
  maxAmount: number;
  // Added initialData prop to support editing
  initialData?: PaymentRecord;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const PaymentModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, maxAmount, initialData }) => {
  const [amount, setAmount] = useState<number>(0);
  const [method, setMethod] = useState<PaymentMethod>('BANK');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [proofImage, setProofImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  function resetForm() {
    setAmount(0);
    setMethod('BANK');
    setDate(new Date().toISOString().split('T')[0]);
    setNote('');
    setProofImage(null);
    setError(null);
  }

  // Synchronize state with initialData when editing or opening modal
  useEffect(() => {
    if (initialData) {
      setAmount(initialData.amount);
      setMethod(initialData.method);
      setDate(initialData.date);
      setNote(initialData.note || '');
      setProofImage(initialData.attachment?.data || null);
    } else {
      resetForm();
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("Proof photo exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setProofImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) return;

    const payment: any = {
      amount,
      method,
      date,
      note
    };

    if (proofImage) {
      payment.attachment = {
        // Preserve attachment ID if editing
        id: initialData?.attachment?.id || `A-P-${Date.now()}`,
        name: `Payment Proof: ${amount}`,
        data: proofImage,
        type: 'image',
      };
    }

    onSubmit(payment);
    resetForm();
  };

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-md rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Injection' : 'Execute Injection'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Capital Transfer Protocol</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Amount</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-bold">RM</span>
                <input required type="number" max={maxAmount} value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua" placeholder="0.00" />
              </div>
            </div>
            <div>
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Date</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-3.5 h-3.5" />
                <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-10 pr-4 py-4 text-sm focus:outline-none" />
              </div>
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Method</label>
            <div className="grid grid-cols-3 gap-2">
              {['Cash', 'BANK', 'E-Wallet'].map((m) => (
                <button key={m} type="button" onClick={() => setMethod(m as PaymentMethod)} className={`py-3 text-[10px] font-bold rounded-xl border transition-all ${method === m ? 'bg-[#999] text-white border-[#999]' : 'bg-white/40 border-white/30 text-gray-400'}`}>
                  {m}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Protocol Memo</label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Transaction reference or memo..." className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-xs focus:outline-none min-h-[80px]" />
          </div>

          <div>
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Proof Artifact</label>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full h-24 border-2 border-dashed border-[#B8A17D]/30 rounded-2xl flex flex-col items-center justify-center text-gray-400 hover:bg-[#B8A17D]/5 transition-all overflow-hidden relative group">
              {proofImage ? (
                <img src={proofImage} className="w-full h-full object-cover" />
              ) : (
                <>
                  <ImageIcon className="w-6 h-6 mb-1 group-hover:text-[#B8A17D]" />
                  <span className="text-[9px] uppercase font-bold">Attach Proof (Max 5MB)</span>
                </>
              )}
            </button>
            {error && <p className="text-[10px] text-red-400 mt-2 flex items-center"><AlertCircle className="w-3 h-3 mr-1"/> {error}</p>}
          </div>

          <button type="submit" className="w-full bg-[#B8A17D] text-white py-5 rounded-[20px] font-bold text-xs uppercase tracking-[0.4em] shadow-lg border border-[#B8A17D] hover:brightness-105 transition-all">{initialData ? 'Update Archive' : 'Archive Injection'}</button>
        </form>
      </motion.div>
    </div>
  );
};

export default PaymentModal;

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  Filter,
  SlidersHorizontal,
  LogOut,
  ShieldCheck,
  AlertTriangle,
  Lock
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType, PurchaseItem, Attachment, PaymentRecord } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import PaymentModal from './components/PaymentModal';
import Login from './components/Login';

const ADMIN_USER = "admin";
const ADMIN_PASS = "jaytin_secure";

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isEditingRecord, setIsEditingRecord] = useState(false);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [typeFilter, setTypeFilter] = useState<'All' | PaymentType>('All');

  const [viewModeId, setViewModeId] = useState<string | null>(null);

  // Load records
  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const mockData: LedgerRecord[] = [
        {
          id: 'JayTINd4Za2C',
          userName: 'Alexander Vanderbilt',
          type: 'Installment',
          totalAmount: 2400,
          paidAmount: 600,
          paymentCycle: 'Weekly',
          cycleCount: 4,
          startDate: '2024-01-01',
          endDate: '2024-01-31', 
          items: [
            { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
          ],
          payments: [
            { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Initial Protocol Injection' }
          ],
          notes: [
            { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
          ],
          attachments: [],
          status: 'Active'
        }
      ];
      setRecords(mockData);
    }
  }, []);

  // Save records
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  // Public View detection (Bypass Login)
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Auth Handler
  const handleLogin = (user: string, pass: string) => {
    if (user === ADMIN_USER && pass === ADMIN_PASS) {
      setIsAuthenticated(true);
      localStorage.setItem('jaytin_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
  };

  // Status Protocol logic
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else {
        if (r.endDate) {
          const end = new Date(r.endDate);
          if (now > end) {
            newStatus = 'Overdue';
          } else {
            newStatus = 'Active';
          }
        } else {
          newStatus = 'Active';
        }
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + curr.payments.reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchesType = typeFilter === 'All' || r.type === typeFilter;
    return matchesSearch && matchesStatus && matchesType;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  // Handlers
  const handleUpdateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
    setIsEditingRecord(false);
  };

  const handleAddOrEditPayment = (recordId: string, payment: any, paymentId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newPayments = [...r.payments];
        if (paymentId) {
          newPayments = newPayments.map(p => p.id === paymentId ? { ...p, ...payment } : p);
        } else {
          newPayments = [{ ...payment, id: `P-${Date.now()}` }, ...newPayments];
        }
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        return { ...r, paidAmount: newPaid, payments: newPayments };
      }
      return r;
    }));
  };

  const handleDeletePayment = (recordId: string, paymentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newPayments = r.payments.filter(p => p.id !== paymentId);
        const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
        return { ...r, paidAmount: newPaid, payments: newPayments };
      }
      return r;
    }));
  };

  const handleAddOrEditItem = (recordId: string, item: PurchaseItem, itemId?: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        let newItems = [...r.items];
        if (itemId) {
          newItems = newItems.map(i => i.id === itemId ? item : i);
        } else {
          newItems = [...newItems, item];
        }
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleDeleteItem = (recordId: string, itemId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        const newItems = r.items.filter(i => i.id !== itemId);
        const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
        return { ...r, items: newItems, totalAmount: newTotal };
      }
      return r;
    }));
  };

  const handleAddAttachment = (recordId: string, attachment: Attachment) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: [attachment, ...r.attachments] };
      }
      return r;
    }));
  };

  const handleDeleteAttachment = (recordId: string, attachmentId: string) => {
    setRecords(prev => prev.map(r => {
      if (r.id === recordId) {
        return { ...r, attachments: r.attachments.filter(a => a.id !== attachmentId) };
      }
      return r;
    }));
  };

  const handleUpdateStatus = (recordId: string, status: 'Active' | 'Settled' | 'Overdue') => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, status } : r));
  };

  const handleUpdateType = (recordId: string, type: PaymentType) => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, type } : r));
  };

  const handleUpdateCycle = (recordId: string, cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => {
    setRecords(prev => prev.map(r => r.id === recordId ? { ...r, paymentCycle: cycle, cycleCount: count } : r));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  // Condition 1: Shared Public View (Priority)
  if (viewModeId && activeRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail 
          record={activeRecord} 
          isViewOnly={true}
          onClose={exitViewMode}
          onEdit={() => {}}
          onPayment={() => {}}
          onEditPayment={() => {}}
          onDeletePayment={() => {}}
          onAddItem={() => {}}
          onEditItem={() => {}}
          onDeleteItem={() => {}}
          onAddAttachment={() => {}}
          onDeleteAttachment={() => {}}
          onUpdateStatus={() => {}}
          onUpdateType={() => {}}
        />
      </div>
    );
  }

  // Condition 2: Admin Authentication required
  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  // Condition 3: Full Admin Dashboard
  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />
             <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em]">Master Protocol Active</p>
          </div>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Archives..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ filter: 'brightness(1.05)' }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <motion.button 
            whileHover={{ filter: 'brightness(0.9)', x: 3 }}
            onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
            title="Security Exit"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter}
                onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList 
          records={filteredRecords} 
          onSelect={setSelectedRecordId} 
          selectedId={selectedRecordId}
        />
      </main>

      <AnimatePresence>
        {selectedRecordId && activeRecord && (
          <CustomerDetail 
            record={activeRecord} 
            isViewOnly={false}
            onClose={() => setSelectedRecordId(null)}
            onEdit={() => setIsEditingRecord(true)}
            onPayment={() => setIsRecordingPayment(true)}
            onEditPayment={(p) => { handleAddOrEditPayment(activeRecord.id, p, p.id); }}
            onDeletePayment={(pid) => handleDeletePayment(activeRecord.id, pid)}
            onAddItem={(item) => handleAddOrEditItem(activeRecord.id, item)}
            onEditItem={(item) => handleAddOrEditItem(activeRecord.id, item, item.id)}
            onDeleteItem={(iid) => handleDeleteItem(activeRecord.id, iid)}
            onAddAttachment={(att) => handleAddAttachment(activeRecord.id, att)}
            onDeleteAttachment={(aid) => handleDeleteAttachment(activeRecord.id, aid)}
            onUpdateStatus={(status) => handleUpdateStatus(activeRecord.id, status)}
            onUpdateType={(type) => handleUpdateType(activeRecord.id, type)}
            onUpdateCycle={(cycle, count) => handleUpdateCycle(activeRecord.id, cycle, count)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => { setRecords([newRecord, ...records]); setIsAddingRecord(false); }} />
      {activeRecord && (
        <>
          <RecordFormModal isOpen={isEditingRecord} onClose={() => setIsEditingRecord(false)} onSave={handleUpdateRecord} initialData={activeRecord} />
          <PaymentModal 
            isOpen={isRecordingPayment} 
            onClose={() => setIsRecordingPayment(false)} 
            onSubmit={(p) => { 
              handleAddOrEditPayment(activeRecord.id, p); 
              setIsRecordingPayment(false); 
            }} 
            maxAmount={activeRecord.totalAmount > 0 ? (activeRecord.totalAmount - activeRecord.paidAmount) : 999999999} 
          />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  ChevronDown,
  Pin,
  ChevronUp,
  AlertTriangle,
  RefreshCw,
  Hash,
  Share2,
  Check,
  ExternalLink,
  Eye,
  Trash2
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, PaymentType } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onEdit: () => void;
  onPayment: () => void;
  onAddItem: (item: PurchaseItem) => void;
  onAddAttachment: (attachment: Attachment) => void;
  onUpdateStatus: (status: 'Active' | 'Settled' | 'Overdue') => void;
  onUpdateType: (type: PaymentType) => void;
  onUpdateCycle?: (cycle: 'Day' | 'Weekly' | 'Monthly', count: number) => void;
  onEditPayment: (payment: any) => void;
  onDeletePayment: (paymentId: string) => void;
  onEditItem: (item: PurchaseItem) => void;
  onDeleteItem: (itemId: string) => void;
  onDeleteAttachment: (attachmentId: string) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onEdit, 
  onPayment, 
  onAddItem, 
  onAddAttachment,
  onUpdateStatus,
  onUpdateType,
  onUpdateCycle,
  onEditPayment,
  onDeletePayment,
  onEditItem,
  onDeleteItem,
  onDeleteAttachment
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [editingItem, setEditingItem] = useState<PurchaseItem | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | null>(null);
  const [isAddingItemModalOpen, setIsAddingItemModalOpen] = useState(false);
  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<PurchaseItem | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment', id: string } | null>(null);

  const [showTypeConfirm, setShowTypeConfirm] = useState(false);
  const [showCycleEdit, setShowCycleEdit] = useState(false);

  const [tempCycle, setTempCycle] = useState<'Day' | 'Weekly' | 'Monthly'>(record.paymentCycle || 'Monthly');
  const [tempCount, setTempCount] = useState(record.cycleCount || 1);
  const [tempEndDate, setTempEndDate] = useState(record.endDate || '');

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const isSyncing = useRef(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  useEffect(() => {
    if (!showCycleEdit || isSyncing.current) return;
    if (!tempEndDate) {
      isSyncing.current = true;
      const start = new Date(record.startDate);
      const calculatedEnd = new Date(start);
      if (tempCycle === 'Day') calculatedEnd.setDate(start.getDate() + tempCount);
      else if (tempCycle === 'Weekly') calculatedEnd.setDate(start.getDate() + (tempCount * 7));
      else if (tempCycle === 'Monthly') calculatedEnd.setMonth(start.getMonth() + tempCount);
      setTempEndDate(calculatedEnd.toISOString().split('T')[0]);
      setTimeout(() => { isSyncing.current = false; }, 50);
    }
  }, [tempCycle, tempCount, showCycleEdit, record.startDate, tempEndDate]);

  const handleTempEndDateChange = (val: string) => {
    setTempEndDate(val);
    if (isSyncing.current) return;
    isSyncing.current = true;
    const start = new Date(record.startDate);
    const end = new Date(val);
    const diffMs = end.getTime() - start.getTime();
    if (diffMs > 0) {
      let newCount = 1;
      if (tempCycle === 'Day') newCount = Math.ceil(diffMs / (24 * 60 * 60 * 1000));
      else if (tempCycle === 'Weekly') newCount = Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000));
      else if (tempCycle === 'Monthly') {
        newCount = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
        if (end.getDate() > start.getDate()) newCount += 1;
      }
      setTempCount(Math.max(1, newCount));
    }
    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    if (record.paidAmount < record.totalAmount) {
      return [{
        id: 'reminder-pinned-calc',
        timestamp: nextDate.toDateString(),
        content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due per cycle. Outstanding Balance: RM${(record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline marker: ${nextDate.toLocaleDateString()}.`,
        isPinned: true
      }];
    }
    return [];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...record.notes], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => isTimelineExpanded ? timelineNotes : timelineNotes.slice(0, 10), [timelineNotes, isTimelineExpanded]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string | null) => void) => {
    const file = e.target.files?.[0];
    if (file && file.size <= MAX_FILE_SIZE) {
      const reader = new FileReader();
      reader.onloadend = () => setter(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAddEvidenceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      onAddAttachment({ id: `A-E-${Date.now()}`, name: `General Evidence Artifact`, data: evidenceImage || '', type: 'image', description: evidenceNote });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareUrl = `${window.location.origin}${window.location.pathname}#/view/${record.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const confirmTypeChange = () => {
    const nextType: PaymentType = record.type === 'Installment' ? 'Delayed' : 'Installment';
    onUpdateType(nextType);
    setShowTypeConfirm(false);
  };

  const saveCycleEdit = () => {
    if (onUpdateCycle) {
      onUpdateCycle(tempCycle, tempCount);
    }
    setShowCycleEdit(false);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') onDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') onDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      onDeleteAttachment(confirmDelete.id);
      setSelectedAttachment(null);
    }
    setConfirmDelete(null);
  };

  const openArtifactPreview = (attachment: Attachment) => {
    setSelectedAttachment(attachment);
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-[0_50px_120px_-30px_rgba(0,0,0,0.15)]"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>

              <div className="flex items-center space-x-2">
                <button 
                  disabled={isViewOnly}
                  onClick={() => setShowTypeConfirm(true)} 
                  className={`bg-white/40 border border-[#B8A17D]/30 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest text-gray-600 flex items-center shadow-sm ${!isViewOnly ? 'hover:bg-white/60 cursor-pointer' : 'cursor-default'}`}
                >
                  {record.type} {!isViewOnly && <RefreshCw className="w-2 h-2 ml-1.5 opacity-40" />}
                </button>

                {record.type === 'Installment' && (
                  <button 
                    disabled={isViewOnly}
                    onClick={() => setShowCycleEdit(true)}
                    className={`bg-[#333] text-[#B8A17D] px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest flex items-center shadow-sm ${!isViewOnly ? 'hover:bg-black cursor-pointer' : 'cursor-default'}`}
                  >
                    Cycle: {record.paymentCycle} ({record.cycleCount}) {!isViewOnly && <Edit2 className="w-2 h-2 ml-1.5 opacity-60" />}
                  </button>
                )}
              </div>

              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white border-red-400' : 
                record.status === 'Settled' ? 'bg-[#333] text-white border-gray-700' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              {!isViewOnly && (
                <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={onEdit} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                  <Edit2 className="w-4.5 h-4.5" />
                </motion.button>
              )}
              <motion.button 
                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                onClick={handleShare}
                className={`p-2.5 bg-white/40 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 ${copied ? 'text-green-600' : 'text-[#B8A17D] hover:bg-white/60'}`}
              >
                {copied ? <Check className="w-4.5 h-4.5" /> : <Share2 className="w-4.5 h-4.5" />}
                <span className="text-[10px] font-bold uppercase tracking-widest pr-1">{copied ? 'Linked' : 'Share'}</span>
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">Protocol ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Maturity: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Fulfillment Scope</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Preserved</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Outstanding</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{(record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline-overlay" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    {!isViewOnly && <button onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>}
                  </h4>
                  {isAddingEvidence && !isViewOnly && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4 shadow-sm">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, setEvidenceImage)} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button onClick={handleAddEvidenceSubmit} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {record.attachments.map(att => (
                      <div key={att.id} onClick={() => openArtifactPreview(att)} className="relative group bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                        {!isViewOnly && <button onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'attachment', id: att.id }); }} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-3 h-3" /></button>}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>
                        {note.isPinned ? 'Protocol Reminders' : note.timestamp}
                      </p>
                      <p className={`text-[14px] font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>
                        {note.content}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              {!isViewOnly && (
                <motion.button whileHover={{ filter: 'brightness(1.05)' }} whileTap={{ scale: 0.98 }} onClick={() => setIsAddingItemModalOpen(true)} className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] gold-glow">
                  <ShoppingBag className="w-5 h-5" />
                  <span>Declare New Asset Entry</span>
                </motion.button>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {record.items.map(item => (
                  <div key={item.id} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40 relative">
                    <div onClick={() => setSelectedItem(item)} className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                    {!isViewOnly && (
                      <div className="absolute bottom-6 right-8 flex space-x-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={(e) => { e.stopPropagation(); setEditingItem(item); }} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                        <button onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'item', id: item.id }); }} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-4xl mx-auto space-y-8">
              {!isViewOnly && (
                <motion.button 
                  whileHover={{ filter: 'brightness(1.05)' }} whileTap={{ scale: 0.98 }} 
                  onClick={onPayment} 
                  disabled={record.status === 'Settled'} 
                  className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] gold-glow'}`}
                >
                  <CreditCard className="w-5 h-5" />
                  <span>{record.status === 'Settled' ? 'Full Settlement Achieved' : 'Execute Capital Injection'}</span>
                </motion.button>
              )}

              <div className="space-y-8 relative before:absolute before:left-[47px] before:top-4 before:bottom-0 before:w-[1px] before:bg-[#B8A17D]/20">
                {record.payments.map((payment) => (
                  <div key={payment.id} className="flex items-start space-x-8 relative group">
                    <div className="flex-none w-24 pt-4 text-right">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{payment.date}</span>
                    </div>

                    <div className="flex-none w-[32px] h-[32px] rounded-full border border-[#B8A17D]/40 bg-white flex items-center justify-center relative z-10 shadow-sm transition-transform group-hover:scale-110">
                      <div className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" />
                    </div>

                    <div className="flex-1 bg-white/40 border border-white/60 p-6 rounded-[28px] hover:bg-white/60 transition-all shadow-sm relative">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-widest block mb-1">{payment.method} Protocol</span>
                          <span className="text-xl font-jua text-green-600/90 tracking-tighter">Injection: RM{payment.amount.toLocaleString()}</span>
                        </div>
                        <div className="flex space-x-2 items-center">
                          {payment.attachment && (
                            <button 
                              onClick={() => openArtifactPreview(payment.attachment!)}
                              className="p-2 text-[#B8A17D] hover:bg-white transition-colors rounded-full"
                            >
                              <Eye className="w-4 h-4" />
