                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                    {!isViewOnly && (
                      <div className="absolute bottom-6 right-8 flex space-x-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={(e) => { e.stopPropagation(); setEditingItem(item); }} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                        <button onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'item', id: item.id }); }} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                  </div>
                ))}
                {record.items.length === 0 && (
                  <div className="col-span-full py-20 text-center opacity-30 italic text-gray-400 text-xs">No assets recorded in this protocol.</div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-4xl mx-auto space-y-8">
              {!isViewOnly && (
                <motion.button 
                  whileHover={{ filter: 'brightness(1.05)' }} 
                  whileTap={{ scale: 0.98 }} 
                  onClick={() => setIsRecordingPayment(true)} 
                  disabled={record.status === 'Settled'} 
                  className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] gold-glow'}`}
                >
                  <CreditCard className="w-5 h-5" />
                  <span>Execute Capital Injection</span>
                </motion.button>
              )}

              <div className="space-y-8 relative before:absolute before:left-[47px] before:top-4 before:bottom-0 before:w-[1px] before:bg-[#B8A17D]/20">
                {record.payments.map((payment) => (
                  <div key={payment.id} className="flex items-start space-x-8 relative group">
                    <div className="flex-none w-24 pt-4 text-right">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{payment.date}</span>
                    </div>
                    <div className="flex-none w-[32px] h-[32px] rounded-full border border-[#B8A17D]/40 bg-white flex items-center justify-center relative z-10 shadow-sm transition-transform group-hover:scale-110">
