import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
} from 'lucide-react';
import { LedgerRecord, DashboardStats, PaymentType } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import Login from './components/Login';

const ADMIN_USER = "admin";
const ADMIN_PASS = "jaytin_secure";

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  const [viewModeId, setViewModeId] = useState<string | null>(null);

  // Load records
  useEffect(() => {
    try {
      const saved = localStorage.getItem('jaytin_ledgers');
      if (saved) {
        const parsed = JSON.parse(saved);
        // Data migration/safeguard: ensure arrays exist
        const sanitized = parsed.map((r: any) => ({
          ...r,
          items: r.items || [],
          payments: r.payments || [],
          notes: r.notes || [],
          attachments: r.attachments || []
        }));
        setRecords(sanitized);
      } else {
        const mockData: LedgerRecord[] = [
          {
            id: 'JayTINd4Za2C',
            userName: 'Alexander Vanderbilt',
            type: 'Installment',
            totalAmount: 2400,
            paidAmount: 600,
            paymentCycle: 'Weekly',
            cycleCount: 4,
            startDate: '2024-01-01',
            endDate: '2024-01-31', 
            items: [
              { id: 'I-01', name: 'Premium Artifact Collection', amount: 2400, date: '2024-01-01', note: 'Curated high-end items.' }
            ],
            payments: [
              { id: 'P-01', amount: 600, method: 'BANK', date: '2024-01-02', note: 'Initial Protocol Injection' }
            ],
            notes: [
              { id: 'N-01', timestamp: '2024-01-01 14:00', content: 'Account established with priority status.' }
            ],
            attachments: [],
            status: 'Active'
          }
        ];
        setRecords(mockData);
      }
    } catch (e) {
      console.error("Failed to load records", e);
    }
  }, []);

  // Save records
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    }
  }, [records]);

  // Public View detection
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const handleLogin = (user: string, pass: string) => {
    if (user === ADMIN_USER && pass === ADMIN_PASS) {
      setIsAuthenticated(true);
      localStorage.setItem('jaytin_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
  };

  // Status Auto-Update Logic
  useEffect(() => {
    const now = new Date();
    let hasChanges = false;
    const nextRecords = records.map(r => {
      let newStatus = r.status;
      const isFullyPaid = r.paidAmount >= r.totalAmount && r.totalAmount > 0;

      if (isFullyPaid) {
        newStatus = 'Settled';
      } else if (r.endDate) {
        const end = new Date(r.endDate);
        newStatus = now > end ? 'Overdue' : 'Active';
      } else {
        newStatus = 'Active';
      }

      if (newStatus !== r.status) {
        hasChanges = true;
        return { ...r, status: newStatus as any };
      }
      return r;
    });

    if (hasChanges) {
      setRecords(nextRecords);
    }
  }, [records]);

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const activeRecord = useMemo(() => {
    const targetId = viewModeId || selectedRecordId;
    return records.find(r => r.id === targetId);
  }, [viewModeId, selectedRecordId, records]);

  const updateRecord = (updated: LedgerRecord) => {
    setRecords(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const exitViewMode = () => {
    window.location.hash = '';
    setViewModeId(null);
  };

  if (viewModeId && activeRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail 
          key={`view-${activeRecord.id}`}
          record={activeRecord} 
          isViewOnly={true}
          onClose={exitViewMode}
          onUpdateRecord={() => {}} 
        />
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />
             <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em]">Master Protocol Active</p>
          </div>
        </div>

        <div className="flex items-center space-x-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999] transition-colors" />
            <input 
              type="text" 
              placeholder="Search Archives..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none transition-all w-64 shadow-sm"
            />
          </div>
          <motion.button 
            whileHover={{ filter: 'brightness(1.05)' }}
            whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <motion.button 
            whileHover={{ filter: 'brightness(0.9)', x: 3 }}
            onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
            title="Security Exit"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter}
                onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList 
          records={filteredRecords} 
          onSelect={setSelectedRecordId} 
          selectedId={selectedRecordId}
        />
      </main>

      <AnimatePresence>
        {selectedRecordId && activeRecord && (
          <CustomerDetail 
            key={`detail-${activeRecord.id}`}
            record={activeRecord} 
            isViewOnly={false}
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={updateRecord}
          />
        )}
      </AnimatePresence>

      <RecordFormModal 
        isOpen={isAddingRecord} 
        onClose={() => setIsAddingRecord(false)} 
        onSave={(newRecord) => { 
          setRecords(prev => [newRecord, ...prev]); 
          setIsAddingRecord(false); 
        }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  Pin,
  AlertTriangle,
  Share2,
  Check,
  Eye,
  Trash2
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';
import RecordFormModal from './RecordFormModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onUpdateRecord: (record: LedgerRecord) => void;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onUpdateRecord
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');

  // Modal States
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [editingItem, setEditingItem] = useState<PurchaseItem | null>(null);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | null>(null);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [selectedItemPreview, setSelectedItemPreview] = useState<PurchaseItem | null>(null);

  const [isTimelineExpanded, setIsTimelineExpanded] = useState(false);
  const [copied, setCopied] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment', id: string } | null>(null);

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Persistence logic for timeline/reminders
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    return [{
      id: 'reminder-pinned-calc',
      timestamp: nextDate.toDateString(),
      content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due. Outstanding: RM${Math.max(0, record.totalAmount - record.paidAmount).toLocaleString()}. Next deadline: ${nextDate.toLocaleDateString()}.`,
      isPinned: true
    }];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...(record.notes || [])], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => isTimelineExpanded ? timelineNotes : timelineNotes.slice(0, 10), [timelineNotes, isTimelineExpanded]);

  // SAFE Handlers using array spread with defaults
  const handleAddItem = (item: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = [...safeItems, { ...item, id: item.id || `I-${Date.now()}` }];
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal });
    setIsAddingItem(false);
  };

  const handleEditItem = (updated: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = safeItems.map(i => i.id === updated.id ? updated : i);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal });
    setEditingItem(null);
  };

  const handleDeleteItem = (id: string) => {
    const safeItems = record.items || [];
    const newItems = safeItems.filter(i => i.id !== id);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal });
    setConfirmDelete(null);
  };

  const handleAddPayment = (payment: any) => {
    const newPaymentObj: PaymentRecord = { ...payment, id: `P-${Date.now()}` };
    const safePayments = record.payments || [];
    const newPayments = [newPaymentObj, ...safePayments];
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid });
    setIsRecordingPayment(false);
  };

  const handleEditPayment = (updated: PaymentRecord) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.map(p => p.id === updated.id ? updated : p);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid });
    setEditingPayment(null);
  };

  const handleDeletePayment = (id: string) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.filter(p => p.id !== id);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid });
    setConfirmDelete(null);
  };

  const handleAddEvidence = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      const newAttachment: Attachment = {
        id: `A-E-${Date.now()}`,
        name: `Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      };
      const safeAttachments = record.attachments || [];
      onUpdateRecord({ ...record, attachments: [newAttachment, ...safeAttachments] });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareUrl = `${window.location.origin}${window.location.pathname}#/view/${record.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') handleDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') handleDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      const safeAttachments = record.attachments || [];
      onUpdateRecord({ ...record, attachments: safeAttachments.filter(a => a.id !== confirmDelete.id) });
      setSelectedAttachment(null);
      setConfirmDelete(null);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8"
    >
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-2xl"
      >
        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button type="button" onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>
              <div className="px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest bg-white/40 border border-[#B8A17D]/20 text-gray-600 shadow-sm">
                {record.type}
              </div>
              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${
                record.status === 'Overdue' ? 'bg-red-500 text-white border-red-400' : 
                record.status === 'Settled' ? 'bg-[#333] text-white border-gray-700' : 
                'bg-white/60 text-gray-800'
              }`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              {!isViewOnly && (
                <motion.button type="button" whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={() => setIsEditingProfile(true)} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                  <Edit2 className="w-4.5 h-4.5" />
                </motion.button>
              )}
              <motion.button 
                type="button"
                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                onClick={handleShare}
                className={`p-2.5 bg-white/40 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 ${copied ? 'text-green-600' : 'text-[#B8A17D] hover:bg-white/60'}`}
              >
                {copied ? <Check className="w-4.5 h-4.5" /> : <Share2 className="w-4.5 h-4.5" />}
                <span className="text-[10px] font-bold uppercase tracking-widest pr-1">{copied ? 'Linked' : 'Share'}</span>
              </motion.button>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">Protocol ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Maturity: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Fulfillment Scope</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Preserved</p>
                <p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Outstanding</p>
                <p className="text-xl font-jua text-[#B8A17D]">RM{Math.max(0, record.totalAmount - record.paidAmount).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} type="button" onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}
              {activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    {!isViewOnly && <button type="button" onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>}
                  </h4>
                  {isAddingEvidence && !isViewOnly && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (file) {
                          const reader = new FileReader();
                          reader.onloadend = () => setEvidenceImage(reader.result as string);
                          reader.readAsDataURL(file);
                        }
                      }} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button type="button" onClick={handleAddEvidence} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {(record.attachments || []).map(att => (
                      <div key={att.id} onClick={() => setSelectedAttachment(att)} className="relative group bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">
                          {att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}
                        </div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                        {!isViewOnly && <button type="button" onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'attachment', id: att.id }); }} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-3 h-3" /></button>}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>
                        {note.isPinned ? 'Protocol Reminders' : note.timestamp}
                      </p>
                      <p className={`text-[14px] font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>
                        {note.content}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              {!isViewOnly && (
                <motion.button 
                  type="button"
                  whileHover={{ filter: 'brightness(1.05)' }} 
                  whileTap={{ scale: 0.98 }} 
                  onClick={() => setIsAddingItem(true)} 
                  className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] gold-glow"
                >
                  <ShoppingBag className="w-5 h-5" />
                  <span>Declare New Asset Entry</span>
                </motion.button>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {(record.items || []).map(item => (
                  <div key={item.id} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40 relative">
                    <div onClick={() => setSelectedItemPreview(item)} className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div>
                          <span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span>
                          <span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        </div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                    {!isViewOnly && (
                      <div className="absolute bottom-6 right-8 flex space-x-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button type="button" onClick={(e) => { e.stopPropagation(); setEditingItem(item); }} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                        <button type="button" onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'item', id: item.id }); }} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                  </div>
                ))}
