import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import Login from './components/Login';
import { supabase } from './supabase';

const ADMIN_USER = "admin";
const ADMIN_PASS = "jaytin_secure";

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');
  const [viewModeId, setViewModeId] = useState<string | null>(null);

  // 1. Fetch from Supabase on mount
  useEffect(() => {
    const fetchFromCloud = async () => {
      setIsLoading(true);
      setSyncError(null);
      try {
        const { data, error } = await supabase
          .from('ledgers')
          .select('*');

        if (error) {
          // Extract specific message to avoid [object Object]
          throw new Error(error.message || 'Database connection failed');
        }

        if (data && data.length > 0) {
          const cloudRecords = data.map((row: any) => row.record);
          setRecords(cloudRecords);
        } else {
          // Fallback to LocalStorage if Cloud is empty
          const saved = localStorage.getItem('jaytin_ledgers');
          if (saved) {
            try {
              setRecords(JSON.parse(saved));
            } catch (e) {
              console.error("Local Parse Error", e);
            }
          }
        }
      } catch (e: any) {
        const msg = e.message || "Unknown Cloud Error";
        console.error("Cloud Protocol Error Details:", msg);
        setSyncError(`Cloud Sync Offline: ${msg}`);

        // Disaster Recovery: LocalStorage
        const saved = localStorage.getItem('jaytin_ledgers');
        if (saved) {
          try {
            setRecords(JSON.parse(saved));
          } catch (parseErr) {
            console.error("Local Backup Corruption", parseErr);
          }
        }
      } finally {
        setIsLoading(false);
      }
    };

    if (isAuthenticated) {
      fetchFromCloud();
    } else {
      setIsLoading(false);
    }
  }, [isAuthenticated]);

  // 2. Sync to Cloud on changes
  const syncRecordToCloud = async (updatedRecord: LedgerRecord) => {
    try {
      const { error } = await supabase
        .from('ledgers')
        .upsert({ 
          id: updatedRecord.id, 
          record: updatedRecord,
          updated_at: new Date().toISOString()
        });

      if (error) throw error;
      setSyncError(null);

      // Update LocalStorage as parallel backup
      localStorage.setItem('jaytin_ledgers', JSON.stringify(records));
    } catch (e: any) {
      const msg = e.message || "Sync Interrupted";
      console.error("Cloud Sync Interrupted:", msg);
      setSyncError(`Sync Error: ${msg}`);
    }
  };

  // Public View detection
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/view/')) {
        const id = hash.replace('#/view/', '');
        setViewModeId(id);
      } else {
        setViewModeId(null);
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
