/**
 * Enhanced error stringifier to prevent [object Object] in UI.
 * Explicitly handles Supabase RLS policy violations and Network Link obstructions.
 */
const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";

  // Specific handling for RLS Policy Violations
  const errMsg = err.message || '';
  if (errMsg.includes('row-level security policy')) {
    return "Database Locked: RLS Policy missing. Please run SQL policies in Supabase Editor.";
  }

  // Specific handling for standard fetch errors (Network/CORS/Blocked)
  if (err instanceof TypeError && errMsg.toLowerCase().includes('fetch')) {
    return "Global Vault Link Obstructed. (Check network or ad-blocker)";
  }

  if (typeof err === 'string') return err;

  // Handle Supabase/Postgrest error format
  const msg = err.message || err.error_description || err.code;
  const details = err.details ? ` (${err.details})` : '';
  const hint = err.hint ? ` Hint: ${err.hint}` : '';

  if (typeof msg === 'string') {
    return `${msg}${details}${hint}`;
  }

  // Handle standard Error objects which have non-enumerable 'message'
  try {
    const errorWithHiddenProps = JSON.stringify(err, Object.getOwnPropertyNames(err));
    const parsed = JSON.parse(errorWithHiddenProps);
    if (parsed.message) return parsed.message;
    return errorWithHiddenProps;
  } catch {
    return String(err);
  }
};

