      <RecordFormModal 
        isOpen={isAddingRecord} 
        onClose={() => setIsAddingRecord(false)} 
        onSave={(newRecord) => {
          const next = [newRecord, ...records];
          setRecords(next);
          syncRecordToCloud(newRecord, next);
          setIsAddingRecord(false);
        }} 
      />

      <UserManagementModal 
        isOpen={isManagingUsers} 
        onClose={() => setIsManagingUsers(false)} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, UserPlus, Trash2, ShieldCheck, Loader2, AlertCircle, Key } from 'lucide-react';
import { supabase } from '../supabase';

interface Props {
  isOpen: boolean;
  onClose: () => void;
}

interface CloudUser {
  id: string;
  username: string;
  created_at: string;
}

const UserManagementModal: React.FC<Props> = ({ isOpen, onClose }) => {
  const [users, setUsers] = useState<CloudUser[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchUsers = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase.from('users').select('id, username, created_at').order('created_at', { ascending: false });
      if (error) throw error;
      setUsers(data || []);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) fetchUsers();
  }, [isOpen]);

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUsername || !newPassword) return;
    setIsAdding(true);
    setError(null);
    try {
      const { error } = await supabase.from('users').insert({ username: newUsername, password: newPassword });
      if (error) throw error;
      setNewUsername('');
      setNewPassword('');
      fetchUsers();
    } catch (e: any) {
      setError(e.message.includes('unique') ? 'Username already exists' : e.message);
    } finally {
      setIsAdding(false);
    }
  };

  const handleDeleteUser = async (id: string, username: string) => {
    if (username === 'admin') return; // Protect core admin
    if (!confirm(`Are you sure you want to revoke access for ${username}?`)) return;
    try {
      const { error } = await supabase.from('users').delete().eq('id', id);
      if (error) throw error;
      fetchUsers();
    } catch (e: any) {
      setError(e.message);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-xl" />
      <motion.div initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }} className="glass-card w-full max-w-2xl h-[80vh] rounded-[48px] overflow-hidden border border-white/60 shadow-2xl relative z-10 flex flex-col">

        <div className="p-10 pb-6 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-3xl font-jua text-[#333]">Identity Management</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.3em] mt-2">Authorized Protocol Personnel</p>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/50 rounded-full transition-all"><X className="w-6 h-6 text-gray-400" /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
          {/* Add User Section */}
          <section className="space-y-6">
            <h4 className="text-[11px] font-bold text-[#B8A17D] uppercase tracking-[0.2em] flex items-center">
              <UserPlus className="w-4 h-4 mr-2" /> Inject New Protocol Identity
            </h4>
            <form onSubmit={handleAddUser} className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <input 
                required type="text" placeholder="Identity UID" value={newUsername} onChange={(e) => setNewUsername(e.target.value)}
                className="bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30"
              />
              <input 
                required type="password" placeholder="Protocol Key" value={newPassword} onChange={(e) => setNewPassword(e.target.value)}
                className="bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:ring-1 focus:ring-[#B8A17D]/30"
              />
              <button 
                type="submit" disabled={isAdding}
                className="bg-[#999] text-white rounded-2xl font-bold text-xs uppercase tracking-widest shadow-lg border border-[#B8A17D]/30 hover:brightness-105 active:scale-95 transition-all flex items-center justify-center space-x-2"
              >
                {isAdding ? <Loader2 className="w-4 h-4 animate-spin" /> : <span>Authorize</span>}
              </button>
            </form>
            {error && <p className="text-[10px] text-red-500 font-bold uppercase tracking-widest flex items-center"><AlertCircle className="w-3 h-3 mr-1" /> {error}</p>}
          </section>

          {/* User List Section */}
          <section className="space-y-6">
            <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.2em]">Authorized Identities</h4>
            {isLoading ? (
              <div className="flex justify-center py-12"><Loader2 className="w-6 h-6 text-[#B8A17D] animate-spin" /></div>
            ) : (
              <div className="grid grid-cols-1 gap-4">
                {users.map(u => (
                  <motion.div 
                    key={u.id} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }}
                    className="p-6 rounded-3xl bg-white/30 border border-white/50 flex justify-between items-center group hover:bg-white/50 transition-all"
                  >
                    <div className="flex items-center space-x-4">
                      <div className="w-12 h-12 bg-[#333] rounded-2xl flex items-center justify-center border border-[#B8A17D]/30 shadow-inner">
                        <ShieldCheck className="w-6 h-6 text-[#B8A17D]" />
                      </div>
                      <div>
                        <p className="text-sm font-bold text-gray-800">{u.username}</p>
                        <p className="text-[9px] text-gray-400 uppercase tracking-widest font-bold">Authorized: {new Date(u.created_at).toLocaleDateString()}</p>
                      </div>
                    </div>
                    {u.username !== 'admin' && (
                      <button 
                        onClick={() => handleDeleteUser(u.id, u.username)}
                        className="p-3 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    )}
                  </motion.div>
                ))}
              </div>
            )}
          </section>
        </div>

        <div className="p-8 bg-white/20 border-t border-white/10 text-center">
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-[0.4em]">JayTIN Private Security Protocol</p>
        </div>
      </motion.div>
    </div>
  );
};

