);

-- 1. 为 ledgers 表添加所有人可操作的权限（因为你使用的是 Anon Key）
CREATE POLICY "Enable all for anon" ON public.ledgers
FOR ALL USING (true) WITH CHECK (true);

-- 2. 为 users 表添加所有人可查询的权限（用于登录校验）
CREATE POLICY "Enable read for anon" ON public.users
FOR SELECT USING (true);

-- 1. 创建身份验证表
CREATE TABLE IF NOT EXISTS public.users (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  username text UNIQUE NOT NULL,
  password text NOT NULL,
  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. 启用行级安全（RLS）
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

-- 3. 创建策略：允许匿名用户通过密钥进行所有操作（增删改查）
-- 注意：在正式环境建议根据身份细分，但为了你现在能立刻使用，开启全权限策略
CREATE POLICY "Allow all access for users" ON public.users FOR ALL USING (true) WITH CHECK (true);

-- 4. 插入初始管理员账号 (如果不存在)
-- 用户名: admin  密码: jaytin_secure
