import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle,
  RefreshCw,
  WifiOff,
  CloudOff,
  Settings,
  Users,
  DatabaseZap
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import UserManagementModal from './components/UserManagementModal';
import Login from './components/Login';
import { supabase } from './supabase';

const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  const errCode = err.code || '';

  if (errCode === '42P01' || errMsg.includes('relation "public.users" does not exist') || errMsg.includes('relation "public.ledgers" does not exist')) {
    return "Database Schema Missing: Please run the initialization SQL in Supabase Editor.";
  }

  if (errMsg.includes('row-level security policy')) {
    return "Database Locked: RLS Policy missing. Please run SQL policies in Supabase Editor.";
  }
  if (err instanceof TypeError && errMsg.toLowerCase().includes('fetch')) {
    return "Global Vault Link Obstructed. (Check network or ad-blocker)";
  }
  if (typeof err === 'string') return err;
  const msg = err.message || err.error_description || err.code;
  if (typeof msg === 'string') return msg;
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { setRecords(JSON.parse(saved)); } catch (e) { console.warn(e); }
    }
  }, []);

  const fetchFromCloud = async () => {
    setSyncError(null);
    try {
      const { data, error } = await supabase.from('ledgers').select('*');
      if (error) throw error;
      if (data && data.length > 0) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
      }
    } catch (e: any) {
      setSyncError(stringifyError(e));
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated) fetchFromCloud();
    else setIsLoading(false);
  }, [isAuthenticated]);

  const syncRecordToCloud = async (updatedRecord: LedgerRecord, currentRecords: LedgerRecord[]) => {
    localStorage.setItem('jaytin_ledgers', JSON.stringify(currentRecords));
    try {
      const { error } = await supabase.from('ledgers').upsert({ 
        id: updatedRecord.id, 
        record: updatedRecord,
        updated_at: new Date().toISOString()
      });
      if (error) throw error;
      setSyncError(null);
    } catch (e: any) {
      setSyncError(`Vault Sync Paused: ${stringifyError(e)}`);
    }
  };

  const handleLogin = async (user: string, pass: string) => {
    try {
      // Strictly authenticate against Supabase Vault
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('username', user)
        .eq('password', pass)
        .single();

      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e: any) {
      console.error("Auth Protocol Breach", e);
      return false;
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
    setRecords([]);
  };

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF] space-y-4">
        <Loader2 className="w-8 h-8 text-[#B8A17D] animate-spin" />
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.3em]">Establishing Vault Connection...</p>
      </div>
    );
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div className="relative group">
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             {syncError ? <CloudOff className="w-3 h-3 text-red-400" /> : <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />}
             <p className={`text-[9px] font-bold uppercase tracking-[0.3em] ${syncError ? 'text-red-400' : 'text-[#B8A17D]'}`}>
               {syncError ? 'Autonomous Local Mode' : 'Cloud Protocol Sync Active'}
             </p>
          </div>

          <AnimatePresence>
            {syncError && syncError.includes('SQL') && (
              <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="absolute top-full left-0 mt-4 p-5 bg-white/95 backdrop-blur-xl border border-red-200 rounded-3xl shadow-2xl z-[100] min-w-[320px]">
                <div className="flex items-start space-x-3">
                  <DatabaseZap className="w-5 h-5 text-red-500 mt-0.5" />
                  <div className="space-y-2">
                    <p className="text-[10px] font-bold text-red-600 uppercase tracking-widest">Protocol Setup Required</p>
                    <p className="text-xs text-gray-600 leading-relaxed font-medium">The Identity Vault table has not been initialized in Supabase. Run the setup SQL to enable cloud users.</p>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex items-center space-x-3">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999]" />
            <input 
              type="text" placeholder="Search Archives..." value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none w-64 shadow-sm"
            />
          </div>

          <motion.button 
            type="button" whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <div className="h-10 w-[1px] bg-gray-200 mx-1" />

          <motion.button 
            type="button" whileHover={{ rotate: 15 }} onClick={() => setIsManagingUsers(true)}
            className="p-2.5 text-[#B8A17D] bg-white/40 rounded-xl border border-white/60 shadow-sm"
          >
            <Users className="w-5 h-5" />
          </motion.button>

          <motion.button 
            type="button" whileHover={{ x: 3 }} onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter} type="button" onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
      </main>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              setRecords(next);
              syncRecordToCloud(updated, next);
            }}
          />
        )}
      </AnimatePresence>

      <RecordFormModal 
        isOpen={isAddingRecord} 
        onClose={() => setIsAddingRecord(false)} 
        onSave={(newRecord) => {
          const next = [newRecord, ...records];
          setRecords(next);
          syncRecordToCloud(newRecord, next);
          setIsAddingRecord(false);
        }} 
      />

      <UserManagementModal 
        isOpen={isManagingUsers} 
        onClose={() => setIsManagingUsers(false)} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, UserPlus, Trash2, ShieldCheck, Loader2, AlertCircle, DatabaseZap, Terminal } from 'lucide-react';
import { supabase } from '../supabase';

interface Props {
  isOpen: boolean;
  onClose: () => void;
}

interface CloudUser {
  id: string;
  username: string;
  created_at: string;
}

const UserManagementModal: React.FC<Props> = ({ isOpen, onClose }) => {
  const [users, setUsers] = useState<CloudUser[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSchemaMissing, setIsSchemaMissing] = useState(false);

  const fetchUsers = async () => {
    setIsLoading(true);
    setIsSchemaMissing(false);
    setError(null);
    try {
      const { data, error } = await supabase.from('users').select('id, username, created_at').order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') {
          setIsSchemaMissing(true);
          throw new Error("Identity Vault Schema (users table) is missing in Supabase.");
        }
        throw error;
      }
      setUsers(data || []);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) fetchUsers();
  }, [isOpen]);

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUsername || !newPassword) return;
    setIsAdding(true);
    setError(null);
    try {
      const { error } = await supabase.from('users').insert({ username: newUsername, password: newPassword });
      if (error) throw error;
      setNewUsername('');
      setNewPassword('');
      fetchUsers();
    } catch (e: any) {
      setError(e.message.includes('unique') ? 'Username already exists' : e.message);
    } finally {
      setIsAdding(false);
    }
  };

  const handleDeleteUser = async (id: string, username: string) => {
    // No more special protection for 'admin' string, but warn the user
    if (!confirm(`Are you sure you want to PERMANENTLY revoke access for ${username}? This cannot be undone.`)) return;
    try {
      const { error } = await supabase.from('users').delete().eq('id', id);
      if (error) throw error;
      fetchUsers();
    } catch (e: any) {
      setError(e.message);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-[#EBFAFF]/80 backdrop-blur-xl" />
      <motion.div initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }} className="glass-card w-full max-w-2xl h-[80vh] rounded-[48px] overflow-hidden border border-white/60 shadow-2xl relative z-10 flex flex-col">

        <div className="p-10 pb-6 border-b border-white/20 flex justify-between items-center">
          <div>
            <h3 className="text-3xl font-jua text-[#333]">Identity Management</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-[0.3em] mt-2">Authorized Protocol Personnel</p>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/50 rounded-full transition-all group">
            <X className="w-6 h-6 text-gray-400 group-hover:rotate-90 transition-transform" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
          {isSchemaMissing ? (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6">
              <div className="p-6 bg-red-50 rounded-[32px] border border-red-100 shadow-inner">
                <DatabaseZap className="w-12 h-12 text-red-500" />
              </div>
              <div className="max-w-md space-y-3">
                <h4 className="text-xl font-jua text-gray-800">Vault Uninitialized</h4>
                <p className="text-sm text-gray-500 leading-relaxed font-medium">The required database table <code className="text-red-500 font-bold bg-red-50 px-1.5 rounded">users</code> was not found. Cloud identity injection is currently disabled.</p>
                <div className="bg-[#333] p-4 rounded-2xl text-left border border-[#B8A17D]/30 mt-4 overflow-hidden relative group">
                  <Terminal className="w-3.5 h-3.5 text-[#B8A17D] absolute top-3 right-3 opacity-30" />
                  <p className="text-[9px] text-[#B8A17D] font-bold uppercase tracking-widest mb-2">Protocol Solution</p>
                  <p className="text-[11px] text-gray-300 font-mono leading-tight">Run the SQL initialization script in Supabase Editor to unlock the Vault.</p>
                </div>
              </div>
