const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  const errCode = err.code || '';

  if (errCode === '42P01' || errMsg.includes('relation "public.users" does not exist') || errMsg.includes('relation "public.ledgers" does not exist')) {
    return "Database Schema Missing: Please run the initialization SQL in Supabase Editor.";
  }

  if (errMsg.includes('row-level security policy')) {
    return "Database Locked: RLS Policy missing. Please run SQL policies in Supabase Editor.";
  }
  if (err instanceof TypeError && errMsg.toLowerCase().includes('fetch')) {
    return "Global Vault Link Obstructed. (Check network or ad-blocker)";
  }
  if (typeof err === 'string') return err;
  const msg = err.message || err.error_description || err.code;
  if (typeof msg === 'string') return msg;
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('jaytin_auth') === 'true';
  });

  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false); // 新增：后台同步状态
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  // 初始化：立即从本地获取数据
  useEffect(() => {
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        const parsed = JSON.parse(saved);
        setRecords(parsed);
        // 如果本地有数据，直接结束全屏加载状态，实现秒开
        setIsLoading(false);
      } catch (e) { 
        console.warn(e); 
      }
    }
  }, []);

  const fetchFromCloud = async () => {
    setSyncError(null);
    setIsSyncing(true); // 标记正在同步
    try {
      // 仅查询 record 列和 id，减少网络负载
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;

      if (data) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
      }
    } catch (e: any) {
      setSyncError(stringifyError(e));
    } finally {
      setIsLoading(false); // 无论结果如何，都关闭全屏加载
      setIsSyncing(false); // 结束同步状态
    }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchFromCloud();
    } else {
      setIsLoading(false);
    }
  }, [isAuthenticated]);

  const syncRecordToCloud = async (updatedRecord: LedgerRecord, currentRecords: LedgerRecord[]) => {
    // 立即更新本地缓存（乐观 UI 更新）
    localStorage.setItem('jaytin_ledgers', JSON.stringify(currentRecords));
    try {
      const { error } = await supabase.from('ledgers').upsert({ 
        id: updatedRecord.id, 
        record: updatedRecord,
        updated_at: new Date().toISOString()
      });
      if (error) throw error;
      setSyncError(null);
    } catch (e: any) {
      setSyncError(`Vault Sync Paused: ${stringifyError(e)}`);
    }
  };

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('username', user)
        .eq('password', pass)
        .single();

      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e: any) {
      console.error("Auth Protocol Breach", e);
      return false;
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
    localStorage.removeItem('jaytin_ledgers'); // 登出时清理缓存
    setRecords([]);
  };

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF] space-y-4">
        <Loader2 className="w-8 h-8 text-[#B8A17D] animate-spin" />
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.3em]">Opening Secure Vault...</p>
      </div>
    );
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      {/* 顶部静默同步指示器 */}
      <AnimatePresence>
        {isSyncing && (
          <motion.div 
            initial={{ opacity: 0, y: -20 }} 
            animate={{ opacity: 1, y: 0 }} 
            exit={{ opacity: 0, y: -20 }}
            className="fixed top-4 left-1/2 -translate-x-1/2 z-[200] bg-[#333]/80 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/10 flex items-center space-x-2 shadow-xl"
          >
            <Loader2 className="w-3 h-3 text-[#B8A17D] animate-spin" />
            <span className="text-[9px] font-bold text-white uppercase tracking-[0.2em]">Synchronizing Archive...</span>
          </motion.div>
        )}
      </AnimatePresence>

      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div className="relative group">
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             {syncError ? <CloudOff className="w-3 h-3 text-red-400" /> : <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />}
             <p className={`text-[9px] font-bold uppercase tracking-[0.3em] ${syncError ? 'text-red-400' : 'text-[#B8A17D]'}`}>
               {syncError ? 'Autonomous Local Mode' : 'Vault Protocol Active'}
             </p>
          </div>

          <AnimatePresence>
            {syncError && syncError.includes('SQL') && (
              <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="absolute top-full left-0 mt-4 p-5 bg-white/95 backdrop-blur-xl border border-red-200 rounded-3xl shadow-2xl z-[100] min-w-[320px]">
                <div className="flex items-start space-x-3">
                  <DatabaseZap className="w-5 h-5 text-red-500 mt-0.5" />
                  <div className="space-y-2">
                    <p className="text-[10px] font-bold text-red-600 uppercase tracking-widest">Protocol Setup Required</p>
                    <p className="text-xs text-gray-600 leading-relaxed font-medium">The Identity Vault table has not been initialized in Supabase.</p>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex items-center space-x-3">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-hover:text-[#999]" />
            <input 
              type="text" placeholder="Search Archives..." value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none w-64 shadow-sm"
            />
          </div>

          <motion.button 
            type="button" whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
            onClick={() => setIsAddingRecord(true)}
            className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow"
          >
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>

          <div className="h-10 w-[1px] bg-gray-200 mx-1" />

          <motion.button 
            type="button" whileHover={{ rotate: 15 }} onClick={() => setIsManagingUsers(true)}
            className="p-2.5 text-[#B8A17D] bg-white/40 rounded-xl border border-white/60 shadow-sm"
          >
            <Users className="w-5 h-5" />
          </motion.button>

          <motion.button 
            type="button" whileHover={{ x: 3 }} onClick={handleLogout}
            className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"
          >
            <LogOut className="w-5 h-5" />
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />

        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((filter) => (
              <button
                key={filter} type="button" onClick={() => setStatusFilter(filter as any)}
                className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${
                  statusFilter === filter 
                    ? 'bg-[#B8A17D] text-white border-[#B8A17D]' 
                    : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'
                }`}
              >
                {filter}
              </button>
            ))}
          </div>
        </div>

        <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
      </main>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              setRecords(next);
              syncRecordToCloud(updated, next);
            }}
          />
        )}
      </AnimatePresence>

      <RecordFormModal 
        isOpen={isAddingRecord} 
        onClose={() => setIsAddingRecord(false)} 
        onSave={(newRecord) => {
          const next = [newRecord, ...records];
          setRecords(next);
          syncRecordToCloud(newRecord, next);
          setIsAddingRecord(false);
        }} 
      />

      <UserManagementModal 
        isOpen={isManagingUsers} 
        onClose={() => setIsManagingUsers(false)} 
      />
    </div>
  );
};

