            </motion.div>
          )}
          {selectedAttachment && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[160] flex items-center justify-center bg-black/60 backdrop-blur-2xl p-4 md:p-12" onClick={() => setSelectedAttachment(null)}>
