import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle,
  CloudOff,
  Users,
  DatabaseZap,
  Globe
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import UserManagementModal from './components/UserManagementModal';
import Login from './components/Login';
import { supabase } from './supabase';

const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  if (errMsg.includes('relation "public.ledgers" does not exist')) return "Database Schema Missing.";
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => localStorage.getItem('jaytin_auth') === 'true');
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  // --- 共享访问逻辑 (Public Mode) ---
  const [publicRecord, setPublicRecord] = useState<LedgerRecord | null>(null);
  // 初始化时立即检查 Hash，避免登录页面的闪烁
  const [isPublicMode, setIsPublicMode] = useState(() => window.location.hash.startsWith('#/share/'));

  useEffect(() => {
    const handleRoute = async () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/share/')) {
        const key = hash.replace('#/share/', '');
        // 只有当密钥长度足够时才认为是合法的共享协议
        if (key && key.length >= 32) {
          setIsPublicMode(true);
          setIsLoading(true);
          try {
            const { data, error } = await supabase
              .from('ledgers')
              .select('record')
              .eq('record->>shareKey', key)
              .maybeSingle();

            if (data) {
              setPublicRecord(data.record as LedgerRecord);
            } else {
              setPublicRecord(null);
            }
          } catch (e) {
            console.error("Vault access failure", e);
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsPublicMode(false);
          setPublicRecord(null);
        }
      } else {
        setIsPublicMode(false);
        setPublicRecord(null);
      }
    };

    handleRoute();
    window.addEventListener('hashchange', handleRoute);
    return () => window.removeEventListener('hashchange', handleRoute);
  }, []);

  // --- 管理端初始化逻辑 ---
  useEffect(() => {
    if (isPublicMode) return;
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        setRecords(JSON.parse(saved));
        setIsLoading(false);
      } catch (e) { console.warn(e); }
    }
  }, [isPublicMode]);

  const fetchFromCloud = async () => {
    if (isPublicMode || !isAuthenticated) return;
    setSyncError(null);
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;
      if (data) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
      }
    } catch (e: any) {
      setSyncError(stringifyError(e));
    } finally {
      setIsLoading(false);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated && !isPublicMode) {
      fetchFromCloud();
    } else if (!isPublicMode) {
      setIsLoading(false);
    }
  }, [isAuthenticated, isPublicMode]);

  const syncRecordToCloud = async (updatedRecord: LedgerRecord, currentRecords: LedgerRecord[]) => {
    localStorage.setItem('jaytin_ledgers', JSON.stringify(currentRecords));
    try {
      const { error } = await supabase.from('ledgers').upsert({ 
        id: updatedRecord.id, 
        record: updatedRecord,
        updated_at: new Date().toISOString()
      });
      if (error) throw error;
    } catch (e: any) {
      setSyncError(`Sync Paused: ${stringifyError(e)}`);
    }
  };

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('username', user).eq('password', pass).single();
      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e) { return false; }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
    localStorage.removeItem('jaytin_ledgers');
    setRecords([]);
    window.location.hash = '';
  };

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  // 加载中状态显示
  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF]">
        <Loader2 className="w-8 h-8 text-[#B8A17D] animate-spin" />
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.3em] mt-4">Handshaking Protocol...</p>
      </div>
    );
  }

  // --- 共享模式展示 (优先级最高) ---
  if (isPublicMode) {
    if (publicRecord) {
      return (
        <div className="min-h-screen bg-[#EBFAFF]">
          <CustomerDetail 
            record={publicRecord} 
            isViewOnly={true} 
            onClose={() => { window.location.hash = ''; }} 
            onUpdateRecord={() => {}} 
          />
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[100] px-6 py-2 bg-[#333]/80 backdrop-blur-md rounded-full border border-white/10 shadow-2xl">
             <p className="text-[9px] text-white font-bold uppercase tracking-[0.3em] flex items-center">
               <Globe className="w-3 h-3 mr-2 text-[#B8A17D]" /> Safe View Mode • JayTIN Protocol
             </p>
          </div>
        </div>
      );
    } else {
      // 密钥无效或记录不存在
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF] p-10 text-center">
          <AlertCircle className="w-12 h-12 text-red-400 mb-6" />
          <h2 className="text-2xl font-jua text-gray-800">Access Denied</h2>
          <p className="text-sm text-gray-400 mt-2">The requested protocol artifact does not exist or link is malformed.</p>
          <button onClick={() => window.location.hash = ''} className="mt-8 px-8 py-3 bg-[#999] text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest">Return to Home</button>
        </div>
      );
    }
  }

  // --- 管理端登录拦截 ---
  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  // --- 正常管理后台 ---
  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <AnimatePresence>
        {isSyncing && (
          <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="fixed top-4 left-1/2 -translate-x-1/2 z-[200] bg-[#333]/80 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/10 flex items-center space-x-2 shadow-xl">
            <Loader2 className="w-3 h-3 text-[#B8A17D] animate-spin" />
            <span className="text-[9px] font-bold text-white uppercase tracking-[0.2em]">Cloud Syncing...</span>
          </motion.div>
        )}
      </AnimatePresence>

      <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
        <div className="relative group">
          <h1 className="text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2 mt-1">
             <ShieldCheck className="w-3 h-3 text-[#B8A17D]" />
             <p className="text-[9px] font-bold uppercase tracking-[0.3em] text-[#B8A17D]">Vault Protocol Active</p>
          </div>
        </div>

        <div className="flex items-center space-x-3">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input type="text" placeholder="Search..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-10 pr-4 py-2 bg-white/40 border border-white/30 backdrop-blur-md rounded-full text-sm focus:outline-none w-64" />
          </div>
          <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setIsAddingRecord(true)} className="flex items-center space-x-2 bg-[#999] text-white px-6 py-2.5 rounded-[14px] font-semibold text-sm border border-[#B8A17D]/30 shadow-inner gold-glow">
            <Plus className="w-4 h-4" />
            <span>New Registry</span>
          </motion.button>
          <div className="h-10 w-[1px] bg-gray-200 mx-1" />
          <motion.button type="button" whileHover={{ rotate: 15 }} onClick={() => setIsManagingUsers(true)} className="p-2.5 text-[#B8A17D] bg-white/40 rounded-xl border border-white/60 shadow-sm"><Users className="w-5 h-5" /></motion.button>
          <motion.button type="button" whileHover={{ x: 3 }} onClick={handleLogout} className="p-2.5 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20"><LogOut className="w-5 h-5" /></motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-8">
        <Dashboard stats={stats} />
        <div className="flex items-center space-x-2 py-2">
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Filter:</span>
          <div className="flex space-x-1.5">
            {['All', 'Active', 'Settled', 'Overdue'].map((f) => (
              <button key={f} onClick={() => setStatusFilter(f as any)} className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all border ${statusFilter === f ? 'bg-[#B8A17D] text-white border-[#B8A17D]' : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'}`}>{f}</button>
            ))}
          </div>
        </div>
        <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
      </main>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              setRecords(next);
              syncRecordToCloud(updated, next);
            }}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => {
        const next = [newRecord, ...records];
        setRecords(next);
        syncRecordToCloud(newRecord, next);
        setIsAddingRecord(false);
      }} />
      <UserManagementModal isOpen={isManagingUsers} onClose={() => setIsManagingUsers(false)} />
    </div>
  );
};

