  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  Pin,
  AlertTriangle,
  Share2,
  Check,
  Eye,
  Trash2,
  Maximize2
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, SystemNote } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';
import RecordFormModal from './RecordFormModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onUpdateRecord: (record: LedgerRecord) => void;
}

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onUpdateRecord
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');

  // Modal States
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [editingItem, setEditingItem] = useState<PurchaseItem | null>(null);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | null>(null);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [selectedItemPreview, setSelectedItemPreview] = useState<PurchaseItem | null>(null);

  const [copied, setCopied] = useState(false);
  const [shareError, setShareError] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment', id: string } | null>(null);

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  // Timeline Logic
  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const unitText = record.paymentCycle === 'Day' ? 'days' : record.paymentCycle === 'Weekly' ? 'weeks' : 'months';
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    return [{
      id: 'reminder-pinned-calc',
      timestamp: nextDate.toDateString(),
      content: `JAYTIN Protocol [${record.paymentCycle} Cycle ${currentPeriod}/${totalPeriods}]: RM${record.totalAmount.toLocaleString()} / ${totalPeriods} ${unitText} = RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due. Next deadline: ${nextDate.toLocaleDateString()}.`,
      isPinned: true
    }];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...(record.notes || [])], [pinnedReminders, record.notes]);
  const displayedTimeline = useMemo(() => timelineNotes, [timelineNotes]);

  const createLogEntry = (content: string): SystemNote => ({
    id: `N-${Date.now()}`,
    timestamp: new Date().toLocaleString(),
    content
  });

  // HANDLERS
  const handleAddItem = (item: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = [...safeItems, { ...item, id: item.id || `I-${Date.now()}` }];
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Secured: ${item.name} (+RM ${item.amount.toLocaleString()})`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setIsAddingItem(false);
  };

  const handleEditItem = (updated: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = safeItems.map(i => i.id === updated.id ? updated : i);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Refined: ${updated.name}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setEditingItem(null);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = record.items.find(i => i.id === id);
    const safeItems = record.items || [];
    const newItems = safeItems.filter(i => i.id !== id);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Purged: ${itemToDelete?.name || 'Unknown'}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setConfirmDelete(null);
  };

  const handleAddPayment = (payment: any) => {
    const newPaymentObj: PaymentRecord = { ...payment, id: `P-${Date.now()}` };
    const safePayments = record.payments || [];
    const newPayments = [newPaymentObj, ...safePayments];
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Capital Injection Detected: RM ${payment.amount.toLocaleString()} via ${payment.method}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setIsRecordingPayment(false);
  };

  const handleEditPayment = (updated: PaymentRecord) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.map(p => p.id === updated.id ? updated : p);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Record Refined: RM ${updated.amount.toLocaleString()}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setEditingPayment(null);
  };

  const handleDeletePayment = (id: string) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.filter(p => p.id !== id);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Purged from Ledger`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setConfirmDelete(null);
  };

  const handleAddEvidence = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      const newAttachment: Attachment = {
        id: `A-E-${Date.now()}`,
        name: `Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      };
      const safeAttachments = record.attachments || [];
      const newNotes = [createLogEntry(`Visual Evidence Archived`), ...(record.notes || [])];
      onUpdateRecord({ ...record, attachments: [newAttachment, ...safeAttachments], notes: newNotes });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareKey = record.shareKey;

    // 如果没有 shareKey（老数据），引导用户点一下编辑保存来生成
    if (!shareKey || shareKey === 'ERROR') {
      setShareError(true);
      setTimeout(() => setShareError(false), 3000);
      return;
    }

    const shareUrl = `${window.location.origin}${window.location.pathname}#/share/${shareKey}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') handleDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') handleDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      const safeAttachments = record.attachments || [];
      onUpdateRecord({ ...record, attachments: safeAttachments.filter(a => a.id !== confirmDelete.id) });
      setSelectedAttachment(null);
      setConfirmDelete(null);
    }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-4 md:p-8">
      <motion.div initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }} className="glass-card w-full max-w-6xl h-full max-h-[92vh] rounded-[48px] overflow-hidden border border-white/60 flex flex-col relative shadow-2xl">

        {/* Detail Header */}
        <div className="p-10 pb-6 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button type="button" onClick={onClose} className="absolute top-10 right-10 p-3 hover:bg-white/50 rounded-full transition-all group z-10 hover:rotate-90">
            <X className="w-7 h-7 text-gray-400 group-hover:text-black" />
          </button>

          <div className="flex-1 space-y-4">
            <div className="flex flex-wrap items-center gap-3">
              <span className="text-[11px] font-jua text-[#B8A17D] uppercase tracking-[0.4em] block">JAYTIN TEAM</span>
              <div className="px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest bg-white/40 border border-[#B8A17D]/20 text-gray-600 shadow-sm">{record.type}</div>
              <div className={`px-4 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest border border-[#B8A17D]/30 shadow-sm flex items-center ${record.status === 'Overdue' ? 'bg-red-500 text-white' : record.status === 'Settled' ? 'bg-[#333] text-white' : 'bg-white/60 text-gray-800'}`}>
                <span className={`w-1.5 h-1.5 rounded-full mr-2 ${record.status === 'Overdue' ? 'bg-white animate-pulse' : 'bg-[#B8A17D]'}`} />
                {record.status}
              </div>
            </div>

            <div className="flex items-center space-x-5">
              <h2 className="text-4xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
              {!isViewOnly && (
                <motion.button type="button" whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }} onClick={() => setIsEditingProfile(true)} className="p-2.5 bg-white/40 border border-white/60 rounded-xl text-[#B8A17D] hover:bg-white/60 transition-colors shadow-sm">
                  <Edit2 className="w-4.5 h-4.5" />
                </motion.button>
              )}
              <motion.button type="button" whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }} onClick={handleShare} className={`p-2.5 bg-white/40 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 ${copied ? 'text-green-600' : shareError ? 'text-red-500' : 'text-[#B8A17D] hover:bg-white/60'}`}>
                {copied ? <Check className="w-4.5 h-4.5" /> : shareError ? <AlertTriangle className="w-4.5 h-4.5 animate-bounce" /> : <Share2 className="w-4.5 h-4.5" />}
                <span className="text-[10px] font-bold uppercase tracking-widest pr-1">
                  {copied ? 'Linked' : shareError ? 'Refine Required' : 'Share'}
                </span>
              </motion.button>
              <AnimatePresence>
                {shareError && (
                  <motion.p initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0 }} className="text-[9px] text-red-500 font-bold uppercase tracking-widest bg-red-50 px-3 py-1.5 rounded-full border border-red-100">
                    Legacy Artifact: Click Edit & Save once to generate link.
                  </motion.p>
                )}
              </AnimatePresence>
            </div>
            <div className="flex flex-col space-y-1">
              <p className="text-[11px] text-gray-400 tracking-[0.2em] font-mono">Protocol ID: {record.id}</p>
              <div className="flex items-center space-x-4 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Start: {record.startDate}</span>
                {record.endDate && <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5 text-[#B8A17D]"/> Maturity: {record.endDate}</span>}
              </div>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-white/30 border border-white/40 shadow-inner space-y-4">
            <div className="flex justify-between items-end mb-1">
              <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Fulfillment Scope</span>
              <span className="text-base font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-2 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="text-left"><p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Preserved</p><p className="text-xl font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Outstanding</p><p className="text-xl font-jua text-[#B8A17D]">RM{Math.max(0, record.totalAmount - record.paidAmount).toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex px-12 border-b border-white/10">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} type="button" onClick={() => setActiveTab(tab as any)} className={`py-6 px-8 text-xs font-bold uppercase tracking-[0.3em] transition-all relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400 hover:text-gray-600'}`}>
              {tab}{activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[4px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-12 pt-10 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center justify-between">
                    <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                    {!isViewOnly && <button type="button" onClick={() => setIsAddingEvidence(true)} className="text-[10px] text-[#B8A17D] font-bold uppercase hover:underline">+ Archive</button>}
                  </h4>
                  {isAddingEvidence && !isViewOnly && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="mb-6 p-6 rounded-3xl bg-white/20 border border-[#B8A17D]/30 space-y-4">
                      <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (file) {
                          const reader = new FileReader();
                          reader.onloadend = () => setEvidenceImage(reader.result as string);
                          reader.readAsDataURL(file);
                        }
                      }} />
                      <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-40 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-400 overflow-hidden relative">
                        {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-30" />}
                      </button>
                      <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/30 rounded-xl p-4 text-xs focus:outline-none min-h-[100px] border border-white/20" />
                      <button type="button" onClick={handleAddEvidence} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black">Archive Evidence</button>
                    </motion.div>
                  )}
                  <div className="grid grid-cols-2 gap-4">
                    {(record.attachments || []).map(att => (
                      <div key={att.id} onClick={() => setSelectedAttachment(att)} className="relative group bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/60 transition-all shadow-sm">
                        <div className="h-24 bg-gray-50 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                        <div className="p-3"><p className="text-[9px] text-gray-500 italic truncate">{att.description || 'No memo.'}</p></div>
                        {!isViewOnly && <button type="button" onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'attachment', id: att.id }); }} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-3 h-3" /></button>}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-[0.25em] mb-5 flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[15px] before:top-2 before:bottom-0 before:w-[2px] before:bg-white/40">
                  {displayedTimeline.map((note) => (
                    <div key={note.id} className={`relative pl-12 ${note.isPinned ? 'z-20' : ''}`}>
                      <div className={`absolute left-0 top-1.5 w-[32px] h-[32px] rounded-full border flex items-center justify-center z-10 shadow-md ${note.isPinned ? 'bg-black border-[#B8A17D] text-[#B8A17D]' : 'bg-[#EBFAFF] border-[#B8A17D]/50 text-[#B8A17D]'}`}>
                        {note.isPinned ? <Pin className="w-3.5 h-3.5" /> : <Clock className="w-3.5 h-3.5" />}
                      </div>
                      <p className={`text-[10px] font-bold tracking-tight mb-1 uppercase ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>{note.isPinned ? 'Protocol Reminders' : note.timestamp}</p>
                      <p className={`text-[14px] font-medium p-3 rounded-2xl border ${note.isPinned ? 'bg-[#333]/90 text-white border-[#B8A17D]/50 shadow-xl' : 'bg-white/20 text-gray-700 border-white/30'}`}>{note.content}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-10">
              {!isViewOnly && (
                <motion.button type="button" whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setIsAddingItem(true)} className="w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] gold-glow">
                  <ShoppingBag className="w-5 h-5" /><span>Declare New Asset Entry</span>
                </motion.button>
              )}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {(record.items || []).map(item => (
                  <div key={item.id} className="glass-card p-8 rounded-[32px] border border-white/50 hover:border-[#B8A17D]/50 transition-all cursor-pointer group shadow-sm hover:bg-white/40 relative">
                    <div onClick={() => setSelectedItemPreview(item)} className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="p-4 bg-white/50 rounded-2xl mr-5 group-hover:bg-[#B8A17D]/10"><ShoppingBag className="w-6 h-6 text-gray-400 group-hover:text-[#B8A17D]" /></div>
                        <div><span className="text-xl font-bold text-[#333] block tracking-tight group-hover:text-black">{item.name}</span><span className="text-[11px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span></div>
                      </div>
                      <span className="text-2xl font-jua text-[#333] tracking-tighter">RM{item.amount.toLocaleString()}</span>
                    </div>
                    {!isViewOnly && (
                      <div className="absolute bottom-6 right-8 flex space-x-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button type="button" onClick={(e) => { e.stopPropagation(); setEditingItem(item); }} className="p-2 text-gray-400 hover:text-blue-500"><Edit2 className="w-4 h-4" /></button>
                        <button type="button" onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'item', id: item.id }); }} className="p-2 text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-4xl mx-auto space-y-8">
              {!isViewOnly && (
                <motion.button type="button" whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setIsRecordingPayment(true)} disabled={record.status === 'Settled'} className={`w-full py-6 rounded-[32px] font-bold text-sm uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 mb-10 ${record.status === 'Settled' ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-[#333] text-white border-[#B8A17D] gold-glow'}`}>
                  <CreditCard className="w-5 h-5" /><span>Execute Capital Injection</span>
                </motion.button>
              )}
              <div className="space-y-8 relative before:absolute before:left-[47px] before:top-4 before:bottom-0 before:w-[1px] before:bg-[#B8A17D]/20">
                {(record.payments || []).map((payment) => (
                  <div key={payment.id} className="flex items-start space-x-8 relative group">
                    <div className="flex-none w-24 pt-4 text-right"><span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{payment.date}</span></div>
                    <div className="flex-none w-[32px] h-[32px] rounded-full border border-[#B8A17D]/40 bg-white flex items-center justify-center relative z-10 shadow-sm transition-transform group-hover:scale-110"><div className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" /></div>
                    <div className="flex-1 bg-white/40 border border-white/60 p-6 rounded-[28px] hover:bg-white/60 transition-all shadow-sm relative">
                      <div className="flex justify-between items-start mb-4">
                        <div><span className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-widest block mb-1">{payment.method} Protocol</span><span className="text-xl font-jua text-green-600/90 tracking-tighter">Injection: RM{payment.amount.toLocaleString()}</span></div>
                        {!isViewOnly && (
                          <div className="flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button type="button" onClick={() => setEditingPayment(payment)} className="p-2 text-gray-400 hover:text-blue-500 transition-colors"><Edit2 className="w-4 h-4" /></button>
                            <button type="button" onClick={() => setConfirmDelete({ type: 'payment', id: payment.id })} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                          </div>
                        )}
                      </div>
                      {payment.note && <p className="text-[13px] text-gray-600 italic leading-relaxed bg-white/30 p-3 rounded-xl border border-white/20 mb-4">{payment.note}</p>}
                      {payment.attachment && (
                        <div onClick={() => setSelectedAttachment(payment.attachment!)} className="w-full h-32 rounded-xl overflow-hidden cursor-pointer border border-white/40 group/img">
                          <img src={payment.attachment.data} className="w-full h-full object-cover group-hover/img:scale-105 transition-transform" />
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Modals */}
        <AnimatePresence>
          {isEditingProfile && !isViewOnly && <RecordFormModal isOpen={true} onClose={() => setIsEditingProfile(false)} onSave={(updated) => { onUpdateRecord(updated); setIsEditingProfile(false); }} initialData={record} />}
          {(isAddingItem || editingItem) && !isViewOnly && <AddItemModal isOpen={true} initialData={editingItem || undefined} onClose={() => { setIsAddingItem(false); setEditingItem(null); }} onSubmit={(item) => editingItem ? handleEditItem(item) : handleAddItem(item)} />}
          {(isRecordingPayment || editingPayment) && !isViewOnly && <PaymentModal isOpen={true} initialData={editingPayment || undefined} onClose={() => { setIsRecordingPayment(false); setEditingPayment(null); }} onSubmit={(p) => editingPayment ? handleEditPayment({ ...editingPayment, ...p }) : handleAddPayment(p)} maxAmount={999999999} />}
          {selectedItemPreview && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[150] flex items-center justify-center bg-black/40 backdrop-blur-2xl p-4 md:p-12" onClick={() => setSelectedItemPreview(null)}>
              <motion.div initial={{ scale: 0.9, y: 40 }} animate={{ scale: 1, y: 0 }} className="glass-card w-full max-w-2xl rounded-[48px] overflow-hidden border border-white/60 bg-white shadow-2xl relative" onClick={e => e.stopPropagation()}>
                 <button type="button" onClick={() => setSelectedItemPreview(null)} className="absolute top-8 right-8 p-3 hover:bg-gray-100 rounded-full transition-all z-10"><X className="w-6 h-6 text-gray-400" /></button>
                 <div className="p-12 space-y-8">
                    <div className="flex justify-between items-end border-b border-gray-100 pb-8">
                       <div className="space-y-2"><span className="text-[11px] font-bold text-[#B8A17D] uppercase tracking-[0.4em]">Asset Artifact</span><h2 className="text-4xl font-jua text-[#333]">{selectedItemPreview.name}</h2><div className="text-[10px] text-gray-400 uppercase font-bold tracking-widest flex items-center"><Calendar className="w-3.5 h-3.5 mr-1 text-[#B8A17D]" /> {selectedItemPreview.date}</div></div>
                       <div className="text-right"><span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block mb-1">Valuation</span><span className="text-4xl font-jua text-[#333]">RM{selectedItemPreview.amount.toLocaleString()}</span></div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-start">
                       <div><h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-3 flex items-center"><FileText className="w-3.5 h-3.5 mr-2 text-[#B8A17D]" /> Annotation</h4><p className="text-sm text-gray-600 leading-relaxed bg-gray-50/50 p-6 rounded-3xl border border-gray-100 italic">{selectedItemPreview.note || "No memo."}</p></div>
                       {selectedItemPreview.attachment && (
                          <div className="space-y-4">
