  const [copied, setCopied] = useState(false);
  const [shareError, setShareError] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment', id: string } | null>(null);

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    return [{
      id: 'reminder-pinned-calc',
      timestamp: nextDate.toDateString(),
      content: `[Cycle ${currentPeriod}/${totalPeriods}]: RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due. Next deadline: ${nextDate.toLocaleDateString()}.`,
      isPinned: true
    }];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...(record.notes || [])], [pinnedReminders, record.notes]);

  const createLogEntry = (content: string): SystemNote => ({
    id: `N-${Date.now()}`,
    timestamp: new Date().toLocaleString(),
    content
  });

  const handleAddItem = (item: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = [...safeItems, { ...item, id: item.id || `I-${Date.now()}` }];
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Secured: ${item.name} (+RM ${item.amount.toLocaleString()})`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setIsAddingItem(false);
  };

  const handleEditItem = (updated: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = safeItems.map(i => i.id === updated.id ? updated : i);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Refined: ${updated.name}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setEditingItem(null);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = record.items.find(i => i.id === id);
    const safeItems = record.items || [];
    const newItems = safeItems.filter(i => i.id !== id);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Purged: ${itemToDelete?.name || 'Unknown'}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setConfirmDelete(null);
  };

  const handleAddPayment = (payment: any) => {
    const newPaymentObj: PaymentRecord = { ...payment, id: `P-${Date.now()}` };
    const safePayments = record.payments || [];
    const newPayments = [newPaymentObj, ...safePayments];
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection: RM ${payment.amount.toLocaleString()} via ${payment.method}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setIsRecordingPayment(false);
  };

  const handleEditPayment = (updated: PaymentRecord) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.map(p => p.id === updated.id ? updated : p);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Refined: RM ${updated.amount.toLocaleString()}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setEditingPayment(null);
  };

  const handleDeletePayment = (id: string) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.filter(p => p.id !== id);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Purged from Ledger`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setConfirmDelete(null);
  };

  const handleAddEvidence = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      const newAttachment: Attachment = {
        id: `A-E-${Date.now()}`,
        name: `Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      };
      const safeAttachments = record.attachments || [];
      const newNotes = [createLogEntry(`Visual Evidence Archived`), ...(record.notes || [])];
      onUpdateRecord({ ...record, attachments: [newAttachment, ...safeAttachments], notes: newNotes });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareKey = record.shareKey;
    if (!shareKey || shareKey === 'ERROR') {
      setShareError(true);
      setTimeout(() => setShareError(false), 3000);
      return;
    }
    const shareUrl = `${window.location.origin}${window.location.pathname}#/share/${shareKey}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') handleDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') handleDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      const safeAttachments = record.attachments || [];
      onUpdateRecord({ ...record, attachments: safeAttachments.filter(a => a.id !== confirmDelete.id) });
      setSelectedAttachment(null);
      setConfirmDelete(null);
    }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-0 md:p-8">
      <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} transition={{ type: 'spring', damping: 25, stiffness: 200 }} className="glass-card w-full max-w-6xl h-full md:h-full md:max-h-[92vh] md:rounded-[48px] overflow-hidden border-t md:border border-white/60 flex flex-col relative shadow-2xl">

        {/* Detail Header */}
        <div className="p-6 md:p-10 pb-4 relative flex flex-col md:flex-row justify-between items-start gap-6 md:gap-8">
          <button type="button" onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/40 hover:bg-white/60 rounded-full transition-all active-scale z-10 shadow-sm border border-white/40">
            <X className="w-6 h-6 text-gray-400" />
          </button>

          <div className="flex-1 space-y-3 w-full pr-12 md:pr-0">
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-[10px] font-jua text-[#B8A17D] uppercase tracking-[0.3em]">JAYTIN PROTOCOL</span>
              <div className="px-2.5 py-1 rounded-lg text-[8px] font-bold uppercase tracking-widest bg-white/40 border border-white/60 text-gray-500">{record.type}</div>
            </div>

            <div className="flex flex-col space-y-2">
              <h2 className="text-3xl md:text-5xl font-jua text-[#333] tracking-tight truncate leading-none">{record.userName}</h2>
              <div className="flex items-center gap-2">
                {!isViewOnly && (
                  <button type="button" onClick={() => setIsEditingProfile(true)} className="p-2 bg-white/50 border border-white/60 rounded-xl text-[#B8A17D] active-scale shadow-sm">
                    <Edit2 className="w-4 h-4" />
                  </button>
                )}
                <button type="button" onClick={handleShare} className={`px-4 py-2 bg-white/50 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 active-scale ${copied ? 'text-green-600' : shareError ? 'text-red-500' : 'text-[#B8A17D]'}`}>
                  {copied ? <Check className="w-4 h-4" /> : shareError ? <AlertTriangle className="w-4 h-4" /> : <Share2 className="w-4 h-4" />}
                  <span className="text-[10px] font-bold uppercase tracking-widest">{copied ? 'Linked' : 'Share'}</span>
                </button>
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-[9px] text-gray-400 font-bold uppercase tracking-widest pt-1">
              <span className="flex items-center"><Calendar className="w-3 h-3 mr-1 text-[#B8A17D]"/> {record.startDate}</span>
              <span className="opacity-40">#{record.id}</span>
            </div>
          </div>

          <div className="w-full md:w-96 p-5 md:p-6 rounded-[28px] bg-white/30 border border-white/50 shadow-inner space-y-4">
            <div className="flex justify-between items-end">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Progress</span>
              <span className="text-sm font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-1.5 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4 pt-1">
              <div className="text-left"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Paid</p><p className="text-lg font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Due</p><p className="text-lg font-jua text-[#B8A17D]">RM{Math.max(0, record.totalAmount - record.paidAmount).toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tabs - Scrollable on mobile */}
        <div className="flex px-4 md:px-12 border-b border-white/10 overflow-x-auto hide-scrollbar">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} type="button" onClick={() => setActiveTab(tab as any)} className={`py-5 px-6 md:px-8 text-[10px] font-bold uppercase tracking-[0.3em] transition-all relative shrink-0 ${activeTab === tab ? 'text-[#333]' : 'text-gray-400'}`}>
              {tab}{activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[3px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 pt-8 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 md:gap-16">
              {/* Evidence Section */}
              <div className="space-y-8">
                <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.25em] flex items-center justify-between">
                  <span className="flex items-center"><ImageIcon className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Evidence Artifacts</span>
                  {!isViewOnly && <button type="button" onClick={() => setIsAddingEvidence(true)} className="text-[9px] text-[#B8A17D] font-bold uppercase active-scale">+ Archive</button>}
                </h4>

                {isAddingEvidence && !isViewOnly && (
                  <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="p-5 rounded-3xl bg-white/30 border border-[#B8A17D]/30 space-y-4">
                    <input type="file" ref={evidenceInputRef} className="hidden" accept="image/*" onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) {
                        const reader = new FileReader();
                        reader.onloadend = () => setEvidenceImage(reader.result as string);
                        reader.readAsDataURL(file);
                      }
                    }} />
                    <button type="button" onClick={() => evidenceInputRef.current?.click()} className="w-full h-36 border-2 border-dashed border-[#B8A17D]/20 rounded-2xl flex flex-col items-center justify-center text-gray-300 overflow-hidden relative active-scale">
                      {evidenceImage ? <img src={evidenceImage} className="w-full h-full object-cover" /> : <ImageIcon className="w-8 h-8 opacity-20" />}
                    </button>
                    <textarea placeholder="Evidence Note" value={evidenceNote} onChange={(e) => setEvidenceNote(e.target.value)} className="w-full bg-white/40 border border-white/60 rounded-xl p-4 text-xs focus:outline-none min-h-[80px]" />
                    <button type="button" onClick={handleAddEvidence} className="w-full bg-[#333] text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest active-scale">Archive Artifact</button>
                  </motion.div>
                )}

                <div className="grid grid-cols-2 md:grid-cols-2 gap-3 md:gap-4">
                  {(record.attachments || []).map(att => (
                    <div key={att.id} onClick={() => setSelectedAttachment(att)} className="relative group bg-white/30 border border-white/50 rounded-2xl overflow-hidden cursor-pointer hover:border-[#B8A17D]/50 transition-all active-scale shadow-sm">
                      <div className="h-28 bg-white/40 flex items-center justify-center">{att.data ? <img src={att.data} className="w-full h-full object-cover" /> : <FileText className="w-6 h-6 text-gray-200" />}</div>
                      {!isViewOnly && <button type="button" onClick={(e) => { e.stopPropagation(); setConfirmDelete({ type: 'attachment', id: att.id }); }} className="absolute top-2 right-2 p-1.5 bg-red-500/80 backdrop-blur-md text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-3 h-3" /></button>}
                    </div>
                  ))}
                </div>
              </div>

              {/* Timeline Section */}
              <div className="space-y-8">
                <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.25em] flex items-center"><FileEdit className="w-4 h-4 mr-2.5 text-[#B8A17D]" /> Ledger Timeline</h4>
                <div className="space-y-6 relative before:absolute before:left-[17px] before:top-2 before:bottom-0 before:w-[1px] before:bg-white/60">
                  {timelineNotes.map((note) => (
                    <div key={note.id} className="relative pl-12">
                      <div className={`absolute left-0 top-1 w-[34px] h-[34px] rounded-full border-2 flex items-center justify-center z-10 shadow-sm transition-all ${note.isPinned ? 'bg-[#333] border-[#B8A17D] text-[#B8A17D] scale-110' : 'bg-white border-white/60 text-gray-300'}`}>
                        {note.isPinned ? <Pin className="w-4 h-4" /> : <Clock className="w-4 h-4" />}
                      </div>
                      <p className={`text-[8px] font-bold uppercase tracking-[0.2em] mb-1 ${note.isPinned ? 'text-[#B8A17D]' : 'text-gray-400'}`}>{note.isPinned ? 'Priority Protocol' : note.timestamp}</p>
                      <p className={`text-xs p-4 rounded-2xl border ${note.isPinned ? 'bg-[#333]/95 text-white border-[#B8A17D]/30 shadow-xl' : 'bg-white/30 text-gray-600 border-white/60'}`}>{note.content}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="max-w-4xl mx-auto space-y-8">
              {!isViewOnly && (
                <motion.button whileTap={{ scale: 0.98 }} onClick={() => setIsAddingItem(true)} className="w-full py-5 rounded-3xl font-bold text-[10px] uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 bg-[#333] text-white border-[#B8A17D] gold-glow active-scale">
                  <ShoppingBag className="w-5 h-5" /><span>Add Asset Entry</span>
                </motion.button>
              )}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
                {(record.items || []).map(item => (
                  <div key={item.id} onClick={() => setSelectedItemPreview(item)} className="glass-card p-6 rounded-[28px] border border-white/50 hover:border-[#B8A17D]/40 transition-all cursor-pointer group shadow-sm active-scale relative">
                    <div className="flex justify-between items-start">
                      <div className="space-y-1">
                        <span className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{item.date}</span>
                        <h4 className="text-lg font-bold text-[#333] tracking-tight">{item.name}</h4>
                      </div>
                      <span className="text-xl font-jua text-[#333]">RM{item.amount.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="max-w-3xl mx-auto space-y-10">
              {!isViewOnly && (
                <motion.button whileTap={{ scale: 0.98 }} onClick={() => setIsRecordingPayment(true)} disabled={record.status === 'Settled'} className={`w-full py-5 rounded-3xl font-bold text-[10px] uppercase tracking-[0.4em] shadow-xl transition-all border flex items-center justify-center space-x-3 ${record.status === 'Settled' ? 'bg-gray-100 text-gray-400 border-gray-200' : 'bg-[#333] text-white border-[#B8A17D] gold-glow active-scale'}`}>
                  <CreditCard className="w-5 h-5" /><span>Execute Injection</span>
                </motion.button>
              )}
              <div className="space-y-6 relative before:absolute before:left-[47px] before:top-4 before:bottom-0 before:w-[1px] before:bg-white/60">
                {(record.payments || []).map((payment) => (
                  <div key={payment.id} className="flex items-start space-x-6 relative group">
                    <div className="flex-none w-12 pt-3 text-right"><span className="text-[8px] font-bold text-gray-400 uppercase tracking-widest leading-none block">{payment.date.split('-')[1]}<br/>{payment.date.split('-')[2]}</span></div>
                    <div className="flex-none w-[34px] h-[34px] rounded-full border border-white/60 bg-white flex items-center justify-center relative z-10 shadow-sm group-hover:border-[#B8A17D] transition-colors"><div className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" /></div>
                    <div className="flex-1 bg-white/40 border border-white/60 p-5 rounded-[24px] group-hover:bg-white/60 transition-all shadow-sm">
                      <div className="flex justify-between items-center mb-1">
                         <span className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-widest">{payment.method}</span>
                         <span className="text-lg font-jua text-green-600/80 tracking-tighter">RM{payment.amount.toLocaleString()}</span>
                      </div>
                      {payment.note && <p className="text-[11px] text-gray-500 italic mt-2 opacity-80">{payment.note}</p>}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Floating Modals Overlays */}
        <AnimatePresence>
          {isEditingProfile && !isViewOnly && <RecordFormModal isOpen={true} onClose={() => setIsEditingProfile(false)} onSave={(updated) => { onUpdateRecord(updated); setIsEditingProfile(false); }} initialData={record} />}
          {(isAddingItem || editingItem) && !isViewOnly && <AddItemModal isOpen={true} initialData={editingItem || undefined} onClose={() => { setIsAddingItem(false); setEditingItem(null); }} onSubmit={(item) => editingItem ? handleEditItem(item) : handleAddItem(item)} />}
          {(isRecordingPayment || editingPayment) && !isViewOnly && <PaymentModal isOpen={true} initialData={editingPayment || undefined} onClose={() => { setIsRecordingPayment(false); setEditingPayment(null); }} onSubmit={(p) => editingPayment ? handleEditPayment({ ...editingPayment, ...p }) : handleAddPayment(p)} maxAmount={999999999} />}
          {selectedItemPreview && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[150] flex items-center justify-center bg-black/30 backdrop-blur-xl p-4" onClick={() => setSelectedItemPreview(null)}>
              <motion.div initial={{ scale: 0.9, y: 30 }} animate={{ scale: 1, y: 0 }} className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden p-8 border border-white shadow-2xl relative bg-white/95" onClick={e => e.stopPropagation()}>
                 <button type="button" onClick={() => setSelectedItemPreview(null)} className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full active-scale"><X className="w-5 h-5 text-gray-400" /></button>
                 <div className="space-y-6">
                    <div className="border-b border-gray-100 pb-6">
                       <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em] mb-1">Asset Detail</p>
                       <h2 className="text-2xl font-jua text-[#333] mb-4">{selectedItemPreview.name}</h2>
                       <div className="flex justify-between items-end">
                          <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{selectedItemPreview.date}</span>
                          <span className="text-3xl font-jua text-[#333]">RM{selectedItemPreview.amount.toLocaleString()}</span>
                       </div>
                    </div>
                    {selectedItemPreview.note && <div className="p-5 bg-gray-50/50 rounded-2xl border border-gray-100 italic text-xs text-gray-600">{selectedItemPreview.note}</div>}
                    {selectedItemPreview.attachment && <div className="rounded-2xl overflow-hidden border border-gray-200"><img src={selectedItemPreview.attachment.data} className="w-full h-auto" /></div>}
                    {!isViewOnly && (
                      <div className="flex gap-3 pt-2">
                        <button onClick={() => setEditingItem(selectedItemPreview)} className="flex-1 py-4 bg-[#333] text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest active-scale">Edit</button>
                        <button onClick={() => setConfirmDelete({ type: 'item', id: selectedItemPreview.id })} className="px-5 py-4 border border-red-200 text-red-500 rounded-2xl active-scale"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
                 </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    </motion.div>
  );
};

export default CustomerDetail;

import React from 'react';
