        icon={<DollarSign className="w-5 h-5 text-[#B8A17D]" />}
        delay={0}
      />
      <StatCard 
        label="Active Protocol" 
        value={stats.activeCustomers.toString()} 
        icon={<UserCheck className="w-5 h-5 text-[#B8A17D]" />}
        delay={0.05}
      />
      <StatCard 
        label="Monthly Collected" 
        value={`RM${stats.collectedThisMonth.toLocaleString()}`} 
        icon={<BarChart3 className="w-5 h-5 text-[#B8A17D]" />}
        delay={0.1}
