    <div className="relative z-10 space-y-1">
      <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-1">{label}</p>
      <h3 className="text-2xl md:text-3xl font-jua text-[#333] tracking-tight">{value}</h3>
      <div className="h-1 w-6 bg-[#B8A17D]/40 rounded-full mt-3" />
    </div>
  </motion.div>
);

export default Dashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle,
  Users,
  Globe,
  CloudCheck,
  RefreshCw
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import UserManagementModal from './components/UserManagementModal';
import Login from './components/Login';
import { supabase } from './supabase';

const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  if (errMsg.includes('relation "public.ledgers" does not exist')) return "Database Schema Missing.";
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => localStorage.getItem('jaytin_auth') === 'true');
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  const [publicRecord, setPublicRecord] = useState<LedgerRecord | null>(null);
  const [isPublicMode, setIsPublicMode] = useState(() => window.location.hash.startsWith('#/share/'));

  // 用于防抖云同步的 Ref
  const syncTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    const handleRoute = async () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/share/')) {
        const key = hash.replace('#/share/', '');
        if (key && key.length >= 32) {
          setIsPublicMode(true);
          setIsLoading(true);
          try {
            const { data, error } = await supabase
              .from('ledgers')
              .select('record')
              .eq('record->>shareKey', key)
              .maybeSingle();

            if (data) {
              setPublicRecord(data.record as LedgerRecord);
            } else {
              setPublicRecord(null);
            }
          } catch (e) {
            console.error("Vault access failure", e);
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsPublicMode(false);
          setPublicRecord(null);
        }
      } else {
        setIsPublicMode(false);
        setPublicRecord(null);
      }
    };

    handleRoute();
    window.addEventListener('hashchange', handleRoute);
    return () => window.removeEventListener('hashchange', handleRoute);
  }, []);

  useEffect(() => {
    if (isPublicMode) return;
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        setRecords(JSON.parse(saved));
        setIsLoading(false);
      } catch (e) { console.warn(e); }
    }
  }, [isPublicMode]);

  const fetchFromCloud = async () => {
    if (isPublicMode || !isAuthenticated) return;
    setSyncError(null);
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;
      if (data) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
        setLastSynced(new Date());
      }
    } catch (e: any) {
      setSyncError(stringifyError(e));
    } finally {
      setIsLoading(false);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated && !isPublicMode) {
      fetchFromCloud();
    } else if (!isPublicMode) {
      setIsLoading(false);
    }
  }, [isAuthenticated, isPublicMode]);

  // 核心自动同步逻辑
  const syncAllToCloud = async (currentRecords: LedgerRecord[]) => {
    if (!isAuthenticated || isPublicMode) return;
    setIsSyncing(true);
    setSyncError(null);
    try {
      // 执行批量 upsert
      const payloads = currentRecords.map(r => ({
        id: r.id,
        record: r,
        updated_at: new Date().toISOString()
      }));

      const { error } = await supabase.from('ledgers').upsert(payloads);
      if (error) throw error;
      setLastSynced(new Date());
    } catch (e: any) {
      setSyncError(`Sync Lag: ${stringifyError(e)}`);
    } finally {
      setIsSyncing(false);
    }
  };

  // 监听记录变化并防抖自动同步
  const handleRecordUpdate = (newRecords: LedgerRecord[]) => {
    setRecords(newRecords);
    localStorage.setItem('jaytin_ledgers', JSON.stringify(newRecords));

    if (syncTimeoutRef.current) window.clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = window.setTimeout(() => {
      syncAllToCloud(newRecords);
    }, 1500); // 1.5秒无操作后自动同步
  };

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('username', user).eq('password', pass).single();
      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e) { return false; }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
    localStorage.removeItem('jaytin_ledgers');
    setRecords([]);
    window.location.hash = '';
  };

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF]">
        <Loader2 className="w-10 h-10 text-[#B8A17D] animate-spin" />
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.4em] mt-6">Handshaking Protocol...</p>
      </div>
    );
  }

  if (isPublicMode) {
    if (publicRecord) {
      return (
        <div className="min-h-screen bg-[#EBFAFF]">
          <CustomerDetail record={publicRecord} isViewOnly={true} onClose={() => { window.location.hash = ''; }} onUpdateRecord={() => {}} />
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 bg-[#333]/90 backdrop-blur-xl rounded-full border border-white/10 shadow-2xl">
             <p className="text-[10px] text-white font-bold uppercase tracking-[0.3em] flex items-center">
               <Globe className="w-3.5 h-3.5 mr-2.5 text-[#B8A17D]" /> Safe View Mode
             </p>
          </div>
        </div>
      );
    } else {
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF] p-10 text-center">
          <AlertCircle className="w-16 h-16 text-red-300 mb-8" />
          <h2 className="text-3xl font-jua text-gray-800">Protocol Expired</h2>
          <p className="text-sm text-gray-400 mt-4 leading-relaxed">The requested financial record is no longer accessible or the link is invalid.</p>
          <button onClick={() => window.location.hash = ''} className="mt-10 px-10 py-4 bg-[#999] text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest active-scale">Return to Terminal</button>
        </div>
      );
    }
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col space-y-6 mb-12">
        <div className="flex justify-between items-center">
          <div className="relative group">
            <h1 className="text-3xl md:text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
            <div className="flex items-center space-x-2 mt-1.5">
               <ShieldCheck className="w-3.5 h-3.5 text-[#B8A17D]" />
               <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#B8A17D]">Vault Secure</p>

               {/* 自动同步指示器 */}
               <div className="flex items-center ml-2 space-x-1 bg-white/40 px-2 py-0.5 rounded-full border border-white/60">
                 {isSyncing ? (
                   <RefreshCw className="w-2.5 h-2.5 text-[#B8A17D] animate-spin" />
                 ) : (
                   <CloudCheck className="w-2.5 h-2.5 text-green-500/70" />
                 )}
                 <span className="text-[8px] font-bold uppercase tracking-tighter text-gray-400">
                   {isSyncing ? 'Syncing' : 'Auto-Saved'}
                 </span>
               </div>
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsManagingUsers(true)} className="p-2.5 text-[#B8A17D] bg-white/40 rounded-xl border border-white/60 shadow-sm active-scale"><Users className="w-5 h-5" /></motion.button>
            <motion.button whileTap={{ scale: 0.9 }} onClick={handleLogout} className="p-3 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20 active-scale"><LogOut className="w-5 h-5" /></motion.button>
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input type="text" placeholder="Search customer or protocol..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-11 pr-5 py-3.5 bg-white/50 border border-white/40 backdrop-blur-xl rounded-2xl text-sm focus:outline-none shadow-sm transition-all" />
          </div>
          <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setIsAddingRecord(true)} className="flex items-center justify-center space-x-3 bg-[#999] text-white px-8 py-3.5 rounded-2xl font-bold text-[10px] uppercase tracking-widest border border-[#B8A17D]/30 shadow-lg gold-glow active-scale">
            <Plus className="w-4.5 h-4.5" />
            <span>New Registry</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-10">
        <Dashboard stats={stats} />

        <div className="space-y-4">
          <div className="flex items-center space-x-2 overflow-x-auto hide-scrollbar py-1">
            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest shrink-0">Protocol Status:</span>
            {['All', 'Active', 'Settled', 'Overdue'].map((f) => (
              <button key={f} onClick={() => setStatusFilter(f as any)} className={`px-4 py-1.5 rounded-xl text-[9px] font-bold uppercase transition-all border shrink-0 ${statusFilter === f ? 'bg-[#333] text-white border-[#333]' : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'}`}>{f}</button>
            ))}
          </div>
          <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
        </div>
      </main>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              handleRecordUpdate(next);
            }}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => {
        const next = [newRecord, ...records];
        handleRecordUpdate(next);
        setIsAddingRecord(false);
      }} />
      <UserManagementModal isOpen={isManagingUsers} onClose={() => setIsManagingUsers(false)} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { X, ShoppingBag, ImageIcon, AlertCircle, RotateCcw } from 'lucide-react';
import { PurchaseItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (item: PurchaseItem) => void;
  initialData?: PurchaseItem;
}

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const DRAFT_KEY = 'jaytin_item_draft';

const AddItemModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData }) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [itemImage, setItemImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  function resetForm() {
    setName('');
    setAmount(0);
    setDate(new Date().toISOString().split('T')[0]);
    setNote('');
    setItemImage(null);
    setError(null);
    localStorage.removeItem(DRAFT_KEY);
  }

  // 挂载时尝试加载草稿（仅限新增模式）
  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setAmount(initialData.amount);
      setDate(initialData.date);
      setNote(initialData.note || '');
      setItemImage(initialData.attachment?.data || null);
    } else if (isOpen) {
      const draft = localStorage.getItem(DRAFT_KEY);
      if (draft) {
        try {
          const parsed = JSON.parse(draft);
          setName(parsed.name || '');
          setAmount(parsed.amount || 0);
          setDate(parsed.date || new Date().toISOString().split('T')[0]);
          setNote(parsed.note || '');
          setItemImage(parsed.itemImage || null);
        } catch (e) {}
      }
    }
  }, [initialData, isOpen]);

  // 实时保存草稿（仅限新增模式）
  useEffect(() => {
    if (!initialData && isOpen && (name || amount > 0 || note)) {
      const draft = { name, amount, date, note, itemImage };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    }
  }, [name, amount, date, note, itemImage, initialData, isOpen]);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        setError("Asset photo exceeds 5MB limit.");
        return;
      }
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => setItemImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (!name.trim() || amount <= 0) {
      setError("Please verify entry details.");
      return;
    }

    try {
      const item: PurchaseItem = {
        id: initialData?.id || `I-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        name: name.trim(),
        amount: Number(amount),
        date,
        note
      };

      if (itemImage) {
        item.attachment = {
          id: initialData?.attachment?.id || `A-I-${Date.now()}`,
          name: `Asset Photo: ${name}`,
          data: itemImage,
          type: 'image',
        };
      }

      onSubmit(item);
      resetForm();
    } catch (err) {
      console.error("Submission Crash", err);
      setError("Archive failure. Protocol interrupted.");
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/10 backdrop-blur-md"
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="glass-card w-full max-w-lg rounded-[40px] overflow-hidden border border-white/60 shadow-2xl relative z-10"
      >
        <div className="p-8 border-b border-white/20 flex justify-between items-center bg-white/20">
          <div>
            <h3 className="text-xl font-jua text-[#333]">{initialData ? 'Refine Asset' : 'Declare Asset'}</h3>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Registry Protocol</p>
          </div>
          <div className="flex items-center space-x-2">
            {!initialData && (name || amount > 0) && (
              <button type="button" onClick={resetForm} className="p-2 text-gray-400 hover:text-red-400 active-scale" title="Clear Draft">
                <RotateCcw className="w-4.5 h-4.5" />
              </button>
            )}
            <button type="button" onClick={onClose} className="p-2 hover:bg-white/40 rounded-full transition-colors active-scale"><X className="w-5 h-5 text-gray-400" /></button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Asset Nomenclature</label>
            <input required type="text" placeholder="e.g. Rare Artifact" value={name} onChange={(e) => setName(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Valuation (RM)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-jua text-xs">RM</span>
                <input required type="number" step="0.01" value={amount || ''} onChange={(e) => setAmount(Number(e.target.value))} className="w-full bg-white/40 border border-white/30 rounded-2xl pl-12 pr-5 py-4 text-sm focus:outline-none font-jua" placeholder="0.00" />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Archive Date</label>
              <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-sm focus:outline-none" />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Registry Annotation</label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Entry details..." className="w-full bg-white/40 border border-white/30 rounded-2xl px-5 py-4 text-xs focus:outline-none min-h-[100px]" />
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest block px-1">Visual Evidence</label>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-[#B8A17D]/30 rounded-2xl flex flex-col items-center justify-center text-gray-400 hover:bg-[#B8A17D]/5 transition-all overflow-hidden relative group">
              {itemImage ? <img src={itemImage} className="w-full h-full object-cover" /> : (
                <>
                  <ShoppingBag className="w-6 h-6 mb-1 group-hover:text-[#B8A17D]" />
                  <span className="text-[9px] uppercase font-bold tracking-widest">Attach Proof</span>
                </>
              )}
            </button>
            {error && <p className="text-[10px] text-red-400 mt-2 flex items-center"><AlertCircle className="w-3 h-3 mr-1"/> {error}</p>}
          </div>

          <button type="submit" className="w-full bg-[#333] text-white py-5 rounded-[24px] font-bold text-xs uppercase tracking-[0.4em] shadow-xl border border-[#B8A17D] hover:brightness-105 transition-all active-scale gold-glow">Archive Asset</button>
        </form>
      </motion.div>
    </div>
  );
};

export default AddItemModal;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle,
  Users,
  Globe,
  CloudCheck,
  RefreshCw
} from 'lucide-react';
import { LedgerRecord, DashboardStats } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import UserManagementModal from './components/UserManagementModal';
import Login from './components/Login';
import { supabase } from './supabase';

const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  if (errMsg.includes('relation "public.ledgers" does not exist')) return "Database Schema Missing.";
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => localStorage.getItem('jaytin_auth') === 'true');
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Settled' | 'Overdue'>('All');

  const [publicRecord, setPublicRecord] = useState<LedgerRecord | null>(null);
  const [isPublicMode, setIsPublicMode] = useState(() => window.location.hash.startsWith('#/share/'));

  const syncTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    const handleRoute = async () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/share/')) {
        const key = hash.replace('#/share/', '');
        if (key && key.length >= 32) {
          setIsPublicMode(true);
          setIsLoading(true);
          try {
            const { data, error } = await supabase
              .from('ledgers')
              .select('record')
              .eq('record->>shareKey', key)
              .maybeSingle();

            if (data) {
              setPublicRecord(data.record as LedgerRecord);
            } else {
              setPublicRecord(null);
            }
          } catch (e) {
            console.error("Vault access failure", e);
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsPublicMode(false);
          setPublicRecord(null);
        }
      } else {
        setIsPublicMode(false);
        setPublicRecord(null);
      }
    };

    handleRoute();
    window.addEventListener('hashchange', handleRoute);
    return () => window.removeEventListener('hashchange', handleRoute);
  }, []);

  useEffect(() => {
    if (isPublicMode) return;
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        setRecords(JSON.parse(saved));
        setIsLoading(false);
      } catch (e) { console.warn(e); }
    }
  }, [isPublicMode]);

  const fetchFromCloud = async () => {
    if (isPublicMode || !isAuthenticated) return;
    setSyncError(null);
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;
      if (data) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
        setLastSynced(new Date());
      }
    } catch (e: any) {
      setSyncError(stringifyError(e));
    } finally {
      setIsLoading(false);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated && !isPublicMode) {
      fetchFromCloud();
    } else if (!isPublicMode) {
      setIsLoading(false);
    }
  }, [isAuthenticated, isPublicMode]);

  const syncAllToCloud = async (currentRecords: LedgerRecord[]) => {
    if (!isAuthenticated || isPublicMode) return;
    setIsSyncing(true);
    setSyncError(null);
    try {
      const payloads = currentRecords.map(r => ({
        id: r.id,
        record: r,
        updated_at: new Date().toISOString()
      }));

      const { error } = await supabase.from('ledgers').upsert(payloads);
      if (error) throw error;
      setLastSynced(new Date());
    } catch (e: any) {
      setSyncError(`Sync Lag: ${stringifyError(e)}`);
    } finally {
      setIsSyncing(false);
    }
  };

  const deleteRecordFromCloud = async (id: string) => {
    if (!isAuthenticated || isPublicMode) return;
    setIsSyncing(true);
    try {
      const { error } = await supabase.from('ledgers').delete().eq('id', id);
      if (error) throw error;
      const next = records.filter(r => r.id !== id);
      setRecords(next);
      localStorage.setItem('jaytin_ledgers', JSON.stringify(next));
      setSelectedRecordId(null);
    } catch (e: any) {
      setSyncError(`Deletion Error: ${stringifyError(e)}`);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRecordUpdate = (newRecords: LedgerRecord[]) => {
    setRecords(newRecords);
    localStorage.setItem('jaytin_ledgers', JSON.stringify(newRecords));

    if (syncTimeoutRef.current) window.clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = window.setTimeout(() => {
      syncAllToCloud(newRecords);
    }, 1500);
  };

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('username', user).eq('password', pass).single();
      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e) { return false; }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('jaytin_auth');
    localStorage.removeItem('jaytin_ledgers');
    setRecords([]);
    window.location.hash = '';
  };

  const stats: DashboardStats = useMemo(() => {
    return {
      totalOutstanding: records.reduce((acc, curr) => acc + Math.max(0, curr.totalAmount - curr.paidAmount), 0),
      activeCustomers: records.filter(r => r.status === 'Active' || r.status === 'Overdue').length,
      collectedThisMonth: records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          const now = new Date();
          return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0)
    };
  }, [records]);

  const filteredRecords = records.filter(r => {
    const matchesSearch = r.userName.toLowerCase().includes(searchQuery.toLowerCase()) || r.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF]">
        <Loader2 className="w-10 h-10 text-[#B8A17D] animate-spin" />
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.4em] mt-6">Secure Connection...</p>
      </div>
    );
  }

  if (isPublicMode) {
    if (publicRecord) {
      return (
        <div className="min-h-screen bg-[#EBFAFF]">
          <CustomerDetail record={publicRecord} isViewOnly={true} onClose={() => { window.location.hash = ''; }} onUpdateRecord={() => {}} onDeleteRecord={() => {}} />
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 bg-[#333]/90 backdrop-blur-xl rounded-full border border-white/10 shadow-2xl">
             <p className="text-[10px] text-white font-bold uppercase tracking-[0.3em] flex items-center">
               <Globe className="w-3.5 h-3.5 mr-2.5 text-[#B8A17D]" /> Safe View Mode
             </p>
          </div>
        </div>
      );
    } else {
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-[#EBFAFF] p-10 text-center">
          <AlertCircle className="w-16 h-16 text-red-300 mb-8" />
          <h2 className="text-3xl font-jua text-gray-800">Protocol Expired</h2>
          <p className="text-sm text-gray-400 mt-4 leading-relaxed">The requested financial record is no longer accessible or the link is invalid.</p>
          <button onClick={() => window.location.hash = ''} className="mt-10 px-10 py-4 bg-[#999] text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest active-scale">Return to Terminal</button>
        </div>
      );
    }
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col space-y-6 mb-12">
        <div className="flex justify-between items-center">
          <div className="relative group">
            <h1 className="text-3xl md:text-4xl font-jua text-[#333] tracking-tight">JayTIN TEAM</h1>
            <div className="flex items-center space-x-2 mt-1.5">
               <ShieldCheck className="w-3.5 h-3.5 text-[#B8A17D]" />
               <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#B8A17D]">Vault Secure</p>
               <div className="flex items-center ml-2 space-x-1 bg-white/40 px-2 py-0.5 rounded-full border border-white/60">
                 {isSyncing ? <RefreshCw className="w-2.5 h-2.5 text-[#B8A17D] animate-spin" /> : <CloudCheck className="w-2.5 h-2.5 text-green-500/70" />}
                 <span className="text-[8px] font-bold uppercase tracking-tighter text-gray-400">{isSyncing ? 'Syncing' : 'Auto-Saved'}</span>
               </div>
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsManagingUsers(true)} className="p-2.5 text-[#B8A17D] bg-white/40 rounded-xl border border-white/60 shadow-sm active-scale"><Users className="w-5 h-5" /></motion.button>
            <motion.button whileTap={{ scale: 0.9 }} onClick={handleLogout} className="p-3 text-gray-400 hover:text-red-400 transition-all rounded-full bg-white/20 active-scale"><LogOut className="w-5 h-5" /></motion.button>
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input type="text" placeholder="Search customer or protocol..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-11 pr-5 py-3.5 bg-white/50 border border-white/40 backdrop-blur-xl rounded-2xl text-sm focus:outline-none shadow-sm transition-all" />
          </div>
          <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setIsAddingRecord(true)} className="flex items-center justify-center space-x-3 bg-[#999] text-white px-8 py-3.5 rounded-2xl font-bold text-[10px] uppercase tracking-widest border border-[#B8A17D]/30 shadow-lg gold-glow active-scale">
            <Plus className="w-4.5 h-4.5" />
            <span>New Registry</span>
          </motion.button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-10">
        <Dashboard stats={stats} />

        <div className="space-y-4">
          <div className="flex items-center space-x-2 overflow-x-auto hide-scrollbar py-1">
            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest shrink-0">Protocol Status:</span>
            {['All', 'Active', 'Settled', 'Overdue'].map((f) => (
              <button key={f} onClick={() => setStatusFilter(f as any)} className={`px-4 py-1.5 rounded-xl text-[9px] font-bold uppercase transition-all border shrink-0 ${statusFilter === f ? 'bg-[#333] text-white border-[#333]' : 'bg-white/40 text-gray-400 border-white/30 hover:bg-white/60'}`}>{f}</button>
            ))}
          </div>
          <CustomerList records={filteredRecords} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
        </div>
      </main>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              handleRecordUpdate(next);
            }}
            onDeleteRecord={(id) => deleteRecordFromCloud(id)}
          />
        )}
      </AnimatePresence>

      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => {
        const next = [newRecord, ...records];
        handleRecordUpdate(next);
        setIsAddingRecord(false);
      }} />
      <UserManagementModal isOpen={isManagingUsers} onClose={() => setIsManagingUsers(false)} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, 
  ShoppingBag, 
  CreditCard, 
  FileEdit, 
  Clock, 
  Edit2,
  Image as ImageIcon,
  Calendar,
  FileText,
  Pin,
  AlertTriangle,
  Share2,
  Check,
  Trash2,
  Maximize2,
  AlertCircle
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord, Attachment, SystemNote } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';
import RecordFormModal from './RecordFormModal';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onUpdateRecord: (record: LedgerRecord) => void;
  onDeleteRecord?: (id: string) => void;
}

const CustomerDetail: React.FC<Props> = ({ 
  record, 
  isViewOnly = false,
  onClose, 
  onUpdateRecord,
  onDeleteRecord
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [editingItem, setEditingItem] = useState<PurchaseItem | null>(null);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | null>(null);

  const [isAddingEvidence, setIsAddingEvidence] = useState(false);
  const [evidenceNote, setEvidenceNote] = useState('');
  const [evidenceImage, setEvidenceImage] = useState<string | null>(null);

  // 预览状态
  const [selectedAttachment, setSelectedAttachment] = useState<Attachment | null>(null);
  const [selectedItemPreview, setSelectedItemPreview] = useState<PurchaseItem | null>(null);
  const [selectedPaymentPreview, setSelectedPaymentPreview] = useState<PaymentRecord | null>(null);
  const [fullScreenImage, setFullScreenImage] = useState<string | null>(null);

  const [copied, setCopied] = useState(false);
  const [shareError, setShareError] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<{ type: 'item' | 'payment' | 'attachment' | 'protocol', id: string } | null>(null);

  const evidenceInputRef = useRef<HTMLInputElement>(null);
  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;

  const pinnedReminders = useMemo(() => {
    if (record.status === 'Settled' || record.type !== 'Installment' || !record.paymentCycle || !record.startDate) return [];
    const now = new Date();
    const start = new Date(record.startDate);
    let totalPeriods = record.cycleCount || 1;
    const installmentAmount = record.totalAmount / totalPeriods;
    let currentPeriod = 1;
    if (record.paymentCycle === 'Day') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Weekly') currentPeriod = Math.ceil((now.getTime() - start.getTime()) / (7 * 24 * 60 * 60 * 1000));
    else if (record.paymentCycle === 'Monthly') currentPeriod = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth()) + 1;
    currentPeriod = Math.max(1, Math.min(currentPeriod, totalPeriods));

    let nextDate = new Date(start);
    if (record.paymentCycle === 'Day') nextDate.setDate(start.getDate() + currentPeriod);
    else if (record.paymentCycle === 'Weekly') nextDate.setDate(start.getDate() + (currentPeriod * 7));
    else if (record.paymentCycle === 'Monthly') nextDate.setMonth(start.getMonth() + currentPeriod);

    return [{
      id: 'reminder-pinned-calc',
      timestamp: nextDate.toDateString(),
      content: `[Cycle ${currentPeriod}/${totalPeriods}]: RM${installmentAmount.toLocaleString(undefined, {minimumFractionDigits: 2})} due. Next deadline: ${nextDate.toLocaleDateString()}.`,
      isPinned: true
    }];
  }, [record]);

  const timelineNotes = useMemo(() => [...pinnedReminders, ...(record.notes || [])], [pinnedReminders, record.notes]);

  const createLogEntry = (content: string): SystemNote => ({
    id: `N-${Date.now()}`,
    timestamp: new Date().toLocaleString(),
    content
  });

  const handleAddItem = (item: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = [...safeItems, { ...item, id: item.id || `I-${Date.now()}` }];
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Secured: ${item.name} (+RM ${item.amount.toLocaleString()})`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setIsAddingItem(false);
  };

  const handleEditItem = (updated: PurchaseItem) => {
    const safeItems = record.items || [];
    const newItems = safeItems.map(i => i.id === updated.id ? updated : i);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Refined: ${updated.name}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setEditingItem(null);
  };

  const handleDeleteItem = (id: string) => {
    const safeItems = record.items || [];
    const itemToDelete = safeItems.find(i => i.id === id);
    const newItems = safeItems.filter(i => i.id !== id);
    const newTotal = newItems.reduce((sum, i) => sum + i.amount, 0);
    const newNotes = [createLogEntry(`Artifact Purged: ${itemToDelete?.name || 'Unknown'}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, items: newItems, totalAmount: newTotal, notes: newNotes });
    setConfirmDelete(null);
    setSelectedItemPreview(null);
  };

  const handleAddPayment = (payment: any) => {
    const newPaymentObj: PaymentRecord = { ...payment, id: `P-${Date.now()}` };
    const safePayments = record.payments || [];
    const newPayments = [newPaymentObj, ...safePayments];
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection: RM ${payment.amount.toLocaleString()} via ${payment.method}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setIsRecordingPayment(false);
  };

  const handleEditPayment = (updated: PaymentRecord) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.map(p => p.id === updated.id ? updated : p);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Refined: RM ${updated.amount.toLocaleString()}`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setEditingPayment(null);
    setSelectedPaymentPreview(null);
  };

  const handleDeletePayment = (id: string) => {
    const safePayments = record.payments || [];
    const newPayments = safePayments.filter(p => p.id !== id);
    const newPaid = newPayments.reduce((sum, p) => sum + p.amount, 0);
    const newNotes = [createLogEntry(`Injection Purged from Ledger`), ...(record.notes || [])];
    onUpdateRecord({ ...record, payments: newPayments, paidAmount: newPaid, notes: newNotes });
    setConfirmDelete(null);
    setSelectedPaymentPreview(null);
  };

  const handleAddEvidence = (e: React.FormEvent) => {
    e.preventDefault();
    if (evidenceImage || evidenceNote) {
      const newAttachment: Attachment = {
        id: `A-E-${Date.now()}`,
        name: `Evidence Artifact`,
        data: evidenceImage || '',
        type: 'image',
        description: evidenceNote
      };
      const safeAttachments = record.attachments || [];
      const newNotes = [createLogEntry(`Visual Evidence Archived`), ...(record.notes || [])];
      onUpdateRecord({ ...record, attachments: [newAttachment, ...safeAttachments], notes: newNotes });
      setEvidenceNote(''); setEvidenceImage(null); setIsAddingEvidence(false);
    }
  };

  const handleShare = () => {
    const shareKey = record.shareKey;
    if (!shareKey || shareKey === 'ERROR') {
      setShareError(true);
      setTimeout(() => setShareError(false), 3000);
      return;
    }
    const shareUrl = `${window.location.origin}${window.location.pathname}#/share/${shareKey}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'item') handleDeleteItem(confirmDelete.id);
    if (confirmDelete.type === 'payment') handleDeletePayment(confirmDelete.id);
    if (confirmDelete.type === 'protocol') onDeleteRecord?.(confirmDelete.id);
    if (confirmDelete.type === 'attachment') {
      const safeAttachments = record.attachments || [];
      onUpdateRecord({ ...record, attachments: safeAttachments.filter(a => a.id !== confirmDelete.id) });
      setSelectedAttachment(null);
      setConfirmDelete(null);
    }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-0 md:p-8">
      <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} transition={{ type: 'spring', damping: 25, stiffness: 200 }} className="glass-card w-full max-w-6xl h-full md:h-full md:max-h-[92vh] md:rounded-[48px] overflow-hidden border-t md:border border-white/60 flex flex-col relative shadow-2xl">

        {/* Detail Header */}
        <div className="p-6 md:p-10 pb-4 relative flex flex-col md:flex-row justify-between items-start gap-6 md:gap-8">
          <button type="button" onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/40 hover:bg-white/60 rounded-full transition-all active-scale z-10 shadow-sm border border-white/40">
            <X className="w-6 h-6 text-gray-400" />
          </button>

          <div className="flex-1 space-y-3 w-full pr-12 md:pr-0">
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-[10px] font-jua text-[#B8A17D] uppercase tracking-[0.3em]">JAYTIN PROTOCOL</span>
              <div className="px-2.5 py-1 rounded-lg text-[8px] font-bold uppercase tracking-widest bg-white/40 border border-white/60 text-gray-500">{record.type}</div>
            </div>

            <div className="flex flex-col space-y-2">
              <h2 className="text-3xl md:text-5xl font-jua text-[#333] tracking-tight truncate leading-none">{record.userName}</h2>
              <div className="flex items-center gap-2">
                {!isViewOnly && (
                  <>
                    <button type="button" onClick={() => setIsEditingProfile(true)} className="p-2 bg-white/50 border border-white/60 rounded-xl text-[#B8A17D] active-scale shadow-sm">
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button type="button" onClick={() => setConfirmDelete({ type: 'protocol', id: record.id })} className="p-2 bg-white/50 border border-red-100 rounded-xl text-red-400 active-scale shadow-sm hover:bg-red-50">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </>
                )}
                <button type="button" onClick={handleShare} className={`px-4 py-2 bg-white/50 border border-white/60 rounded-xl transition-all shadow-sm flex items-center space-x-2 active-scale ${copied ? 'text-green-600' : shareError ? 'text-red-500' : 'text-[#B8A17D]'}`}>
                  {copied ? <Check className="w-4 h-4" /> : shareError ? <AlertTriangle className="w-4 h-4" /> : <Share2 className="w-4 h-4" />}
                  <span className="text-[10px] font-bold uppercase tracking-widest">{copied ? 'Linked' : 'Share'}</span>
                </button>
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-[9px] text-gray-400 font-bold uppercase tracking-widest pt-1">
              <span className="flex items-center"><Calendar className="w-3 h-3 mr-1 text-[#B8A17D]"/> {record.startDate}</span>
              <span className="opacity-40">#{record.id}</span>
            </div>
          </div>

          <div className="w-full md:w-96 p-5 md:p-6 rounded-[28px] bg-white/30 border border-white/50 shadow-inner space-y-4">
            <div className="flex justify-between items-end">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Progress</span>
              <span className="text-sm font-jua text-[#333]">{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full h-1.5 bg-white/50 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" />
            </div>
            <div className="grid grid-cols-2 gap-4 pt-1">
              <div className="text-left"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Paid</p><p className="text-lg font-jua text-gray-800">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Due</p><p className="text-lg font-jua text-[#B8A17D]">RM{Math.max(0, record.totalAmount - record.paidAmount).toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex px-4 md:px-12 border-b border-white/10 overflow-x-auto hide-scrollbar">
          {['overview', 'items', 'history'].map((tab) => (
            <button key={tab} type="button" onClick={() => setActiveTab(tab as any)} className={`py-5 px-6 md:px-8 text-[10px] font-bold uppercase tracking-[0.3em] transition-all relative shrink-0 ${activeTab === tab ? 'text-[#333]' : 'text-gray-400'}`}>
              {tab}{activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[3px] bg-[#B8A17D] rounded-t-full" />}
            </button>
          ))}
        </div>

