              <motion.div initial={{ scale: 0.9, y: 30 }} animate={{ scale: 1, y: 0 }} className="glass-card w-full max-w-lg rounded-[32px] overflow-hidden p-8 border border-white shadow-2xl relative bg-white/95" onClick={e => e.stopPropagation()}>
                 <button type="button" onClick={() => setSelectedPaymentPreview(null)} className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full active-scale"><X className="w-5 h-5 text-gray-400" /></button>
                 <div className="space-y-6">
                    <div className="border-b border-gray-100 pb-6">
                       <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-[0.3em] mb-1">Injection Detail</p>
                       <h2 className="text-2xl font-jua text-[#333] mb-4">Payment: {selectedPaymentPreview.method}</h2>
                       <div className="flex justify-between items-end">
