                    {selectedPaymentPreview.attachment?.data && (
                      <div className="rounded-2xl overflow-hidden border border-gray-200 cursor-zoom-in" onClick={() => setFullScreenImage(selectedPaymentPreview.attachment!.data)}>
                        <img src={selectedPaymentPreview.attachment.data} className="w-full h-auto" />
