                    {!isViewOnly && (
                      <div className="flex gap-3 pt-2">
                        <button onClick={() => setEditingPayment(selectedPaymentPreview)} className="flex-1 py-4 bg-[#333] text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest active-scale">Edit Entry</button>
                        <button onClick={() => setConfirmDelete({ type: 'payment', id: selectedPaymentPreview.id })} className="px-5 py-4 border border-red-200 text-red-500 rounded-2xl active-scale"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    )}
