              </motion.div>
            </motion.div>
          )}

          {/* Full Screen Image Viewer */}
          {fullScreenImage && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[200] bg-black/95 flex items-center justify-center p-4 cursor-zoom-out" onClick={() => setFullScreenImage(null)}>
              <motion.img initial={{ scale: 0.9 }} animate={{ scale: 1 }} src={fullScreenImage} className="max-w-full max-h-full object-contain rounded-lg" />
              <button className="absolute top-8 right-8 p-3 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md border border-white/20 transition-all"><X className="w-8 h-8" /></button>
            </motion.div>
          )}

          {/* Delete Confirm Overlay */}
          {confirmDelete && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[300] bg-[#333]/60 backdrop-blur-md flex items-center justify-center p-6">
              <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="glass-card w-full max-w-sm rounded-[32px] p-8 text-center border border-white shadow-2xl bg-white/95">
                <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6"><AlertCircle className="w-8 h-8 text-red-500" /></div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">Confirm Termination</h3>
                <p className="text-xs text-gray-400 uppercase tracking-widest font-bold mb-8">This protocol will be permanently purged.</p>
                <div className="flex flex-col gap-3">
                  <button onClick={executeDelete} className="w-full py-4 bg-red-500 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest shadow-xl active-scale">Confirm Purge</button>
                  <button onClick={() => setConfirmDelete(null)} className="w-full py-4 bg-gray-100 text-gray-500 rounded-2xl text-[10px] font-bold uppercase tracking-widest active-scale">Abort</button>
                </div>
