import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, Send, Bot, Sparkles, Loader2, 
  TrendingUp, AlertCircle, PieChart, Info,
  MessageSquare, History, Wand2
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { LedgerRecord, DashboardStats } from '../types';

interface AIAssistantProps {
  isOpen: boolean;
  onClose: () => void;
  records: LedgerRecord[];
  stats: DashboardStats;
}

interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, onClose, records, stats }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'assistant',
      content: "Protocol active. I am the JayTIN Private Concierge. How may I assist with your capital analysis today?",
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    const newMessages: Message[] = [
      ...messages,
      { role: 'user', content: userMessage, timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }
    ];
    setMessages(newMessages);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      // Prepare context for the AI
      const context = {
        totalOutstanding: stats.totalOutstanding,
        activeProtocols: stats.activeCustomers,
        collectionRate: stats.collectionRate,
        overdueAmount: stats.overdueAmount,
        topClients: records
          .sort((a, b) => (b.totalAmount - b.paidAmount) - (a.totalAmount - a.paidAmount))
          .slice(0, 5)
          .map(r => ({ name: r.userName, balance: r.totalAmount - r.paidAmount, status: r.status })),
        recentActivity: records
          .flatMap(r => r.payments.map(p => ({ user: r.userName, amount: p.amount, date: p.date })))
          .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
          .slice(0, 5)
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMessage,
        config: {
          systemInstruction: `You are the JayTIN Private Concierge, a high-end financial advisor for a private balance ledger system. 
          Use the following context to answer the user's questions about their financial data.
          CONTEXT: ${JSON.stringify(context)}
          TONE: Professional, sophisticated, concise, and analytical. Use terms like 'capital', 'protocol', 'liquidity', and 'exposure'.
          FORMATTING: Use clear markdown for lists and bold for numbers.
          If the user asks something unrelated to financial data, politely steer them back to capital management.`,
        },
      });

      const aiText = response.text || "I apologize, but I encountered a disruption in the intelligence protocol.";

      setMessages([
        ...newMessages,
        { 
          role: 'assistant', 
          content: aiText, 
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
        }
      ]);
    } catch (error) {
      console.error("AI Protocol Error:", error);
      setMessages([
        ...newMessages,
        { 
          role: 'assistant', 
          content: "Protocol Interruption: Unable to reach the intelligence core. Please verify your network connection.", 
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
        }
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const suggestions = [
    "Summarize financial health",
    "Identify high-risk exposure",
    "Predict next month's inflow",
    "Analyze top 5 clients"
  ];

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 z-[200] bg-black/20 backdrop-blur-sm"
          />
          <motion.div 
            initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed right-0 top-0 h-full w-full max-w-md z-[210] bg-[#1A1A1A] text-white shadow-2xl flex flex-col border-l border-white/5"
          >
            {/* Header */}
            <div className="p-8 border-b border-white/10 flex justify-between items-center bg-gradient-to-br from-[#222] to-[#111]">
              <div className="flex items-center space-x-4">
                <div className="w-12 h-12 rounded-2xl bg-[#B8A17D] flex items-center justify-center shadow-[0_0_20px_rgba(184,161,125,0.3)]">
                  <Bot className="w-7 h-7 text-[#1A1A1A]" />
                </div>
                <div>
                  <h3 className="text-xl font-jua tracking-tight">JayTIN Concierge</h3>
                  <div className="flex items-center space-x-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                    <span className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Intelligence Link Active</span>
                  </div>
                </div>
              </div>
              <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors">
                <X className="w-6 h-6 text-gray-500" />
              </button>
            </div>

            {/* Chat Area */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-[#1A1A1A]">
              {messages.map((msg, i) => (
                <motion.div 
                  key={i}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`max-w-[85%] rounded-[24px] p-5 text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-[#B8A17D] text-[#1A1A1A] font-bold rounded-tr-none' 
                      : 'bg-[#262626] text-gray-200 border border-white/5 rounded-tl-none'
                  }`}>
                    <div className="markdown-content whitespace-pre-wrap">
                      {msg.content}
                    </div>
                    <p className={`text-[8px] mt-2 font-bold uppercase tracking-widest ${msg.role === 'user' ? 'text-[#1A1A1A]/50' : 'text-gray-500'}`}>
                      {msg.timestamp}
                    </p>
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-[#262626] rounded-[24px] rounded-tl-none p-5 border border-white/5 flex items-center space-x-3">
                    <Loader2 className="w-4 h-4 animate-spin text-[#B8A17D]" />
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Processing Data...</span>
                  </div>
                </div>
              )}
            </div>

            {/* Suggestions & Input */}
            <div className="p-6 bg-[#111] border-t border-white/5 space-y-6">
              <div className="flex overflow-x-auto hide-scrollbar space-x-2 pb-2">
                {suggestions.map((s, i) => (
                  <button 
                    key={i} 
                    onClick={() => setInput(s)}
                    className="shrink-0 px-4 py-2 bg-[#222] border border-white/10 rounded-full text-[9px] font-bold text-gray-400 uppercase tracking-widest hover:border-[#B8A17D] hover:text-[#B8A17D] transition-all"
                  >
                    {s}
                  </button>
                ))}
              </div>

              <div className="relative group">
                <input 
                  type="text" 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Inquire with private concierge..."
                  className="w-full bg-[#222] border border-white/10 rounded-2xl pl-6 pr-14 py-4 text-sm focus:outline-none focus:border-[#B8A17D]/50 transition-all"
                />
                <button 
                  onClick={handleSend}
                  disabled={!input.trim() || isLoading}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-[#B8A17D] rounded-xl text-[#1A1A1A] disabled:opacity-50 disabled:grayscale transition-all"
                >
                  <Send className="w-4.5 h-4.5" />
                </button>
              </div>
              <p className="text-center text-[8px] text-gray-600 font-bold uppercase tracking-[0.2em]">
                JayTIN Intelligence Protocol v2.5
              </p>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default AIAssistant;

import React, { useState, useMemo, useEffect, useRef } from 'react';
