const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  if (errMsg.includes('relation "public.ledgers" does not exist')) return "Database Schema Missing.";
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => localStorage.getItem('jaytin_auth') === 'true');
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [isAIOpen, setIsAIOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [publicRecord, setPublicRecord] = useState<LedgerRecord | null>(null);
  const [isPublicMode, setIsPublicMode] = useState(() => window.location.hash.startsWith('#/share/'));

  const syncTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    const handleRoute = async () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/share/')) {
        const key = hash.replace('#/share/', '');
        if (key && key.length >= 32) {
          setIsPublicMode(true);
          setIsLoading(true);
          try {
            const { data, error } = await supabase
              .from('ledgers')
              .select('record')
              .eq('record->>shareKey', key)
              .maybeSingle();

            if (data) {
              setPublicRecord(data.record as LedgerRecord);
            } else {
              setPublicRecord(null);
            }
          } catch (e) {
            console.error("Vault access failure", e);
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsPublicMode(false);
          setPublicRecord(null);
        }
      } else {
        setIsPublicMode(false);
        setPublicRecord(null);
      }
    };

    handleRoute();
    window.addEventListener('hashchange', handleRoute);
    return () => window.removeEventListener('hashchange', handleRoute);
  }, []);

  useEffect(() => {
    if (isPublicMode) return;
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        setRecords(JSON.parse(saved));
        setIsLoading(false);
      } catch (e) { console.warn(e); }
    }
  }, [isPublicMode]);

  const fetchFromCloud = async () => {
    if (isPublicMode || !isAuthenticated) return;
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;
      if (data) {
        const cloudRecords = data.map((row: any) => row.record);
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
      }
    } catch (e: any) {
      console.error(stringifyError(e));
    } finally {
      setIsLoading(false);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated && !isPublicMode) {
      fetchFromCloud();
    } else if (!isPublicMode) {
      setIsLoading(false);
    }
  }, [isAuthenticated, isPublicMode]);

  const syncAllToCloud = async (currentRecords: LedgerRecord[]) => {
    if (!isAuthenticated || isPublicMode) return;
    setIsSyncing(true);
    try {
      const payloads = currentRecords.map(r => ({
        id: r.id,
        record: r,
        updated_at: new Date().toISOString()
      }));
      const { error } = await supabase.from('ledgers').upsert(payloads);
      if (error) throw error;
    } catch (e: any) {
      console.error(stringifyError(e));
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRecordUpdate = (newRecords: LedgerRecord[]) => {
    setRecords(newRecords);
    localStorage.setItem('jaytin_ledgers', JSON.stringify(newRecords));
    if (syncTimeoutRef.current) window.clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = window.setTimeout(() => {
      syncAllToCloud(newRecords);
    }, 1500);
  };

  const stats: DashboardStats = useMemo(() => {
    const totalValuation = records.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const totalPaid = records.reduce((acc, curr) => acc + curr.paidAmount, 0);
    const totalOutstanding = totalValuation - totalPaid;

    const now = new Date();
    const collectedThisMonth = records.reduce((acc, curr) => 
      acc + (curr.payments || []).reduce((pAcc, p) => {
        const pDate = new Date(p.date);
        return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
      }, 0)
    , 0);

    const overdueAmount = records
      .filter(r => r.status === 'Overdue')
      .reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0);

    const monthlyTrend: MonthlyTrend[] = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(now.getMonth() - i);
      const mLabel = d.toLocaleString('en-US', { month: 'short' });
      const mValue = records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          return (pDate.getMonth() === d.getMonth() && pDate.getFullYear() === d.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0);
      monthlyTrend.push({ month: mLabel, amount: mValue });
    }

    return {
      totalValuation,
      totalOutstanding,
      activeCustomers: records.filter(r => r.status !== 'Settled').length,
      collectedThisMonth,
      collectionRate: totalValuation > 0 ? (totalPaid / totalValuation) * 100 : 0,
      overdueAmount,
      monthlyTrend
    };
  }, [records]);

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('username', user).eq('password', pass).single();
      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e) { return false; }
  };

  const handleDeleteRecord = (id: string) => {
    const next = records.filter(r => r.id !== id);
    handleRecordUpdate(next);
  };

  if (isLoading) return <div className="min-h-screen flex items-center justify-center bg-[#EBFAFF]"><Loader2 className="w-10 h-10 text-[#B8A17D] animate-spin" /></div>;

  if (isPublicMode && publicRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail record={publicRecord} isViewOnly={true} onClose={() => { window.location.hash = ''; }} onUpdateRecord={() => {}} />
        <AIAssistant isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} records={[publicRecord]} stats={stats} />
        <motion.button 
          whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
          onClick={() => setIsAIOpen(true)}
          className="fixed bottom-8 right-8 w-14 h-14 bg-[#333] text-[#B8A17D] rounded-2xl shadow-2xl flex items-center justify-center z-[150] border border-[#B8A17D]/30"
        >
          <Sparkles className="w-6 h-6" />
        </motion.button>
      </div>
    );
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col space-y-6 mb-12">
        <div className="flex justify-between items-center">
          <h1 className="text-3xl font-jua text-[#333]">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2">
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsManagingUsers(true)} className="p-2.5 text-[#B8A17D] bg-white rounded-xl border border-white active-scale shadow-sm"><Users className="w-5 h-5" /></motion.button>
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => { setIsAuthenticated(false); localStorage.removeItem('jaytin_auth'); }} className="p-3 text-gray-400 hover:text-red-400 transition-all active-scale"><LogOut className="w-5 h-5" /></motion.button>
          </div>
        </div>
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input type="text" placeholder="Search protocol..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-11 pr-5 py-3.5 bg-white/50 border border-white/40 rounded-2xl text-sm" />
          </div>
          <button onClick={() => setIsAddingRecord(true)} className="flex items-center justify-center space-x-3 bg-[#333] text-white px-8 py-3.5 rounded-2xl font-bold text-[10px] uppercase tracking-widest active-scale">
            <Plus className="w-4.5 h-4.5" /><span>New Registry</span>
          </button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-10">
        <Dashboard stats={stats} />
        <CustomerList records={records.filter(r => r.userName.toLowerCase().includes(searchQuery.toLowerCase()))} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
      </main>

      {/* Floating AI Assistant Trigger */}
      <motion.button 
        whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
        onClick={() => setIsAIOpen(true)}
        className="fixed bottom-8 right-8 w-16 h-16 bg-[#333] text-[#B8A17D] rounded-3xl shadow-[0_20px_40px_rgba(0,0,0,0.2)] flex flex-col items-center justify-center z-[150] border border-[#B8A17D]/30 group"
      >
        <Sparkles className="w-6 h-6 mb-1 group-hover:rotate-12 transition-transform" />
        <span className="text-[7px] font-bold uppercase tracking-widest">Concierge</span>
      </motion.button>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              handleRecordUpdate(next);
            }}
            onDeleteRecord={handleDeleteRecord}
          />
        )}
      </AnimatePresence>

      <AIAssistant isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} records={records} stats={stats} />
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => {
        handleRecordUpdate([newRecord, ...records]);
        setIsAddingRecord(false);
      }} />
      <UserManagementModal isOpen={isManagingUsers} onClose={() => setIsManagingUsers(false)} />
    </div>
  );
};

