import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, Send, Bot, Sparkles, Loader2, 
  TrendingUp, AlertCircle, PieChart, Info,
  MessageSquare, History, Wand2, Copy, Check
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { LedgerRecord, DashboardStats } from '../types';

interface AIAssistantProps {
  isOpen: boolean;
  onClose: () => void;
  records: LedgerRecord[];
  stats: DashboardStats;
  currentRecord?: LedgerRecord | null;
}

interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, onClose, records, stats, currentRecord }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      const welcomeMsg = currentRecord 
        ? `Protocol active for **${currentRecord.userName}**. I have audited this specific bond. Currently RM${(currentRecord.totalAmount - currentRecord.paidAmount).toLocaleString()} is outstanding. How shall we manage this exposure?`
        : "JayTIN Intelligence Core online. Global liquidity and risk exposure data loaded. Awaiting your analytical query.";

      setMessages([{
        role: 'assistant',
        content: welcomeMsg,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);
    }
  }, [isOpen, currentRecord]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async (overrideInput?: string) => {
    const userMsgText = overrideInput || input.trim();
    if (!userMsgText || isLoading) return;

    setInput('');
    const newMessages: Message[] = [
      ...messages,
      { role: 'user', content: userMsgText, timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }
    ];
    setMessages(newMessages);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const financialContext = {
        mode: currentRecord ? 'SINGLE_CLIENT_AUDIT' : 'GLOBAL_DASHBOARD',
        global: {
          totalOutstanding: stats.totalOutstanding,
          collectionRate: `${stats.collectionRate.toFixed(2)}%`,
          overdueCount: records.filter(r => r.status === 'Overdue').length,
          overdueAmount: stats.overdueAmount
        },
        focus: currentRecord ? {
          name: currentRecord.userName,
          balance: currentRecord.totalAmount - currentRecord.paidAmount,
          progress: ((currentRecord.paidAmount / currentRecord.totalAmount) * 100).toFixed(1) + '%',
          lastPayment: currentRecord.payments[0]?.date || 'None',
          itemsCount: currentRecord.items.length,
          status: currentRecord.status
        } : null,
        topRisks: records
          .filter(r => r.status !== 'Settled')
          .sort((a, b) => (b.totalAmount - b.paidAmount) - (a.totalAmount - a.paidAmount))
          .slice(0, 3)
          .map(r => ({ name: r.userName, debt: r.totalAmount - r.paidAmount }))
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', // 升级到 Pro 模型处理复杂财务逻辑
        contents: userMsgText,
        config: {
          systemInstruction: `You are the JayTIN Private Concierge, a top-tier financial risk auditor.
          CURRENT CONTEXT: ${JSON.stringify(financialContext)}

          MISSION:
          1. Analyze capital flow and provide high-value insights.
          2. If in SINGLE_CLIENT_AUDIT mode, focus ONLY on helping the user manage that specific person.
          3. If the user asks for a "reminder" or "collection text", draft a sophisticated, firm, but professional message.
          4. Use Markdown for clarity (bold for amounts, bullet points for risks).
          5. Never break character. You are part of an elite banking system.

          TONE: Analytical, stoic, precise, and proactive.`,
          thinkingConfig: { thinkingBudget: 2000 }
        },
      });

      setMessages([
        ...newMessages,
        { 
          role: 'assistant', 
          content: response.text || "Communication timeout. Re-establishing link...", 
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
        }
      ]);
    } catch (error) {
      setMessages([...newMessages, { role: 'assistant', content: "Protocol Error: Intelligence core offline.", timestamp: "ERR" }]);
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = () => {
    const lastMsg = messages[messages.length - 1]?.content;
    if (lastMsg) {
      navigator.clipboard.writeText(lastMsg);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const suggestions = currentRecord 
    ? ["Analyze repayment risk", "Draft collection reminder", "Summarize client status"]
    : ["Financial health summary", "Who is high risk?", "Monthly inflow forecast"];

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="fixed inset-0 z-[200] bg-black/40 backdrop-blur-md" />
          <motion.div 
            initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
            className="fixed right-0 top-0 h-full w-full max-w-lg z-[210] bg-[#0D0D0D] text-white shadow-2xl flex flex-col border-l border-white/10"
          >
            {/* AI Header */}
            <div className="p-8 border-b border-white/5 bg-gradient-to-r from-[#1A1A1A] to-[#0D0D0D] flex justify-between items-center">
              <div className="flex items-center space-x-4">
                <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-[#B8A17D] to-[#8C7A5E] flex items-center justify-center shadow-[0_0_30px_rgba(184,161,125,0.4)]">
                  <Bot className="w-7 h-7 text-black" />
                </div>
                <div>
                  <h3 className="text-xl font-jua tracking-tight text-[#B8A17D]">JayTIN Concierge</h3>
                  <div className="flex items-center space-x-2">
                    <span className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_#22c55e]" />
                    <span className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Real-time Financial Audit Active</span>
                  </div>
                </div>
              </div>
              <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6 text-gray-500" /></button>
            </div>

            {/* Chat Messages */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar bg-[#0D0D0D]">
              {messages.map((msg, i) => (
                <motion.div key={i} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`relative max-w-[90%] rounded-[28px] p-6 text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-[#B8A17D] text-black font-bold rounded-tr-none' 
                      : 'bg-[#1A1A1A] text-gray-200 border border-white/10 rounded-tl-none shadow-xl'
                  }`}>
                    <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap">
                      {msg.content}
                    </div>
                    <div className="flex justify-between items-center mt-4">
                      <span className={`text-[8px] font-bold uppercase tracking-widest ${msg.role === 'user' ? 'text-black/40' : 'text-gray-600'}`}>{msg.timestamp}</span>
                      {msg.role === 'assistant' && i === messages.length - 1 && !isLoading && (
                        <button onClick={copyToClipboard} className="p-1.5 hover:bg-white/5 rounded-lg text-gray-600 hover:text-[#B8A17D] transition-colors">
                          {copied ? <Check className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
                        </button>
                      )}
                    </div>
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-[#1A1A1A] rounded-[28px] rounded-tl-none p-6 border border-white/10 flex items-center space-x-4">
                    <div className="flex space-x-1">
                      <motion.div animate={{ scale: [1, 1.5, 1] }} transition={{ repeat: Infinity, duration: 1 }} className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" />
                      <motion.div animate={{ scale: [1, 1.5, 1] }} transition={{ repeat: Infinity, duration: 1, delay: 0.2 }} className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" />
                      <motion.div animate={{ scale: [1, 1.5, 1] }} transition={{ repeat: Infinity, duration: 1, delay: 0.4 }} className="w-1.5 h-1.5 bg-[#B8A17D] rounded-full" />
                    </div>
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Auditing Capital Structures...</span>
                  </div>
                </div>
              )}
            </div>

            {/* Input & Quick Actions */}
            <div className="p-8 bg-[#111] border-t border-white/5 space-y-6">
              <div className="flex overflow-x-auto hide-scrollbar space-x-3 pb-2">
                {suggestions.map((s, i) => (
                  <button key={i} onClick={() => handleSend(s)} className="shrink-0 px-5 py-2.5 bg-[#1A1A1A] border border-white/10 rounded-xl text-[9px] font-bold text-gray-400 uppercase tracking-widest hover:border-[#B8A17D] hover:text-[#B8A17D] transition-all active:scale-95">
                    {s}
                  </button>
                ))}
              </div>

              <div className="relative group">
                <input 
                  type="text" value={input} onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Ask for audit, risk analysis or reminder draft..."
                  className="w-full bg-[#1A1A1A] border border-white/10 rounded-2xl pl-6 pr-14 py-5 text-sm focus:outline-none focus:border-[#B8A17D]/40 transition-all placeholder:text-gray-700"
                />
                <button 
                  onClick={() => handleSend()} disabled={!input.trim() || isLoading}
                  className="absolute right-2.5 top-1/2 -translate-y-1/2 p-3 bg-[#B8A17D] rounded-xl text-black disabled:opacity-30 disabled:grayscale transition-all hover:scale-105 active:scale-95"
                >
                  <Send className="w-4.5 h-4.5" />
                </button>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

