interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onUpdateRecord: (record: LedgerRecord) => void;
  onDeleteRecord?: (id: string) => void;
  stats?: any; // For AI
  allRecords?: LedgerRecord[]; // For AI
}

const CustomerDetail: React.FC<Props> = ({ record, isViewOnly = false, onClose, onUpdateRecord, onDeleteRecord, stats, allRecords }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [editingItem, setEditingItem] = useState<PurchaseItem | undefined>(undefined);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | undefined>(undefined);
  const [fullScreenImage, setFullScreenImage] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [isLocalAIOpen, setIsLocalAIOpen] = useState(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;
  const remaining = Math.max(0, record.totalAmount - record.paidAmount);
  const isOverdue = record.status === 'Overdue';

  const handleSettleCompletely = () => {
    if (!confirm("Confirm full settlement of this protocol? All outstanding balance will be marked as cleared.")) return;
    const nextRecord = { 
      ...record, 
      paidAmount: record.totalAmount, 
      status: 'Settled' as const,
      notes: [{ id: `N-${Date.now()}`, timestamp: new Date().toLocaleString(), content: 'Protocol officially settled and closed.' }, ...record.notes]
    };
    onUpdateRecord(nextRecord);
  };

  const handleDeleteProtocol = () => {
    if (onDeleteRecord) {
      onDeleteRecord(record.id);
      onClose();
    }
  };

  const handleUpdateItem = (item: PurchaseItem) => {
    let nextItems = [...record.items];
    const index = nextItems.findIndex(i => i.id === item.id);
    if (index >= 0) nextItems[index] = item;
    else nextItems = [item, ...nextItems];

    const total = nextItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: nextItems, totalAmount: total });
    setIsAddingItem(false);
    setEditingItem(undefined);
  };

  const handleDeleteItem = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("Remove this asset from registry?")) return;
    const nextItems = record.items.filter(i => i.id !== id);
    const total = nextItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: nextItems, totalAmount: total });
  };

  const handleUpdatePayment = (payment: PaymentRecord) => {
    let nextPayments = [...record.payments];
    const index = nextPayments.findIndex(p => p.id === payment.id);
    if (index >= 0) nextPayments[index] = payment;
    else nextPayments = [payment, ...nextPayments];

    const paid = nextPayments.reduce((sum, p) => sum + p.amount, 0);
    const newStatus = paid >= record.totalAmount ? 'Settled' : record.status;
    onUpdateRecord({ ...record, payments: nextPayments, paidAmount: paid, status: newStatus as any });
    setIsRecordingPayment(false);
    setEditingPayment(undefined);
  };

  const handleDeletePayment = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("Void this injection record?")) return;
    const nextPayments = record.payments.filter(p => p.id !== id);
    const paid = nextPayments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, payments: nextPayments, paidAmount: paid });
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-0 md:p-8">
      <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} className="glass-card w-full max-w-6xl h-full md:h-full md:max-h-[92vh] md:rounded-[48px] overflow-hidden border-t md:border border-white/60 flex flex-col relative shadow-2xl">

        {/* Header Section */}
        <div className="p-6 md:p-10 pb-4 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/40 rounded-full z-10 shadow-sm border border-white/40 hover:bg-white transition-colors"><X className="w-6 h-6 text-gray-400" /></button>

          <div className="flex-1 space-y-3 w-full">
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-jua text-[#B8A17D] uppercase tracking-[0.3em]">{isViewOnly ? 'Personal Ledger' : 'Identity Management'}</span>
              <div className={`px-2.5 py-1 rounded-lg text-[8px] font-bold uppercase tracking-widest border border-white/60 ${isOverdue ? 'bg-red-500 text-white animate-pulse' : 'bg-white/40 text-gray-500'}`}>
                {record.status}
              </div>
            </div>
            <h2 className="text-3xl md:text-5xl font-jua text-[#333] tracking-tight truncate leading-none">{record.userName}</h2>
            <div className="flex items-center gap-2 pt-1">
              {!isViewOnly && (
                <>
                  <button onClick={() => setIsEditingProfile(true)} className="p-2 bg-white/50 border border-white/60 rounded-xl text-[#B8A17D] active-scale shadow-sm hover:bg-white" title="Edit Profile"><Edit2 className="w-4 h-4" /></button>
                  <button onClick={handleSettleCompletely} className="p-2 bg-green-50/50 border border-green-100/60 rounded-xl text-green-600 active-scale shadow-sm hover:bg-green-100" title="Full Settlement"><ShieldCheck className="w-4 h-4" /></button>
                  <button onClick={() => setIsLocalAIOpen(true)} className="p-2 bg-[#333] border border-[#B8A17D]/30 rounded-xl text-[#B8A17D] active-scale shadow-sm" title="AI Audit"><Sparkles className="w-4 h-4" /></button>
                  <button onClick={() => setShowDeleteConfirm(true)} className="p-2 bg-red-50/50 border border-red-100/60 rounded-xl text-red-400 active-scale shadow-sm hover:bg-red-50" title="Delete"><Trash2 className="w-4 h-4" /></button>
                </>
              )}
              <button onClick={() => { 
                const url = `${window.location.origin}${window.location.pathname}#/share/${record.shareKey}`;
                navigator.clipboard.writeText(url); 
                setCopied(true); 
                setTimeout(() => setCopied(false), 2000); 
              }} className="px-4 py-2 bg-white/50 border border-white/60 rounded-xl text-[10px] font-bold uppercase tracking-widest active-scale text-[#B8A17D] flex items-center hover:bg-white">
                {copied ? <Check className="w-4 h-4 mr-2" /> : <Share2 className="w-4 h-4 mr-2" />} {copied ? 'Linked' : 'Share'}
              </button>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[28px] bg-[#333] text-white shadow-2xl space-y-4">
            <div className="flex justify-between items-end"><span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Settlement Ratio</span><span className="text-sm font-jua">{progress.toFixed(1)}%</span></div>
            <div className="w-full h-1.5 bg-white/10 rounded-full overflow-hidden"><motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#999]" /></div>
            <div className="grid grid-cols-2 gap-4 pt-1">
              <div className="text-left"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Paid</p><p className="text-lg font-jua">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Balance</p><p className={`text-lg font-jua ${isOverdue ? 'text-red-400' : 'text-[#B8A17D]'}`}>RM{remaining.toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tabs and Tab Actions */}
        <div className="flex items-center justify-between px-4 md:px-12 border-b border-white/10">
          <div className="flex overflow-x-auto hide-scrollbar">
            {['overview', 'items', 'history'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-5 px-6 md:px-8 text-[10px] font-bold uppercase tracking-[0.3em] relative shrink-0 ${activeTab === tab ? 'text-[#333]' : 'text-gray-400'}`}>
                {tab}{activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[3px] bg-[#B8A17D] rounded-t-full" />}
