              {isOverdue && (
                <button onClick={() => setIsLocalAIOpen(true)} className="flex items-center space-x-2 px-4 py-2 bg-red-500 text-white rounded-xl text-[9px] font-bold uppercase tracking-widest active-scale shadow-lg">
                  <MessageCircle className="w-3.5 h-3.5" /> <span>Generate Reminder</span>
