                </button>
              )}
            </div>
          )}
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 pt-8 space-y-12 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                 <div className="p-8 rounded-[32px] bg-white border border-white/60 shadow-xl flex flex-col justify-between">
                    <div className="flex justify-between items-start"><Target className="w-6 h-6 text-[#B8A17D]" /><span className="text-[9px] font-bold text-gray-300 uppercase">Valuation</span></div>
                    <div className="mt-6"><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Total Commitment</p><h4 className="text-2xl font-jua text-[#333]">RM{record.totalAmount.toLocaleString()}</h4></div>
                 </div>
                 <div className={`p-8 rounded-[32px] border shadow-xl flex flex-col justify-between ${isOverdue ? 'bg-red-50 border-red-200' : 'bg-white border-white/60'}`}>
                    <div className="flex justify-between items-start"><TrendingDown className={`w-6 h-6 ${isOverdue ? 'text-red-500 animate-bounce' : 'text-red-400'}`} /><span className="text-[9px] font-bold text-gray-300 uppercase">Liability</span></div>
                    <div className="mt-6"><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Remaining Balance</p><h4 className={`text-2xl font-jua ${isOverdue ? 'text-red-600' : 'text-red-500'}`}>RM{remaining.toLocaleString()}</h4></div>
                 </div>
                 <div className="p-8 rounded-[32px] bg-[#B8A17D] text-white shadow-xl flex flex-col justify-between">
                    <div className="flex justify-between items-start"><Clock className="w-6 h-6 text-white/60" /><span className="text-[9px] font-bold text-white/40 uppercase">Term</span></div>
                    <div className="mt-6"><p className="text-[10px] font-bold text-white/60 uppercase tracking-widest">Maturity Date</p><h4 className="text-xl font-jua">{record.endDate || 'Ongoing'}</h4></div>
                 </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                <div className="space-y-6">
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Visual Artifacts</h4>
                  <div className="grid grid-cols-3 gap-3">
                    {[...(record.attachments || []), ...record.items.filter(i => i.attachment).map(i => i.attachment!)].map(att => (
                      <div key={att.id} onClick={() => setFullScreenImage(att.data)} className="aspect-square bg-white/40 border border-white/60 rounded-2xl overflow-hidden cursor-pointer active-scale shadow-sm group">
                        <img src={att.data} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                      </div>
                    ))}
                  </div>
                </div>
                <div className="space-y-6">
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Registry Log</h4>
                  <div className="space-y-3">
                    {(record.notes || []).map(note => (
                      <div key={note.id} className="p-5 bg-white/40 rounded-2xl border border-white/60 shadow-sm">
                        <p className="text-[8px] font-bold text-gray-400 uppercase mb-2 flex items-center"><Clock className="w-2.5 h-2.5 mr-1.5" /> {note.timestamp}</p>
                        <p className="text-xs text-gray-600 leading-relaxed font-medium">{note.content}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'items' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {record.items.map(item => (
                <div key={item.id} onClick={() => !isViewOnly && (setEditingItem(item), setIsAddingItem(true))} className="group p-6 bg-white/40 border border-white/60 rounded-[32px] shadow-sm hover:shadow-xl hover:bg-white transition-all cursor-pointer relative overflow-hidden">
                  <div className="flex justify-between items-start relative z-10">
                    <div>
                      <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-widest mb-1">{item.date}</p>
                      <h4 className="text-lg font-bold text-[#333] group-hover:text-black">{item.name}</h4>
                    </div>
                    <div className="flex flex-col items-end">
                      <span className="text-2xl font-jua text-[#333]">RM{item.amount.toLocaleString()}</span>
                      {!isViewOnly && (
                        <div className="flex items-center mt-4 space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={(e) => { e.stopPropagation(); setEditingItem(item); setIsAddingItem(true); }} className="p-2 bg-gray-50 rounded-lg text-gray-400 hover:text-[#B8A17D]"><Edit2 className="w-3.5 h-3.5" /></button>
                          <button onClick={(e) => handleDeleteItem(e, item.id)} className="p-2 bg-red-50 rounded-lg text-red-300 hover:text-red-500"><Trash2 className="w-3.5 h-3.5" /></button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 max-w-3xl mx-auto">
              {record.payments.map(payment => (
                <div key={payment.id} className="group flex items-center space-x-6 p-6 bg-white/40 border border-white/60 rounded-[32px] shadow-sm hover:shadow-xl hover:bg-white transition-all cursor-pointer">
                  <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center border border-gray-100 shadow-inner shrink-0"><Check className="w-6 h-6 text-green-500" /></div>
                  <div className="flex-1">
                    <p className="text-[9px] font-bold text-[#B8A17D] uppercase tracking-widest">{payment.method} • {payment.date}</p>
                    <p className="text-base font-bold text-gray-800">Injection Confirmed</p>
                  </div>
                  <div className="flex flex-col items-end">
                    <span className="text-2xl font-jua text-green-600">+RM{payment.amount.toLocaleString()}</span>
                    {!isViewOnly && (
                      <button onClick={(e) => handleDeletePayment(e, payment.id)} className="p-2 text-red-300 hover:text-red-500 opacity-0 group-hover:opacity-100"><Trash2 className="w-3.5 h-3.5" /></button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Local AI Assistant */}
        <AIAssistant 
          isOpen={isLocalAIOpen} 
          onClose={() => setIsLocalAIOpen(false)} 
          records={allRecords || [record]} 
          stats={stats} 
          currentRecord={record}
        />

        <AnimatePresence>
          {isAddingItem && (
            <AddItemModal isOpen={isAddingItem} onClose={() => { setIsAddingItem(false); setEditingItem(undefined); }} onSubmit={handleUpdateItem} initialData={editingItem} />
          )}
          {isRecordingPayment && (
            <PaymentModal isOpen={isRecordingPayment} onClose={() => { setIsRecordingPayment(false); setEditingPayment(undefined); }} onSubmit={handleUpdatePayment} maxAmount={remaining} initialData={editingPayment} />
          )}
          {isEditingProfile && (
            <RecordFormModal isOpen={isEditingProfile} onClose={() => setIsEditingProfile(false)} onSave={onUpdateRecord} initialData={record} />
          )}
          {fullScreenImage && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setFullScreenImage(null)} className="fixed inset-0 z-[200] bg-black/95 flex items-center justify-center p-4 cursor-zoom-out">
              <img src={fullScreenImage} className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" />
              <button className="absolute top-8 right-8 p-3 bg-white/10 rounded-full text-white hover:bg-white/20"><X className="w-8 h-8" /></button>
            </motion.div>
          )}
          {showDeleteConfirm && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[150] bg-[#333]/40 backdrop-blur-sm flex items-center justify-center p-6">
              <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="bg-white rounded-[40px] p-10 max-w-sm w-full text-center space-y-6 shadow-2xl border border-red-100">
                <div className="w-20 h-20 bg-red-50 rounded-3xl mx-auto flex items-center justify-center"><AlertCircle className="w-10 h-10 text-red-500" /></div>
                <div><h4 className="text-2xl font-jua text-[#333]">Void Registry?</h4><p className="text-xs text-gray-500 mt-2 font-medium">This action will permanently erase this bond. It cannot be undone.</p></div>
                <div className="flex flex-col gap-3">
                  <button onClick={handleDeleteProtocol} className="w-full bg-red-500 text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-widest active-scale">Terminate Protocol</button>
                  <button onClick={() => setShowDeleteConfirm(false)} className="w-full bg-gray-100 text-gray-400 py-4 rounded-2xl font-bold text-xs uppercase tracking-widest active-scale">Abort</button>
                </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    </motion.div>
  );
};

export default CustomerDetail;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Plus, 
  Search, 
  LogOut,
  ShieldCheck,
  Loader2,
  AlertCircle,
  Users,
  Globe,
  CloudCheck,
  RefreshCw,
  Sparkles
} from 'lucide-react';
import { LedgerRecord, DashboardStats, MonthlyTrend } from './types';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import RecordFormModal from './components/RecordFormModal';
import UserManagementModal from './components/UserManagementModal';
import AIAssistant from './components/AIAssistant';
import Login from './components/Login';
import { supabase } from './supabase';

const stringifyError = (err: any): string => {
  if (!err) return "Unknown Protocol Error";
  const errMsg = err.message || '';
  if (errMsg.includes('relation "public.ledgers" does not exist')) return "Database Schema Missing.";
  return String(err);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => localStorage.getItem('jaytin_auth') === 'true');
  const [records, setRecords] = useState<LedgerRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isAddingRecord, setIsAddingRecord] = useState(false);
  const [isManagingUsers, setIsManagingUsers] = useState(false);
  const [isAIOpen, setIsAIOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [publicRecord, setPublicRecord] = useState<LedgerRecord | null>(null);
  const [isPublicMode, setIsPublicMode] = useState(() => window.location.hash.startsWith('#/share/'));

  const syncTimeoutRef = useRef<number | null>(null);

  // 自动逾期检测逻辑
  const processAutoOverdue = (inputRecords: LedgerRecord[]): LedgerRecord[] => {
    const now = new Date();
    return inputRecords.map(record => {
      if (record.status === 'Settled' || !record.endDate) return record;
      const end = new Date(record.endDate);
      if (end < now && record.paidAmount < record.totalAmount && record.status !== 'Overdue') {
        return { ...record, status: 'Overdue' };
      }
      return record;
    });
  };

  useEffect(() => {
    const handleRoute = async () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/share/')) {
        const key = hash.replace('#/share/', '');
        if (key && key.length >= 32) {
          setIsPublicMode(true);
          setIsLoading(true);
          try {
            const { data, error } = await supabase
              .from('ledgers')
              .select('record')
              .eq('record->>shareKey', key)
              .maybeSingle();

            if (data) {
              setPublicRecord(data.record as LedgerRecord);
            } else {
              setPublicRecord(null);
            }
          } catch (e) {
            console.error("Vault access failure", e);
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsPublicMode(false);
          setPublicRecord(null);
        }
      } else {
        setIsPublicMode(false);
        setPublicRecord(null);
      }
    };

    handleRoute();
    window.addEventListener('hashchange', handleRoute);
    return () => window.removeEventListener('hashchange', handleRoute);
  }, []);

  useEffect(() => {
    if (isPublicMode) return;
    const saved = localStorage.getItem('jaytin_ledgers');
    if (saved) {
      try { 
        setRecords(processAutoOverdue(JSON.parse(saved)));
        setIsLoading(false);
      } catch (e) { console.warn(e); }
    }
  }, [isPublicMode]);

  const fetchFromCloud = async () => {
    if (isPublicMode || !isAuthenticated) return;
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('ledgers').select('record');
      if (error) throw error;
      if (data) {
        const cloudRecords = processAutoOverdue(data.map((row: any) => row.record));
        setRecords(cloudRecords);
        localStorage.setItem('jaytin_ledgers', JSON.stringify(cloudRecords));
      }
    } catch (e: any) {
      console.error(stringifyError(e));
    } finally {
      setIsLoading(false);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated && !isPublicMode) {
      fetchFromCloud();
    } else if (!isPublicMode) {
      setIsLoading(false);
    }
  }, [isAuthenticated, isPublicMode]);

  const syncAllToCloud = async (currentRecords: LedgerRecord[]) => {
    if (!isAuthenticated || isPublicMode) return;
    setIsSyncing(true);
    try {
      const payloads = currentRecords.map(r => ({
        id: r.id,
        record: r,
        updated_at: new Date().toISOString()
      }));
      const { error } = await supabase.from('ledgers').upsert(payloads);
      if (error) throw error;
    } catch (e: any) {
      console.error(stringifyError(e));
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRecordUpdate = (newRecords: LedgerRecord[]) => {
    const processed = processAutoOverdue(newRecords);
    setRecords(processed);
    localStorage.setItem('jaytin_ledgers', JSON.stringify(processed));
    if (syncTimeoutRef.current) window.clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = window.setTimeout(() => {
      syncAllToCloud(processed);
    }, 1500);
  };

  const stats: DashboardStats = useMemo(() => {
    const totalValuation = records.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const totalPaid = records.reduce((acc, curr) => acc + curr.paidAmount, 0);
    const totalOutstanding = totalValuation - totalPaid;

    const now = new Date();
    const collectedThisMonth = records.reduce((acc, curr) => 
      acc + (curr.payments || []).reduce((pAcc, p) => {
        const pDate = new Date(p.date);
        return (pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear()) ? pAcc + p.amount : pAcc;
      }, 0)
    , 0);

    const overdueAmount = records
      .filter(r => r.status === 'Overdue')
      .reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0);

    const monthlyTrend: MonthlyTrend[] = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(now.getMonth() - i);
      const mLabel = d.toLocaleString('en-US', { month: 'short' });
      const mValue = records.reduce((acc, curr) => 
        acc + (curr.payments || []).reduce((pAcc, p) => {
          const pDate = new Date(p.date);
          return (pDate.getMonth() === d.getMonth() && pDate.getFullYear() === d.getFullYear()) ? pAcc + p.amount : pAcc;
        }, 0)
      , 0);
      monthlyTrend.push({ month: mLabel, amount: mValue });
    }

    return {
      totalValuation,
      totalOutstanding,
      activeCustomers: records.filter(r => r.status !== 'Settled').length,
      collectedThisMonth,
      collectionRate: totalValuation > 0 ? (totalPaid / totalValuation) * 100 : 0,
      overdueAmount,
      monthlyTrend
    };
  }, [records]);

  const handleLogin = async (user: string, pass: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('username', user).eq('password', pass).single();
      if (!error && data) {
        setIsAuthenticated(true);
        localStorage.setItem('jaytin_auth', 'true');
        return true;
      }
      return false;
    } catch (e) { return false; }
  };

  const handleDeleteRecord = (id: string) => {
    const next = records.filter(r => r.id !== id);
    handleRecordUpdate(next);
  };

  if (isLoading) return <div className="min-h-screen flex items-center justify-center bg-[#EBFAFF]"><Loader2 className="w-10 h-10 text-[#B8A17D] animate-spin" /></div>;

  if (isPublicMode && publicRecord) {
    return (
      <div className="min-h-screen bg-[#EBFAFF]">
        <CustomerDetail record={publicRecord} isViewOnly={true} onClose={() => { window.location.hash = ''; }} onUpdateRecord={() => {}} stats={stats} />
        <AIAssistant isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} records={[publicRecord]} stats={stats} currentRecord={publicRecord} />
        <motion.button 
          whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
          onClick={() => setIsAIOpen(true)}
          className="fixed bottom-8 right-8 w-14 h-14 bg-[#333] text-[#B8A17D] rounded-2xl shadow-2xl flex items-center justify-center z-[150] border border-[#B8A17D]/30"
        >
          <Sparkles className="w-6 h-6" />
        </motion.button>
      </div>
    );
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 md:py-12 flex flex-col items-center bg-[#EBFAFF]">
      <header className="w-full max-w-7xl flex flex-col space-y-6 mb-12">
        <div className="flex justify-between items-center">
          <h1 className="text-3xl font-jua text-[#333]">JayTIN TEAM</h1>
          <div className="flex items-center space-x-2">
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsManagingUsers(true)} className="p-2.5 text-[#B8A17D] bg-white rounded-xl border border-white active-scale shadow-sm"><Users className="w-5 h-5" /></motion.button>
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => { setIsAuthenticated(false); localStorage.removeItem('jaytin_auth'); }} className="p-3 text-gray-400 hover:text-red-400 transition-all active-scale"><LogOut className="w-5 h-5" /></motion.button>
          </div>
        </div>
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input type="text" placeholder="Search protocol..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-11 pr-5 py-3.5 bg-white/50 border border-white/40 rounded-2xl text-sm" />
          </div>
          <button onClick={() => setIsAddingRecord(true)} className="flex items-center justify-center space-x-3 bg-[#333] text-white px-8 py-3.5 rounded-2xl font-bold text-[10px] uppercase tracking-widest active-scale">
            <Plus className="w-4.5 h-4.5" /><span>New Registry</span>
          </button>
        </div>
      </header>

      <main className="w-full max-w-7xl space-y-10">
        <Dashboard stats={stats} />
        <CustomerList records={records.filter(r => r.userName.toLowerCase().includes(searchQuery.toLowerCase()))} onSelect={setSelectedRecordId} selectedId={selectedRecordId} />
      </main>

      <motion.button 
        whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
        onClick={() => setIsAIOpen(true)}
        className="fixed bottom-8 right-8 w-16 h-16 bg-[#333] text-[#B8A17D] rounded-3xl shadow-[0_20px_40px_rgba(0,0,0,0.2)] flex flex-col items-center justify-center z-[150] border border-[#B8A17D]/30 group"
      >
        <Sparkles className="w-6 h-6 mb-1 group-hover:rotate-12 transition-transform" />
        <span className="text-[7px] font-bold uppercase tracking-widest">Concierge</span>
      </motion.button>

      <AnimatePresence>
        {selectedRecordId && records.find(r => r.id === selectedRecordId) && (
          <CustomerDetail 
            record={records.find(r => r.id === selectedRecordId)!} 
            onClose={() => setSelectedRecordId(null)}
            onUpdateRecord={(updated) => {
              const next = records.map(r => r.id === updated.id ? updated : r);
              handleRecordUpdate(next);
            }}
            onDeleteRecord={handleDeleteRecord}
            stats={stats}
            allRecords={records}
          />
        )}
      </AnimatePresence>

      <AIAssistant isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} records={records} stats={stats} />
      <RecordFormModal isOpen={isAddingRecord} onClose={() => setIsAddingRecord(false)} onSave={(newRecord) => {
        handleRecordUpdate([newRecord, ...records]);
        setIsAddingRecord(false);
      }} />
      <UserManagementModal isOpen={isManagingUsers} onClose={() => setIsManagingUsers(false)} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, Send, Bot, Sparkles, Loader2, 
  Copy, Check, MessageCircle, Trash2, Maximize2
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { LedgerRecord, DashboardStats } from '../types';

interface AIAssistantProps {
  isOpen: boolean;
  onClose: () => void;
  records: LedgerRecord[];
  stats: DashboardStats;
  currentRecord?: LedgerRecord | null;
}

interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, onClose, records, stats, currentRecord }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      const welcome = currentRecord 
        ? `Protocol recognized. Auditing **${currentRecord.userName}**'s capital position. Outstanding balance is **RM${(currentRecord.totalAmount - currentRecord.paidAmount).toLocaleString()}**. How can I help you manage this exposure?`
        : "JayTIN Intelligence Core v3.0 Online. I have analyzed all ledger protocols. Ready for deep financial audit or risk assessment.";

      setMessages([{
        role: 'assistant',
        content: welcome,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);
    }
  }, [isOpen, currentRecord]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const handleSend = async (overrideInput?: string) => {
    const text = overrideInput || input.trim();
    if (!text || isLoading) return;

    setInput('');
    const userMsg: Message = { 
      role: 'user', 
      content: text, 
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
    };
    const newMsgs = [...messages, userMsg];
    setMessages(newMsgs);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const context = {
        scope: currentRecord ? 'ClientSpecific' : 'Global',
        client: currentRecord ? {
          name: currentRecord.userName,
          outstanding: currentRecord.totalAmount - currentRecord.paidAmount,
          paid: currentRecord.paidAmount,
          history: currentRecord.payments.map(p => `${p.date}: RM${p.amount}`),
          items: currentRecord.items.map(i => `${i.name}: RM${i.amount}`),
          status: currentRecord.status
        } : null,
        global: {
          totalOutstanding: stats.totalOutstanding,
          riskExposure: stats.overdueAmount,
          activeProtocols: stats.activeCustomers,
          collectionRate: stats.collectionRate.toFixed(2) + '%'
        }
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: text,
        config: {
          systemInstruction: `You are the JayTIN Private Concierge, an elite AI financial auditor.
          CONTEXT: ${JSON.stringify(context)}
          MISSION:
          1. Provide high-level financial reasoning and audit summaries.
          2. Use Markdown tables for data comparisons.
          3. If the user is in Client mode, offer to draft professional reminders or settlement strategies.
          4. Keep the tone stoic, professional, and sophisticated.
          5. Never mention technical implementation; stay in character as a banking AI.`,
          thinkingConfig: { thinkingBudget: 2000 }
        },
      });

      setMessages([...newMsgs, { 
        role: 'assistant', 
        content: response.text || "Communication interrupted.", 
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
      }]);
    } catch (e) {
      setMessages([...newMsgs, { role: 'assistant', content: "Protocol Error: Unable to synchronize with the cloud intelligence core.", timestamp: "ERR" }]);
    } finally {
      setIsLoading(false);
    }
  };

  const suggestions = currentRecord 
    ? ["Summarize repayment health", "Draft a professional reminder", "Predict settlement date"]
    : ["Generate global risk report", "Show top 3 exposures", "Analyze monthly trend"];

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="fixed inset-0 z-[200] bg-black/50 backdrop-blur-md" />
          <motion.div 
            initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
            className="fixed right-0 top-0 h-full w-full max-w-lg z-[210] bg-[#0A0A0A] text-white shadow-2xl flex flex-col border-l border-white/10"
          >
            {/* Header */}
            <div className="p-8 border-b border-white/5 bg-gradient-to-r from-[#111] to-[#0A0A0A] flex justify-between items-center">
              <div className="flex items-center space-x-4">
                <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-[#B8A17D] to-[#8C7A5E] flex items-center justify-center shadow-[0_0_30px_rgba(184,161,125,0.3)]">
                  <Bot className="w-7 h-7 text-black" />
                </div>
                <div>
                  <h3 className="text-xl font-jua text-[#B8A17D]">JayTIN Assistant</h3>
                  <div className="flex items-center space-x-2">
                    <span className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_#22c55e] animate-pulse" />
                    <span className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Neural Link Synchronized</span>
                  </div>
                </div>
              </div>
              <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6 text-gray-500" /></button>
            </div>

            {/* Chat Body */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
              {messages.map((msg, i) => (
                <motion.div key={i} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-[24px] p-5 text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-[#B8A17D] text-black font-bold rounded-tr-none' 
                      : 'bg-[#1A1A1A] text-gray-200 border border-white/5 rounded-tl-none shadow-xl'
                  }`}>
                    <div className="markdown-content prose prose-invert prose-sm max-w-none">
                      {msg.content}
                    </div>
                    <div className="mt-3 flex justify-between items-center">
                      <span className={`text-[8px] font-bold uppercase tracking-widest ${msg.role === 'user' ? 'text-black/40' : 'text-gray-600'}`}>{msg.timestamp}</span>
                      {msg.role === 'assistant' && !isLoading && i === messages.length - 1 && (
                        <button onClick={() => { navigator.clipboard.writeText(msg.content); setCopied(true); setTimeout(()=>setCopied(false), 2000); }} className="p-1 hover:bg-white/5 rounded">
                          {copied ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3 text-gray-600" />}
                        </button>
                      )}
                    </div>
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-[#1A1A1A] rounded-[24px] rounded-tl-none p-5 border border-white/5 flex items-center space-x-3">
                    <Loader2 className="w-4 h-4 animate-spin text-[#B8A17D]" />
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Consulting Core Intelligence...</span>
                  </div>
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="p-8 bg-[#0D0D0D] border-t border-white/5 space-y-6">
              <div className="flex overflow-x-auto hide-scrollbar space-x-3 pb-1">
                {suggestions.map((s, i) => (
                  <button key={i} onClick={() => handleSend(s)} className="shrink-0 px-4 py-2.5 bg-[#1A1A1A] border border-white/10 rounded-xl text-[9px] font-bold text-gray-400 uppercase tracking-widest hover:border-[#B8A17D] hover:text-[#B8A17D] transition-all">
                    {s}
                  </button>
                ))}
              </div>
              <div className="relative">
                <input 
                  type="text" value={input} onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Inquire with private concierge..."
                  className="w-full bg-[#1A1A1A] border border-white/10 rounded-2xl pl-6 pr-14 py-5 text-sm focus:outline-none focus:border-[#B8A17D]/40 transition-all placeholder:text-gray-700"
                />
                <button 
                  onClick={() => handleSend()} disabled={!input.trim() || isLoading}
                  className="absolute right-2.5 top-1/2 -translate-y-1/2 p-3 bg-[#B8A17D] rounded-xl text-black disabled:opacity-30 transition-all hover:scale-105 active:scale-95 shadow-lg"
                >
                  <Send className="w-4.5 h-4.5" />
                </button>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default AIAssistant;

import React, { useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  X, ShoppingBag, CreditCard, Edit2, 
  Image as ImageIcon, Share2, Check, Trash2, AlertCircle, Target, TrendingDown, Clock, Plus, Sparkles, MessageCircle, ShieldCheck, Maximize2
} from 'lucide-react';
import { LedgerRecord, PurchaseItem, PaymentRecord } from '../types';
import AddItemModal from './AddItemModal';
import PaymentModal from './PaymentModal';
import RecordFormModal from './RecordFormModal';
import AIAssistant from './AIAssistant';

interface Props {
  record: LedgerRecord;
  isViewOnly?: boolean;
  onClose: () => void;
  onUpdateRecord: (record: LedgerRecord) => void;
  onDeleteRecord?: (id: string) => void;
  stats?: any;
  allRecords?: LedgerRecord[];
}

const CustomerDetail: React.FC<Props> = ({ record, isViewOnly = false, onClose, onUpdateRecord, onDeleteRecord, stats, allRecords }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'items' | 'history'>('overview');
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [editingItem, setEditingItem] = useState<PurchaseItem | undefined>(undefined);
  const [isRecordingPayment, setIsRecordingPayment] = useState(false);
  const [editingPayment, setEditingPayment] = useState<PaymentRecord | undefined>(undefined);
  const [fullScreenImage, setFullScreenImage] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [isLocalAIOpen, setIsLocalAIOpen] = useState(false);

  const progress = (record.paidAmount / record.totalAmount) * 100 || 0;
  const remaining = Math.max(0, record.totalAmount - record.paidAmount);
  const isOverdue = record.status === 'Overdue';

  const handleSettleCompletely = () => {
    if (!confirm("Confirm full settlement of this protocol?")) return;
    const nextRecord = { 
      ...record, 
      paidAmount: record.totalAmount, 
      status: 'Settled' as const,
      notes: [{ id: `N-${Date.now()}`, timestamp: new Date().toLocaleString(), content: 'Protocol manually settled and closed.' }, ...record.notes]
    };
    onUpdateRecord(nextRecord);
  };

  const handleUpdateItem = (item: PurchaseItem) => {
    let nextItems = [...record.items];
    const index = nextItems.findIndex(i => i.id === item.id);
    if (index >= 0) nextItems[index] = item;
    else nextItems = [item, ...nextItems];

    const total = nextItems.reduce((sum, i) => sum + i.amount, 0);
    const paid = record.payments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, items: nextItems, totalAmount: total, paidAmount: paid });
    setIsAddingItem(false);
    setEditingItem(undefined);
  };

  const handleDeleteItem = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("Remove this asset?")) return;
    const nextItems = record.items.filter(i => i.id !== id);
    const total = nextItems.reduce((sum, i) => sum + i.amount, 0);
    onUpdateRecord({ ...record, items: nextItems, totalAmount: total });
  };

  const handleUpdatePayment = (payment: PaymentRecord) => {
    let nextPayments = [...record.payments];
    const index = nextPayments.findIndex(p => p.id === payment.id);
    if (index >= 0) nextPayments[index] = payment;
    else nextPayments = [payment, ...nextPayments];

    const paid = nextPayments.reduce((sum, p) => sum + p.amount, 0);
    const newStatus = paid >= record.totalAmount ? 'Settled' : record.status;
    onUpdateRecord({ ...record, payments: nextPayments, paidAmount: paid, status: newStatus as any });
    setIsRecordingPayment(false);
    setEditingPayment(undefined);
  };

  const handleDeletePayment = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("Void this injection record?")) return;
    const nextPayments = record.payments.filter(p => p.id !== id);
    const paid = nextPayments.reduce((sum, p) => sum + p.amount, 0);
    onUpdateRecord({ ...record, payments: nextPayments, paidAmount: paid });
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[60] flex items-center justify-center bg-[#EBFAFF]/80 backdrop-blur-xl p-0 md:p-8">
      <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} className="glass-card w-full max-w-6xl h-full md:max-h-[92vh] md:rounded-[48px] overflow-hidden flex flex-col relative shadow-2xl">

        {/* Header */}
        <div className="p-6 md:p-10 pb-4 relative flex flex-col md:flex-row justify-between items-start gap-8">
          <button onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/40 rounded-full z-10 border border-white/40 hover:bg-white active-scale shadow-sm transition-colors"><X className="w-6 h-6 text-gray-400" /></button>
          <div className="flex-1 space-y-3 w-full">
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-jua text-[#B8A17D] uppercase tracking-[0.3em]">{isViewOnly ? 'Identity Vault' : 'Protocol Detail'}</span>
              <div className={`px-2.5 py-1 rounded-lg text-[8px] font-bold uppercase tracking-widest border ${isOverdue ? 'bg-red-500 text-white animate-pulse border-red-400' : 'bg-white/40 text-gray-500 border-white/60'}`}>
                {record.status}
              </div>
            </div>
            <h2 className="text-3xl md:text-5xl font-jua text-[#333] tracking-tight">{record.userName}</h2>
            <div className="flex items-center gap-2 pt-1">
              {!isViewOnly && (
                <>
                  <button onClick={() => setIsEditingProfile(true)} className="p-2 bg-white/50 border border-white/60 rounded-xl text-[#B8A17D] active-scale shadow-sm hover:bg-white" title="Edit Profile"><Edit2 className="w-4 h-4" /></button>
                  <button onClick={handleSettleCompletely} className="p-2 bg-green-50 border border-green-200 rounded-xl text-green-600 active-scale shadow-sm hover:bg-green-100" title="Instant Settle"><ShieldCheck className="w-4 h-4" /></button>
                  <button onClick={() => setIsLocalAIOpen(true)} className="p-2 bg-[#1A1A1A] border border-[#B8A17D]/30 rounded-xl text-[#B8A17D] active-scale shadow-sm" title="AI Audit"><Sparkles className="w-4 h-4" /></button>
                  <button onClick={() => setShowDeleteConfirm(true)} className="p-2 bg-red-50 border border-red-100 rounded-xl text-red-400 active-scale shadow-sm hover:bg-red-50" title="Delete"><Trash2 className="w-4 h-4" /></button>
                </>
              )}
              <button onClick={() => { const url = `${window.location.origin}${window.location.pathname}#/share/${record.shareKey}`; navigator.clipboard.writeText(url); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="px-4 py-2 bg-white border border-white/60 rounded-xl text-[10px] font-bold uppercase tracking-widest active-scale text-[#B8A17D] flex items-center shadow-sm">
                {copied ? <Check className="w-4 h-4 mr-2" /> : <Share2 className="w-4 h-4 mr-2" />} {copied ? 'Copied' : 'Share URL'}
              </button>
            </div>
          </div>

          <div className="w-full md:w-96 p-6 rounded-[32px] bg-[#1A1A1A] text-white shadow-2xl space-y-4 border border-white/10">
            <div className="flex justify-between items-end"><span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Protocol Fulfillment</span><span className="text-sm font-jua">{progress.toFixed(1)}%</span></div>
            <div className="w-full h-1.5 bg-white/10 rounded-full overflow-hidden"><motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-[#B8A17D] to-[#8C7A5E]" /></div>
            <div className="grid grid-cols-2 gap-4 pt-1">
              <div><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Injected</p><p className="text-lg font-jua">RM{record.paidAmount.toLocaleString()}</p></div>
              <div className="text-right"><p className="text-[8px] text-gray-400 uppercase tracking-widest font-bold">Exposure</p><p className={`text-lg font-jua ${isOverdue ? 'text-red-400' : 'text-[#B8A17D]'}`}>RM{remaining.toLocaleString()}</p></div>
            </div>
          </div>
        </div>

        {/* Tab Switcher */}
        <div className="flex items-center justify-between px-4 md:px-12 border-b border-white/10">
          <div className="flex">
            {['overview', 'items', 'history'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`py-5 px-6 md:px-8 text-[10px] font-bold uppercase tracking-[0.3em] relative ${activeTab === tab ? 'text-[#333]' : 'text-gray-400'}`}>
                {tab}{activeTab === tab && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-[3px] bg-[#B8A17D] rounded-t-full" />}
              </button>
            ))}
          </div>
          {!isViewOnly && (
            <div className="flex items-center space-x-2">
              {activeTab === 'items' && (
                <button onClick={() => { setEditingItem(undefined); setIsAddingItem(true); }} className="flex items-center space-x-2 px-4 py-2 bg-[#1A1A1A] text-white rounded-xl text-[9px] font-bold uppercase tracking-widest active-scale shadow-lg"><Plus className="w-3.5 h-3.5" /> <span>Declare Asset</span></button>
              )}
              {activeTab === 'history' && (
                <button onClick={() => { setEditingPayment(undefined); setIsRecordingPayment(true); }} className="flex items-center space-x-2 px-4 py-2 bg-[#B8A17D] text-white rounded-xl text-[9px] font-bold uppercase tracking-widest active-scale shadow-lg"><Plus className="w-3.5 h-3.5" /> <span>Inject Capital</span></button>
              )}
            </div>
          )}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-12 pt-8 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                 <div className="p-8 rounded-[32px] bg-white border border-white/60 shadow-xl flex flex-col justify-between">
                    <Target className="w-6 h-6 text-[#B8A17D] mb-4" />
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Agreement Valuation</p><h4 className="text-2xl font-jua text-[#333]">RM{record.totalAmount.toLocaleString()}</h4></div>
                 </div>
                 <div className={`p-8 rounded-[32px] border shadow-xl flex flex-col justify-between ${isOverdue ? 'bg-red-50 border-red-200' : 'bg-white border-white/60'}`}>
                    <TrendingDown className={`w-6 h-6 mb-4 ${isOverdue ? 'text-red-500 animate-bounce' : 'text-red-400'}`} />
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Active Exposure</p><h4 className={`text-2xl font-jua ${isOverdue ? 'text-red-600' : 'text-red-500'}`}>RM{remaining.toLocaleString()}</h4></div>
                 </div>
                 <div className="p-8 rounded-[32px] bg-[#B8A17D] text-white shadow-xl flex flex-col justify-between">
                    <Clock className="w-6 h-6 text-white/60 mb-4" />
                    <div><p className="text-[10px] font-bold text-white/60 uppercase tracking-widest">Maturity Date</p><h4 className="text-xl font-jua">{record.endDate || 'N/A'}</h4></div>
                 </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                <div className="space-y-6">
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Evidence Gallery</h4>
                  <div className="grid grid-cols-3 gap-3">
                    {[...(record.attachments || []), ...record.items.filter(i => i.attachment).map(i => i.attachment!)].map((att, idx) => (
                      <div key={idx} onClick={() => setFullScreenImage(att.data)} className="aspect-square bg-white border border-white/60 rounded-2xl overflow-hidden cursor-pointer active-scale shadow-sm group">
                        <img src={att.data} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                      </div>
                    ))}
                    {record.items.length === 0 && <div className="col-span-3 text-[10px] text-gray-300 font-bold uppercase italic py-8 border-2 border-dashed border-gray-100 rounded-3xl text-center">No artifacts uploaded.</div>}
                  </div>
                </div>
                <div className="space-y-6">
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Audit Logs</h4>
                  <div className="space-y-3">
                    {record.notes.map(note => (
                      <div key={note.id} className="p-5 bg-white/50 rounded-2xl border border-white shadow-sm">
